function getGlobalNavPathByKey(navKey, fallbackPath = '') {
    try {
        if (typeof window.getMetaModelNavPathByKey === 'function') {
            const resolved = String(window.getMetaModelNavPathByKey(navKey) || '').trim();
            if (resolved) return resolved;
        }
    } catch (_error) {
        // ignore nav map lookup failures and use fallback
    }
    const fallback = String(fallbackPath || '').trim();
    if (!fallback) return '';
    if (/^https?:\/\//i.test(fallback)) return fallback;
    return fallback.startsWith('/') ? fallback : `/${fallback.replace(/^\.?\//, '')}`;
}

function toHrefFeatureKeyFromPath(rawPath = '') {
    const value = String(rawPath || '').trim();
    if (!value) return '';
    try {
        const url = new URL(value, window.location.href);
        return `href:${url.pathname.replace(/^\//, '')}`;
    } catch (_error) {
        const normalized = value.split('?')[0].split('#')[0].replace(/^\.?\//, '').replace(/^\//, '');
        return normalized ? `href:${normalized}` : '';
    }
}

function getNavHrefFeatureKey(navKey, fallbackPath = '') {
    return toHrefFeatureKeyFromPath(getGlobalNavPathByKey(navKey, fallbackPath));
}

function getNavKeyByTab(tabName = '') {
    const targetTab = normalizeRequestedTab(tabName);
    if (!targetTab || typeof window === 'undefined') return '';
    const navMap = window.MetaModelNavMap && typeof window.MetaModelNavMap === 'object'
        ? window.MetaModelNavMap
        : {};
    return Object.keys(navMap).find((key) => {
        const entry = navMap[key];
        return entry?.type === 'tab' && normalizeRequestedTab(entry.tab) === targetTab;
    }) || '';
}

function resolveCanonicalRouteForFeature(tabName = '', fallbackRoute = '') {
    const tab = normalizeRequestedTab(tabName);
    if (tab && document.getElementById(tab)) {
        return buildRoutePathForTab(tab);
    }
    const fallback = String(fallbackRoute || '').trim();
    if (!fallback) return '';
    const navKey = typeof window.getMetaModelNavKeyByPath === 'function'
        ? String(window.getMetaModelNavKeyByPath(fallback) || '').trim()
        : '';
    if (navKey) {
        return getGlobalNavPathByKey(navKey, fallback);
    }
    return fallback;
}

function normalizeText(value) {
    return (value ?? '').toString().trim();
}

if (typeof window !== 'undefined' && typeof window.normalizeText !== 'function') {
    window.normalizeText = normalizeText;
}

async function gateSentenceConsumption(options = {}) {
    const api = window.MetaFreemium;
    if (!api || typeof api.consumeSentenceOrPrompt !== 'function') return true;
    try {
        const allowed = await api.consumeSentenceOrPrompt({
            source: String(options.source || 'app'),
            count: Math.max(1, Number(options.count) || 1)
        });
        return allowed !== false;
    } catch (error) {
        return false;
    }
}

function getNavHrefFeatureKeyFromElement(element) {
    if (!element) return '';
    const href = String(element.getAttribute('data-versioned-href') || element.getAttribute('href') || '').trim();
    if (!href) return '';
    try {
        if (typeof window.getMetaModelNavKeyByPath === 'function') {
            const navKey = String(window.getMetaModelNavKeyByPath(href) || '').trim();
            if (navKey) return getNavHrefFeatureKey(navKey, href);
        }
    } catch (_error) {
        // ignore reverse lookup failures and fall back to raw href
    }
    return toHrefFeatureKeyFromPath(href);
}

const SUBCATEGORY_TO_CATEGORY = {
    SIMPLE_DELETION: 'DELETION',
    COMPARATIVE_DELETION: 'DELETION',
    LACK_REFERENTIAL_INDEX: 'DELETION',
    LACK_OF_REFERENTIAL_INDEX: 'DELETION',
    NOMINALIZATION: 'DISTORTION',
    'CAUSE-EFFECT': 'DISTORTION',
    MIND_READING: 'DISTORTION',
    LOST_PERFORMATIVE: 'DISTORTION',
    PRESUPPOSITION: 'DISTORTION',
    COMPLEX_EQUIVALENCE: 'DISTORTION',
    UNIVERSAL_QUANTIFIER: 'GENERALIZATION',
    MODAL_OPERATOR: 'GENERALIZATION'
};

function shuffleArray(items) {
    const arr = [...items];
    for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
}

function getQuestionCategoryKey(question) {
    const directCategory = (question.category || '').toUpperCase().trim();
    if (TRAINER_CATEGORY_LABELS[directCategory]) return directCategory;

    const directViolation = (question.violation || '').toUpperCase().trim();
    if (TRAINER_CATEGORY_LABELS[directViolation]) return directViolation;

    const normalizedViolation = directViolation.replace(/\s+/g, '_');
    return SUBCATEGORY_TO_CATEGORY[normalizedViolation] || '';
}

function loadAudioSettings() {
    let saved = null;
    try {
        saved = localStorage.getItem('meta_audio_muted');
    } catch (_error) {
        saved = null;
    }

    // Embedded contexts (Google Sites / iframes) should always start quiet.
    if (isEmbeddedRuntimeContext()) {
        audioState.muted = true;
    } else if (saved === 'true' || saved === 'false') {
        audioState.muted = saved === 'true';
    } else {
        audioState.muted = false;
    }

    try {
        audioState.firstEntryDone = localStorage.getItem(OPENING_TRACK_FIRST_ENTRY_KEY) === 'true';
    } catch (_error) {
        audioState.firstEntryDone = false;
    }
}

function isEmbeddedRuntimeContext() {
    if (document.body && document.body.classList.contains('embed-mode')) return true;
    try {
        return window.self !== window.top;
    } catch (_error) {
        return true;
    }
}

function safeResumeAudioContext(ctx) {
    if (!ctx || typeof ctx.resume !== 'function' || ctx.state !== 'suspended') return;
    try {
        const resumeResult = ctx.resume();
        if (resumeResult && typeof resumeResult.catch === 'function') {
            resumeResult.catch(() => {});
        }
    } catch (_error) {
        // Ignore audio resume failures in restricted embeds/iframes.
    }
}

function armAudioFromUserInteraction() {
    if (audioState.audioArmed) return;
    audioState.audioArmed = true;
    const ctx = ensureAudioContext();
    safeResumeAudioContext(ctx);
}

function setupAudioInteractionArm() {
    if (audioState.audioArmBound) return;
    audioState.audioArmBound = true;

    const armHandler = () => {
        armAudioFromUserInteraction();
    };

    document.addEventListener('pointerdown', armHandler, { once: true, capture: true });
    document.addEventListener('keydown', armHandler, { once: true, capture: true });
    document.addEventListener('touchstart', armHandler, { once: true, capture: true, passive: true });
}

function ensureAudioContext() {
    if (audioState.context) return audioState.context;
    try {
        audioState.context = new (window.AudioContext || window.webkitAudioContext)();
        return audioState.context;
    } catch (e) {
        return null;
    }
}

function ensureUiSoundOutput(ctx) {
    if (!ctx) return null;
    if (audioState.uiMasterGain) return audioState.uiMasterGain;
    try {
        const compressor = ctx.createDynamicsCompressor();
        compressor.threshold.value = -24;
        compressor.knee.value = 18;
        compressor.ratio.value = 2.5;
        compressor.attack.value = 0.003;
        compressor.release.value = 0.18;

        const masterGain = ctx.createGain();
        masterGain.gain.value = 0.92;

        compressor.connect(masterGain);
        masterGain.connect(ctx.destination);

        audioState.uiCompressor = compressor;
        audioState.uiMasterGain = masterGain;
        return masterGain;
    } catch (_error) {
        return ctx.destination;
    }
}

function pickRandomMusicSource(excludingSource = '') {
    const base = MUSIC_TRACK_SOURCES.filter((src) => String(src || '').trim());
    if (!base.length) return '';

    if (!Array.isArray(audioState.musicShuffleQueue) || !audioState.musicShuffleQueue.length) {
        const queue = [...base];
        for (let i = queue.length - 1; i > 0; i -= 1) {
            const j = Math.floor(Math.random() * (i + 1));
            [queue[i], queue[j]] = [queue[j], queue[i]];
        }
        if (queue.length > 1 && excludingSource && queue[0] === excludingSource) {
            [queue[0], queue[1]] = [queue[1], queue[0]];
        }
        audioState.musicShuffleQueue = queue;
    }

    let next = String(audioState.musicShuffleQueue.shift() || '').trim();
    if (!next) {
        audioState.musicShuffleQueue = [];
        return pickRandomMusicSource(excludingSource);
    }

    if (base.length > 1 && next === excludingSource) {
        const replacement = String(audioState.musicShuffleQueue.shift() || '').trim();
        if (replacement) {
            audioState.musicShuffleQueue.push(next);
            next = replacement;
        }
    }

    return next;
}

function ensureOpeningTrack(requestedSource = '') {
    const source = String(requestedSource || '').trim() || pickRandomMusicSource(audioState.musicLastSource);
    if (!source) return null;

    const cachedTrack = audioState.musicTracks.get(source);
    if (cachedTrack) {
        audioState.openingTrack = cachedTrack;
        return cachedTrack;
    }

    try {
        const track = new Audio(source);
        track.preload = 'auto';
        track.loop = false;
        track.dataset.musicSource = source;
        track.addEventListener('play', updateMusicToggleButtonUI);
        track.addEventListener('pause', updateMusicToggleButtonUI);
        track.addEventListener('ended', () => {
            clearMusicSnippetTimer();
            if (audioState.openingTrack === track) {
                audioState.openingTrack = null;
            }
            updateMusicToggleButtonUI();
        });
        audioState.musicTracks.set(source, track);
        audioState.openingTrack = track;
        return track;
    } catch (_error) {
        return null;
    }
}

function clearMusicSnippetTimer() {
    if (!audioState.musicSnippetTimer) return;
    clearTimeout(audioState.musicSnippetTimer);
    audioState.musicSnippetTimer = null;
}

function scheduleMusicSnippetStop(track) {
    clearMusicSnippetTimer();
    if (!track) return;
    audioState.musicSnippetTimer = setTimeout(() => {
        if (track.paused) return;
        track.pause();
        track.currentTime = 0;
        if (audioState.openingTrack === track) {
            audioState.openingTrack = null;
        }
        updateMusicToggleButtonUI();
    }, MUSIC_SNIPPET_DURATION_MS);
}

function isOpeningTrackPlaying() {
    const track = audioState.openingTrack;
    return !!(track && !track.paused && !track.ended);
}

function updateMusicToggleButtonUI() {
    const btn = document.getElementById('music-toggle-btn');
    if (!btn) return;

    if (audioState.muted) {
        btn.innerHTML = '<span class="audio-fab-icon">🔇</span><span class="audio-fab-label">מיוט</span>';
        btn.setAttribute('aria-label', 'בטל מיוט ונגן שיר אקראי ל-30 שניות');
        btn.setAttribute('title', 'בטל מיוט ונגן שיר אקראי ל-30 שניות');
        btn.classList.add('is-muted');
        btn.classList.remove('is-playing');
        return;
    }

    if (isOpeningTrackPlaying()) {
        btn.innerHTML = '<span class="audio-fab-icon">⏹</span><span class="audio-fab-label">עצור</span>';
        btn.setAttribute('aria-label', 'עצור שיר');
        btn.setAttribute('title', 'עצור שיר');
        btn.classList.add('is-playing');
        btn.classList.remove('is-muted');
        return;
    }

    btn.innerHTML = '<span class="audio-fab-icon">🎵</span><span class="audio-fab-label">רנדום</span>';
    btn.setAttribute('aria-label', 'נגן שיר אקראי ל-30 שניות');
    btn.setAttribute('title', 'נגן שיר אקראי ל-30 שניות');
    btn.classList.remove('is-playing', 'is-muted');
}

function updateFloatingMuteButtonUI() {
    const btn = document.getElementById('audio-master-mute-btn');
    if (!btn) return;
    if (audioState.muted) {
        btn.innerHTML = '<span class="audio-fab-icon">🔇</span><span class="audio-fab-label">MUTE</span>';
        btn.setAttribute('aria-label', 'הפעל סאונד');
        btn.setAttribute('title', 'הפעל סאונד');
        btn.classList.add('is-muted');
        btn.classList.remove('is-active');
        return;
    }

    btn.innerHTML = '<span class="audio-fab-icon">🔊</span><span class="audio-fab-label">SOUND</span>';
    btn.setAttribute('aria-label', 'השתק סאונד');
    btn.setAttribute('title', 'השתק סאונד');
    btn.classList.add('is-active');
    btn.classList.remove('is-muted');
}

function readAudioControlPositions() {
    try {
        const raw = localStorage.getItem(AUDIO_FLOATING_CONTROLS_POSITION_KEY);
        if (!raw) return {};
        const parsed = JSON.parse(raw);
        return parsed && typeof parsed === 'object' ? parsed : {};
    } catch (_error) {
        return {};
    }
}

function writeAudioControlPositions(positions) {
    try {
        localStorage.setItem(AUDIO_FLOATING_CONTROLS_POSITION_KEY, JSON.stringify(positions || {}));
    } catch (_error) {
        // Ignore storage failures in restricted contexts.
    }
}

function clampAudioControlPosition(button, left, top) {
    if (!button) return { left: 8, top: 8 };
    const rect = button.getBoundingClientRect();
    const width = Math.max(42, Math.round(rect.width || button.offsetWidth || 58));
    const height = Math.max(42, Math.round(rect.height || button.offsetHeight || 58));
    const bottomOffset = isMobileViewportMode() ? getFloatingAudioBottomOffsetPx() : 0;
    const maxLeft = Math.max(8, window.innerWidth - width - 8);
    const maxTop = Math.max(8, window.innerHeight - height - 8 - bottomOffset);
    return {
        left: Math.min(maxLeft, Math.max(8, Math.round(Number(left) || 8))),
        top: Math.min(maxTop, Math.max(8, Math.round(Number(top) || 8)))
    };
}

function getFloatingAudioBottomOffsetPx() {
    if (!isMobileViewportMode()) return 0;
    let offset = 0;

    if (document.body?.classList.contains('mobile-sticky-cta-visible')) {
        const stickyCta = document.getElementById(MOBILE_STICKY_CTA_ID);
        if (stickyCta && !stickyCta.classList.contains('hidden')) {
            const rect = stickyCta.getBoundingClientRect();
            const visibleHeight = Math.max(0, Math.min(window.innerHeight, rect.bottom) - Math.max(0, rect.top));
            offset += Math.max(0, Math.round(visibleHeight + 10));
        } else {
            offset += 88;
        }
    }

    const vv = window.visualViewport;
    if (vv && Number.isFinite(vv.height) && vv.height > 0) {
        const keyboardInset = Math.max(0, Math.round((window.innerHeight || 0) - vv.height - 4));
        if (keyboardInset > 36) {
            offset += keyboardInset;
        }
    }

    return Math.max(0, offset);
}

function syncFloatingAudioSafeZone() {
    const offset = getFloatingAudioBottomOffsetPx();
    document.documentElement.style.setProperty('--audio-floating-bottom-offset', `${offset}px`);
}

function fadeFloatingAudioControlsDuringScroll() {
    if (!isMobileViewportMode()) return;
    const controls = document.querySelectorAll('.audio-floating-control');
    if (!controls.length) return;
    controls.forEach((node) => node.classList.add('is-scroll-faded'));
    if (audioState.floatingScrollFadeTimer) {
        clearTimeout(audioState.floatingScrollFadeTimer);
        audioState.floatingScrollFadeTimer = null;
    }
    audioState.floatingScrollFadeTimer = setTimeout(() => {
        controls.forEach((node) => node.classList.remove('is-scroll-faded'));
        audioState.floatingScrollFadeTimer = null;
    }, 190);
}

function releaseMobileAudioDockIfNotPinned() {
    if (!isMobileViewportMode()) return;
    ['music-toggle-btn', 'audio-master-mute-btn'].forEach((id) => {
        const button = document.getElementById(id);
        if (!button) return;
        if (button.dataset.dragPinned === 'true') return;
        button.style.left = '';
        button.style.top = '';
        button.style.right = '';
        button.style.bottom = '';
    });
}

function applyStoredAudioControlPosition(button, key) {
    if (!button || !key) return;
    if (isMobileViewportMode()) return;
    const positions = readAudioControlPositions();
    const saved = positions[key];
    if (!saved || !Number.isFinite(Number(saved.left)) || !Number.isFinite(Number(saved.top))) return;
    const clamped = clampAudioControlPosition(button, saved.left, saved.top);
    button.style.left = `${clamped.left}px`;
    button.style.top = `${clamped.top}px`;
    button.style.right = 'auto';
    button.style.bottom = 'auto';
}

function persistAudioControlPosition(key, left, top) {
    if (!key) return;
    const positions = readAudioControlPositions();
    positions[key] = { left: Math.round(left), top: Math.round(top) };
    writeAudioControlPositions(positions);
}

function bindAudioControlDrag(button, key) {
    if (!button || !key || button.dataset.dragBound === 'true') return;
    button.dataset.dragBound = 'true';

    applyStoredAudioControlPosition(button, key);

    const drag = {
        active: false,
        pointerId: null,
        startX: 0,
        startY: 0,
        startLeft: 0,
        startTop: 0,
        moved: false
    };

    const suppressClickAfterDrag = () => {
        button.dataset.dragSuppressClick = 'true';
        setTimeout(() => {
            if (button.dataset.dragSuppressClick === 'true') {
                button.dataset.dragSuppressClick = 'false';
            }
        }, 180);
    };

    const finishDrag = () => {
        if (!drag.active) return;
        drag.active = false;
        button.classList.remove('is-dragging');
        if (drag.pointerId !== null && typeof button.releasePointerCapture === 'function') {
            try {
                button.releasePointerCapture(drag.pointerId);
            } catch (_error) {}
        }
        if (drag.moved) {
            const rect = button.getBoundingClientRect();
            const clamped = clampAudioControlPosition(button, rect.left, rect.top);
            button.style.left = `${clamped.left}px`;
            button.style.top = `${clamped.top}px`;
            button.style.right = 'auto';
            button.style.bottom = 'auto';
            button.dataset.dragPinned = 'true';
            persistAudioControlPosition(key, clamped.left, clamped.top);
            suppressClickAfterDrag();
        }
        drag.pointerId = null;
        drag.moved = false;
    };

    button.addEventListener('pointerdown', (event) => {
        if (event.button !== 0) return;
        drag.active = true;
        drag.pointerId = event.pointerId;
        drag.startX = event.clientX;
        drag.startY = event.clientY;
        const rect = button.getBoundingClientRect();
        drag.startLeft = rect.left;
        drag.startTop = rect.top;
        drag.moved = false;
        button.classList.add('is-dragging');
        if (typeof button.setPointerCapture === 'function') {
            try {
                button.setPointerCapture(event.pointerId);
            } catch (_error) {}
        }
    });

    button.addEventListener('pointermove', (event) => {
        if (!drag.active || event.pointerId !== drag.pointerId) return;
        const dx = event.clientX - drag.startX;
        const dy = event.clientY - drag.startY;
        if (!drag.moved && ((Math.abs(dx) > 4) || (Math.abs(dy) > 4))) {
            drag.moved = true;
        }
        if (!drag.moved) return;
        const clamped = clampAudioControlPosition(button, drag.startLeft + dx, drag.startTop + dy);
        button.style.left = `${clamped.left}px`;
        button.style.top = `${clamped.top}px`;
        button.style.right = 'auto';
        button.style.bottom = 'auto';
    });

    button.addEventListener('pointerup', finishDrag);
    button.addEventListener('pointercancel', finishDrag);
    button.addEventListener('lostpointercapture', finishDrag);

    button.addEventListener('click', (event) => {
        if (button.dataset.dragSuppressClick === 'true') {
            button.dataset.dragSuppressClick = 'false';
            event.preventDefault();
            event.stopPropagation();
        }
    }, true);
}

function setupFloatingAudioControls() {
    if (audioState.floatingControlsBound) return;
    audioState.floatingControlsBound = true;

    const scheduleSafeZoneSync = (delay = 0) => {
        if (audioState.floatingAutoDockTimer) {
            clearTimeout(audioState.floatingAutoDockTimer);
            audioState.floatingAutoDockTimer = null;
        }
        audioState.floatingAutoDockTimer = setTimeout(() => {
            syncFloatingAudioSafeZone();
            releaseMobileAudioDockIfNotPinned();
            remapOnResize();
            audioState.floatingAutoDockTimer = null;
        }, Math.max(0, Number(delay) || 0));
    };

    const remapOnResize = () => {
        ['music-toggle-btn', 'audio-master-mute-btn'].forEach((id) => {
            const button = document.getElementById(id);
            if (!button) return;
            const rect = button.getBoundingClientRect();
            if (!Number.isFinite(rect.left) || !Number.isFinite(rect.top)) return;
            if (button.style.left === '' || button.style.top === '') return;
            const clamped = clampAudioControlPosition(button, rect.left, rect.top);
            button.style.left = `${clamped.left}px`;
            button.style.top = `${clamped.top}px`;
            const storageKey = id === 'music-toggle-btn' ? 'music' : 'mute';
            persistAudioControlPosition(storageKey, clamped.left, clamped.top);
        });
    };

    window.addEventListener('resize', () => scheduleSafeZoneSync(0), { passive: true });
    window.addEventListener('scroll', () => {
        fadeFloatingAudioControlsDuringScroll();
        scheduleSafeZoneSync(120);
    }, { passive: true });

    const visualViewport = window.visualViewport;
    if (visualViewport) {
        visualViewport.addEventListener('resize', () => scheduleSafeZoneSync(0), { passive: true });
        visualViewport.addEventListener('scroll', () => scheduleSafeZoneSync(0), { passive: true });
    }

    if (window.MutationObserver && document.body) {
        const observer = new MutationObserver(() => scheduleSafeZoneSync(0));
        observer.observe(document.body, { attributes: true, attributeFilter: ['class'] });
    }

    scheduleSafeZoneSync(0);
}

function setupMusicToggleButton() {
    let btn = document.getElementById('music-toggle-btn');
    if (!btn) {
        btn = document.createElement('button');
        btn.id = 'music-toggle-btn';
        btn.className = 'music-toggle-btn audio-fab audio-floating-control';
        btn.type = 'button';
        btn.setAttribute('data-ui-sound', 'off');
        document.body.appendChild(btn);
    }

    if (btn.dataset.audioBound !== 'true') {
        btn.dataset.audioBound = 'true';
        btn.addEventListener('click', async () => {
            armAudioFromUserInteraction();
            if (audioState.muted) setMutedAudio(false);
            if (isOpeningTrackPlaying()) {
                stopOpeningMusic(true);
                return;
            }
            await playOpeningMusic({ force: true, markFirstEntry: false });
        });
    }

    bindAudioControlDrag(btn, 'music');
    setupFloatingAudioControls();
    updateMusicToggleButtonUI();
}

function ensureFloatingMuteButton() {
    let btn = document.getElementById('audio-master-mute-btn');
    if (!btn) {
        btn = document.createElement('button');
        btn.id = 'audio-master-mute-btn';
        btn.className = 'audio-mute-btn audio-master-mute-btn audio-fab audio-floating-control';
        btn.type = 'button';
        btn.setAttribute('data-ui-sound', 'off');
        document.body.appendChild(btn);
    }
    bindAudioControlDrag(btn, 'mute');
    setupFloatingAudioControls();
    return btn;
}

function updateMuteButtonUI() {
    ensureFloatingMuteButton();
    const btns = document.querySelectorAll('.audio-mute-btn');
    btns.forEach((btn) => {
        if (btn.id === 'audio-master-mute-btn') return;
        btn.textContent = audioState.muted ? 'סאונד כבוי' : 'סאונד פעיל';
        btn.classList.toggle('is-muted', audioState.muted);
    });
    updateFloatingMuteButtonUI();
    updateMusicToggleButtonUI();
    updateHomeLobbyMuteToggleLabel();
}

function setMutedAudio(isMuted) {
    audioState.muted = isMuted;
    try {
        localStorage.setItem('meta_audio_muted', String(isMuted));
    } catch (_error) {
        // Ignore storage failures (common in restricted iframe/privacy contexts).
    }
    if (isMuted) {
        stopOpeningMusic(true);
        stopAllUiSounds();
    }
    updateMuteButtonUI();
}

function toggleAudioMute() {
    setMutedAudio(!audioState.muted);
}

function setupAudioMuteButtons() {
    ensureFloatingMuteButton();
    const btns = document.querySelectorAll('.audio-mute-btn');
    btns.forEach((btn) => {
        if (btn.dataset.audioBound === 'true') return;
        btn.dataset.audioBound = 'true';
        btn.addEventListener('click', toggleAudioMute);
    });
    updateMuteButtonUI();
}

function clearUiSoundSafetyTimer() {
    if (!audioState.uiSafetyStopTimer) return;
    clearTimeout(audioState.uiSafetyStopTimer);
    audioState.uiSafetyStopTimer = null;
}

function stopAllUiSounds() {
    clearUiSoundSafetyTimer();
    audioState.activeUiNodes.forEach((node) => {
        if (!node) return;
        if (typeof node.stop === 'function') {
            try {
                node.stop();
            } catch (_error) {
                // Node may already be stopped.
            }
        }
        if (typeof node.disconnect === 'function') {
            try {
                node.disconnect();
            } catch (_error) {}
        }
    });
    audioState.activeUiNodes.clear();
}

function scheduleUiSoundSafetyStop() {
    clearUiSoundSafetyTimer();
    audioState.uiSafetyStopTimer = setTimeout(() => {
        stopAllUiSounds();
    }, 1500);
}

function playTone(frequency, duration = 0.12, type = 'sine', volume = 0.05, delay = 0) {
    if (audioState.muted || !audioState.audioArmed) return;
    const ctx = ensureAudioContext();
    if (!ctx) return;
    safeResumeAudioContext(ctx);

    const now = ctx.currentTime + delay;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    const output = ensureUiSoundOutput(ctx) || ctx.destination;
    osc.connect(gain);
    gain.connect(output);
    audioState.activeUiNodes.add(osc);
    audioState.activeUiNodes.add(gain);

    const cleanup = () => {
        audioState.activeUiNodes.delete(osc);
        audioState.activeUiNodes.delete(gain);
        try {
            osc.disconnect();
        } catch (_error) {}
        try {
            gain.disconnect();
        } catch (_error) {}
    };

    osc.frequency.value = frequency;
    osc.type = type;
    osc.detune.value = (Math.random() - 0.5) * 6;
    const boostedVolume = Math.min(UI_SOUND_GAIN_LIMIT, Math.max(0.0001, volume * UI_SOUND_GAIN_BOOST));
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(boostedVolume, now + 0.008);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + duration);

    osc.addEventListener('ended', cleanup, { once: true });

    try {
        osc.start(now);
        osc.stop(now + duration + 0.01);
    } catch (_error) {
        cleanup();
    }
}

function playUISound(kind) {
    if (audioState.muted || !audioState.audioArmed) return;
    const soundKind = kind === 'success'
        ? 'correct'
        : kind === 'warning'
            ? 'hint'
            : kind === 'error'
                ? 'wrong'
                : kind;
    const nowMs = (typeof performance !== 'undefined' && typeof performance.now === 'function')
        ? performance.now()
        : Date.now();
    const cooldownMs = Number(UI_SOUND_KIND_COOLDOWNS_MS[soundKind] || 0);
    const lastByKind = Number(audioState.lastUiSoundByKind[soundKind] || 0);
    if (cooldownMs > 0 && (nowMs - lastByKind) < cooldownMs) return;

    audioState.lastUiSoundByKind[soundKind] = nowMs;
    audioState.lastUiSoundAtMs = nowMs;
    if (soundKind === 'correct') {
        playTone(660, 0.12, 'triangle', 0.06, 0);
        playTone(990, 0.1, 'sine', 0.028, 0.02);
        playTone(880, 0.14, 'triangle', 0.06, 0.08);
        playTone(1320, 0.08, 'sine', 0.02, 0.12);
    } else if (soundKind === 'wrong') {
        playTone(220, 0.14, 'sawtooth', 0.05, 0);
        playTone(196, 0.09, 'square', 0.025, 0.04);
        playTone(165, 0.16, 'sawtooth', 0.05, 0.08);
        playTone(132, 0.11, 'sawtooth', 0.02, 0.14);
    } else if (soundKind === 'hint') {
        playTone(540, 0.08, 'sine', 0.04, 0);
        playTone(620, 0.08, 'triangle', 0.04, 0.06);
        playTone(780, 0.05, 'sine', 0.016, 0.1);
    } else if (soundKind === 'skip') {
        playTone(380, 0.08, 'square', 0.04, 0);
        playTone(280, 0.045, 'sine', 0.014, 0.03);
    } else if (soundKind === 'next') {
        playTone(520, 0.08, 'triangle', 0.04, 0);
        playTone(660, 0.05, 'sine', 0.016, 0.045);
    } else if (soundKind === 'start') {
        playTone(523.25, 0.12, 'sine', 0.04, 0);
        playTone(659.25, 0.12, 'triangle', 0.04, 0.09);
        playTone(783.99, 0.1, 'sine', 0.02, 0.16);
    } else if (soundKind === 'finish') {
        playTone(523.25, 0.11, 'triangle', 0.05, 0);
        playTone(659.25, 0.11, 'triangle', 0.05, 0.08);
        playTone(783.99, 0.15, 'triangle', 0.05, 0.16);
        playTone(1046.5, 0.1, 'sine', 0.02, 0.24);
    } else if (soundKind === 'buzzer') {
        playTone(980, 0.06, 'square', 0.06, 0);
        playTone(740, 0.08, 'square', 0.06, 0.06);
        playTone(190, 0.22, 'sawtooth', 0.065, 0.14);
        playTone(130.81, 0.13, 'triangle', 0.018, 0.16);
    } else if (soundKind === 'stars_big') {
        playTone(659.25, 0.08, 'triangle', 0.06, 0);
        playTone(880, 0.1, 'triangle', 0.06, 0.07);
        playTone(1174.66, 0.12, 'triangle', 0.06, 0.15);
        playTone(1567.98, 0.09, 'sine', 0.025, 0.23);
    } else if (soundKind === 'stars_soft') {
        playTone(520, 0.07, 'sine', 0.045, 0);
        playTone(620, 0.08, 'sine', 0.045, 0.06);
        playTone(780, 0.05, 'sine', 0.015, 0.11);
    } else if (soundKind === 'prism_open') {
        playTone(440, 0.1, 'sine', 0.05, 0);
        playTone(554, 0.1, 'sine', 0.05, 0.09);
    } else if (soundKind === 'prism_pick') {
        playTone(720, 0.06, 'triangle', 0.04, 0);
        playTone(980, 0.04, 'sine', 0.012, 0.04);
    } else if (soundKind === 'prism_warn') {
        playTone(240, 0.1, 'square', 0.04, 0);
        playTone(210, 0.1, 'square', 0.04, 0.08);
    } else if (soundKind === 'prism_submit') {
        playTone(600, 0.08, 'triangle', 0.05, 0);
        playTone(760, 0.08, 'triangle', 0.05, 0.08);
        playTone(920, 0.12, 'triangle', 0.05, 0.16);
        playTone(1140, 0.07, 'sine', 0.017, 0.24);
    } else if (soundKind === 'prism_back') {
        playTone(460, 0.08, 'sine', 0.04, 0);
    } else if (soundKind === 'prism_error') {
        playTone(180, 0.12, 'sawtooth', 0.05, 0);
        playTone(150, 0.12, 'sawtooth', 0.05, 0.1);
    } else if (soundKind === 'tap_soft') {
        playTone(510, 0.045, 'sine', 0.022, 0);
        playTone(820, 0.03, 'sine', 0.009, 0.012);
    } else if (soundKind === 'select_soft') {
        playTone(480, 0.05, 'triangle', 0.026, 0);
        playTone(620, 0.055, 'triangle', 0.026, 0.05);
    } else if (soundKind === 'wr2w_quantifier') {
        playTone(740, 0.05, 'triangle', 0.04, 0);
        playTone(920, 0.07, 'triangle', 0.04, 0.05);
    } else if (soundKind === 'wr2w_path') {
        playTone(420, 0.06, 'sine', 0.03, 0);
        playTone(560, 0.07, 'triangle', 0.03, 0.05);
    } else if (soundKind === 'wr2w_submit') {
        playTone(430, 0.06, 'sine', 0.03, 0);
        playTone(520, 0.06, 'sine', 0.03, 0.05);
        playTone(650, 0.08, 'triangle', 0.03, 0.11);
        playTone(760, 0.06, 'sine', 0.014, 0.19);
    } else if (soundKind === 'wr2w_confirm_yes') {
        playTone(620, 0.05, 'triangle', 0.032, 0);
        playTone(780, 0.07, 'triangle', 0.032, 0.05);
    } else if (soundKind === 'wr2w_confirm_partial') {
        playTone(520, 0.055, 'triangle', 0.03, 0);
        playTone(560, 0.06, 'triangle', 0.03, 0.05);
    } else if (soundKind === 'wr2w_confirm_no') {
        playTone(230, 0.07, 'sawtooth', 0.03, 0);
        playTone(190, 0.08, 'sawtooth', 0.03, 0.06);
    } else if (soundKind === 'wr2w_probe') {
        playTone(470, 0.045, 'sine', 0.026, 0);
        playTone(540, 0.045, 'sine', 0.026, 0.04);
    } else if (soundKind === 'wr2w_probe_found') {
        playTone(560, 0.05, 'triangle', 0.03, 0);
        playTone(700, 0.06, 'triangle', 0.03, 0.05);
        playTone(860, 0.08, 'triangle', 0.03, 0.11);
    }
    scheduleUiSoundSafetyStop();
}

function prefersReducedMotion() {
    if (typeof window === 'undefined' || typeof window.matchMedia !== 'function') return false;
    try {
        return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    } catch (_error) {
        return false;
    }
}

function triggerPlayfulFeedbackFx(element, tone = 'info') {
    if (!element || !element.classList || prefersReducedMotion()) return;
    const toneClass = tone === 'success'
        ? 'ui-feedback-success'
        : (tone === 'warn' || tone === 'warning')
            ? 'ui-feedback-warn'
            : (tone === 'danger' || tone === 'error' || tone === 'fail')
                ? 'ui-feedback-danger'
                : 'ui-feedback-info';

    element.classList.remove(
        'ui-feedback-fx',
        'ui-feedback-success',
        'ui-feedback-warn',
        'ui-feedback-danger',
        'ui-feedback-info'
    );
    void element.offsetWidth;
    element.classList.add('ui-feedback-fx', toneClass);

    if (element.__uiFeedbackFxTimer) {
        clearTimeout(element.__uiFeedbackFxTimer);
    }
    element.__uiFeedbackFxTimer = setTimeout(() => {
        if (!element || !element.classList) return;
        element.classList.remove('ui-feedback-fx', toneClass);
        element.__uiFeedbackFxTimer = null;
    }, 700);
}

if (typeof window !== 'undefined') {
    window.triggerPlayfulFeedbackFx = triggerPlayfulFeedbackFx;
}

function setupGlobalInteractionSounds() {
    if (audioState.globalInteractionBound) return;
    audioState.globalInteractionBound = true;

    const nowMs = () => (
        (typeof performance !== 'undefined' && typeof performance.now === 'function')
            ? performance.now()
            : Date.now()
    );

    const canPlayGlobalTap = () => {
        const now = nowMs();
        if ((now - Number(audioState.lastUiSoundAtMs || 0)) < 90) return false;
        if ((now - Number(audioState.lastGlobalTapAtMs || 0)) < 120) return false;
        audioState.lastGlobalTapAtMs = now;
        return true;
    };

    document.addEventListener('click', (event) => {
        const target = event.target && typeof event.target.closest === 'function'
            ? event.target.closest('button, summary, .tab-btn, [role="button"]')
            : null;
        if (!target) return;
        if (target.closest('.wr2w-card')) return; // WR2W gets custom sounds per action
        if (target.matches('.audio-mute-btn, #music-toggle-btn')) return;
        if (target.dataset && target.dataset.uiSound === 'off') return;
        if (!canPlayGlobalTap()) return;
        const isSummary = target.tagName === 'SUMMARY';
        playUISound(isSummary ? 'select_soft' : 'tap_soft');
    });

    document.addEventListener('change', (event) => {
        const target = event.target;
        if (!target || typeof target.matches !== 'function') return;
        if (!target.matches('select')) return;
        if (target.closest('.wr2w-card')) return;
        const now = nowMs();
        if ((now - Number(audioState.lastUiSoundAtMs || 0)) < 90) return;
        playUISound('select_soft');
    });
}

function isRevealActionButtonCandidate(element) {
    if (!element || typeof element.matches !== 'function') return false;
    if (element.matches('.audio-mute-btn, #music-toggle-btn')) return false;
    if (element.matches('input, textarea, select, option')) return false;
    return element.matches(
        'button, .btn, summary, [role="button"], [aria-controls], [data-global-feature-menu-open], [data-feature-picker-open], [data-tr-action], [data-ui-reveal], [data-open-reveal]'
    );
}

function findRevealActionButton(startNode) {
    if (!startNode || typeof startNode.closest !== 'function') return null;
    const button = startNode.closest(
        'button, .btn, summary, [role="button"], [aria-controls], [data-global-feature-menu-open], [data-feature-picker-open], [data-tr-action], [data-ui-reveal], [data-open-reveal]'
    );
    if (!button || !isRevealActionButtonCandidate(button)) return null;
    return button;
}

function applyActionButtonVisualState(button, { sticky = false } = {}) {
    if (!button || !button.classList) return;
    button.classList.add('action-button-active');
    if (sticky) {
        button.setAttribute('data-action-button-sticky', '1');
    }
    if (button.__actionButtonTimer) {
        clearTimeout(button.__actionButtonTimer);
        button.__actionButtonTimer = null;
    }
    if (!sticky) {
        button.__actionButtonTimer = setTimeout(() => {
            button.__actionButtonTimer = null;
            if (button.getAttribute('data-action-button-sticky') === '1') return;
            button.classList.remove('action-button-active');
        }, 230);
    }
}

function clearActionButtonVisualState(button) {
    if (!button || !button.classList) return;
    if (button.__actionButtonTimer) {
        clearTimeout(button.__actionButtonTimer);
        button.__actionButtonTimer = null;
    }
    if (button.__actionButtonStickyTimer) {
        clearTimeout(button.__actionButtonStickyTimer);
        button.__actionButtonStickyTimer = null;
    }
    button.removeAttribute('data-action-button-sticky');
    button.classList.remove('action-button-active');
}

function isElementActuallyVisible(element) {
    if (!element || !(element instanceof Element)) return false;
    if (!element.isConnected) return false;
    if (element.hidden) return false;
    if (element.getAttribute('aria-hidden') === 'true') return false;
    const closedDetails = element.closest('details:not([open])');
    if (closedDetails) {
        const summary = element.closest('summary');
        if (!summary || summary.parentElement !== closedDetails) return false;
    }
    const style = window.getComputedStyle(element);
    if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || 1) <= 0.01) return false;
    const rect = element.getBoundingClientRect();
    return rect.width > 0 && rect.height > 0;
}

function elementLooksLikeOpenedContent(node, trigger) {
    if (!node || !(node instanceof Element)) return false;
    if (node === trigger) return false;
    if (node.matches('button, summary, input, select, textarea, label, option')) return false;
    if (node.matches('.home-route-feature-card, .home-route-features, .mobile-feed-card, .mobile-feed-list, .feature-map-grid, .feature-map-menu-box, .feature-map-menu-sections')) return false;
    if (!isElementActuallyVisible(node)) return false;

    const style = window.getComputedStyle(node);
    if (style.display === 'inline') return false;

    const rect = node.getBoundingClientRect();
    if (rect.width < 80 || rect.height < 20) return false;
    if (rect.width > window.innerWidth * 0.98 && rect.height > window.innerHeight * 0.92) return false;

    const signalText = `${node.id || ''} ${node.className || ''}`;
    const normalizedText = String(node.textContent || '').replace(/\s+/g, ' ').trim();
    if (OPENED_CONTENT_EXCLUDED_HINT_RE.test(signalText)) return false;
    if (OPENED_CONTENT_HINT_RE.test(signalText)) return true;
    if (node.matches('details, section, article, aside')) return normalizedText.length >= 22;
    if (node.classList.contains('card') || node.classList.contains('panel') || node.classList.contains('box')) return normalizedText.length >= 18;
    return normalizedText.length >= 44;
}

function getOpenedContentScore(node, trigger) {
    if (!node || !(node instanceof Element)) return -1;
    if (!elementLooksLikeOpenedContent(node, trigger)) return -1;

    const signalText = `${node.id || ''} ${node.className || ''}`;
    const normalizedText = String(node.textContent || '').replace(/\s+/g, ' ').trim();
    const rect = node.getBoundingClientRect();

    let score = 0;
    if (OPENED_CONTENT_HINT_RE.test(signalText)) score += 7;
    if (node.matches('details, section, article')) score += 4;
    if (node.classList.contains('card') || node.classList.contains('panel') || node.classList.contains('box')) score += 3;
    if (normalizedText.length >= 120) score += 2;
    if (rect.height <= 420) score += 2;
    if (rect.width <= window.innerWidth * 0.9) score += 1;
    if (/container|wrapper|root|layout|app/i.test(signalText)) score -= 4;

    return score;
}

function resolveOpenedContentContainer(startElement, trigger) {
    if (!startElement || !(startElement instanceof Element)) return null;
    let node = startElement;
    let bestNode = null;
    let bestScore = -1;
    let depth = 0;

    while (node && node !== document.body && depth < 9) {
        const score = getOpenedContentScore(node, trigger);
        if (score > bestScore) {
            bestScore = score;
            bestNode = node;
        }
        node = node.parentElement;
        depth += 1;
    }

    return bestScore >= 0 ? bestNode : null;
}

function clearOpenedContentFeedback(element) {
    if (!element || !(element instanceof Element) || !element.classList) return;
    if (element.__openedContentTimer) {
        clearTimeout(element.__openedContentTimer);
        element.__openedContentTimer = null;
    }
    if (element.__openedContentPulseTimer) {
        clearTimeout(element.__openedContentPulseTimer);
        element.__openedContentPulseTimer = null;
    }
    element.classList.remove('opened-content-pulse');
    element.classList.remove('opened-content');
    if (revealFeedbackState.activeContentElement === element) {
        revealFeedbackState.activeContentElement = null;
    }
}

function clearOtherOpenedContentFeedback(activeElement) {
    if (!document || typeof document.querySelectorAll !== 'function') return;
    const opened = document.querySelectorAll('.opened-content');
    opened.forEach((node) => {
        if (!(node instanceof Element)) return;
        if (node === activeElement) return;
        clearOpenedContentFeedback(node);
    });
}

function maybeAssistScrollToOpenedContent(element) {
    if (!element || !(element instanceof Element) || typeof element.scrollIntoView !== 'function') return;
    const now = Date.now();
    if (now < Number(revealFeedbackState.scrollCooldownUntil || 0)) return;
    const rect = element.getBoundingClientRect();
    const viewportHeight = Math.max(1, window.innerHeight || document.documentElement?.clientHeight || 1);
    const isMobileViewport = isMobileViewportMode();
    const isOutsideFocusBand = rect.top < 88 || rect.bottom > (viewportHeight - 80);
    if (isMobileViewport) return;
    if (!isOutsideFocusBand) return;

    revealFeedbackState.scrollCooldownUntil = now + OPENED_CONTENT_SCROLL_COOLDOWN_MS;
    try {
        element.scrollIntoView({
            behavior: prefersReducedMotion() ? 'auto' : 'smooth',
            block: 'center',
            inline: 'nearest'
        });
    } catch (_error) {
        try {
            element.scrollIntoView();
        } catch (_ignored) {}
    }
}

function applyOpenedContentFeedback(element, triggerButton) {
    if (!element || !(element instanceof Element) || !element.classList) return;
    if (!isElementActuallyVisible(element)) return;

    if (revealFeedbackState.activeContentElement && revealFeedbackState.activeContentElement !== element) {
        clearOpenedContentFeedback(revealFeedbackState.activeContentElement);
    }
    clearOtherOpenedContentFeedback(element);
    revealFeedbackState.activeContentElement = element;

    element.classList.add('opened-content');
    element.classList.remove('opened-content-pulse');
    void element.offsetWidth;
    element.classList.add('opened-content-pulse');

    if (element.__openedContentPulseTimer) clearTimeout(element.__openedContentPulseTimer);
    element.__openedContentPulseTimer = setTimeout(() => {
        if (!element || !element.classList) return;
        element.classList.remove('opened-content-pulse');
        element.__openedContentPulseTimer = null;
    }, 480);

    if (element.__openedContentTimer) clearTimeout(element.__openedContentTimer);
    element.__openedContentTimer = setTimeout(() => {
        if (!element || !element.classList) return;
        element.__openedContentTimer = null;
        if (!isElementActuallyVisible(element)) {
            clearOpenedContentFeedback(element);
            return;
        }
        element.classList.remove('opened-content');
        if (revealFeedbackState.activeContentElement === element) {
            revealFeedbackState.activeContentElement = null;
        }
    }, OPENED_CONTENT_TRANSIENT_MS);

    maybeAssistScrollToOpenedContent(element);

    if (triggerButton) {
        applyActionButtonVisualState(triggerButton, { sticky: true });
        if (triggerButton.__actionButtonStickyTimer) clearTimeout(triggerButton.__actionButtonStickyTimer);
        triggerButton.__actionButtonStickyTimer = setTimeout(() => {
            triggerButton.__actionButtonStickyTimer = null;
            triggerButton.removeAttribute('data-action-button-sticky');
            syncActionButtonOpenState(triggerButton);
        }, 3600);
    }
}

function isControlledPanelOpenByButton(button) {
    if (!button || !(button instanceof Element)) return false;
    if (button.tagName === 'SUMMARY') {
        const details = button.closest('details');
        return !!(details && details.open);
    }
    if (button.getAttribute('aria-expanded') === 'true') return true;

    const controls = String(button.getAttribute('aria-controls') || '').trim();
    if (!controls) return false;
    const ids = controls.split(/\s+/).filter(Boolean);
    return ids.some((id) => {
        const controlled = document.getElementById(id);
        return !!controlled && isElementActuallyVisible(controlled);
    });
}

function syncActionButtonOpenState(button) {
    if (!button || !(button instanceof Element) || !button.classList.contains('action-button')) return;
    const isOpen = isControlledPanelOpenByButton(button);
    if (isOpen) {
        applyActionButtonVisualState(button, { sticky: true });
    } else if (button.getAttribute('data-action-button-sticky') === '1') {
        clearActionButtonVisualState(button);
    }
}

function refreshActionButtonDecorators(root = document) {
    if (!root) return;
    const selector = 'button, .btn, summary, [role="button"], [aria-controls], [data-global-feature-menu-open], [data-feature-picker-open], [data-tr-action], [data-ui-reveal], [data-open-reveal]';
    const nodes = [];
    if (root instanceof Element && root.matches(selector)) nodes.push(root);
    if (typeof root.querySelectorAll === 'function') {
        nodes.push(...Array.from(root.querySelectorAll(selector)));
    }
    nodes.forEach((node) => {
        if (!isRevealActionButtonCandidate(node)) return;
        node.classList.add('action-button');
    });
}

function handleRevealFeedbackMutations(records) {
    const mutationList = Array.from(records || []);
    if (!mutationList.length) return;
    const now = Date.now();
    const withinActionWindow = (now - Number(revealFeedbackState.lastActionAt || 0)) <= OPENED_CONTENT_ACTION_WINDOW_MS;
    const candidateElements = new Set();

    mutationList.forEach((record) => {
        if (!record) return;
        if (record.type === 'childList') {
            if (withinActionWindow && record.target instanceof Element) candidateElements.add(record.target);
            record.addedNodes.forEach((node) => {
                if (!(node instanceof Element)) return;
                refreshActionButtonDecorators(node);
                if (withinActionWindow) candidateElements.add(node);
            });
            return;
        }

        if (record.type === 'attributes') {
            const target = record.target;
            if (target instanceof Element) {
                if (
                    record.attributeName === 'class'
                    && target.classList
                    && (
                        target.classList.contains('opened-content')
                        || target.classList.contains('opened-content-pulse')
                        || target.classList.contains('action-button-active')
                    )
                ) {
                    return;
                }
                if (record.attributeName === 'aria-expanded') {
                    syncActionButtonOpenState(target);
                } else if (record.attributeName === 'open' && target.tagName === 'DETAILS') {
                    const summary = target.querySelector(':scope > summary');
                    if (summary) syncActionButtonOpenState(summary);
                }
                if (withinActionWindow) {
                    candidateElements.add(target);
                } else if (target.classList.contains('opened-content')) {
                    candidateElements.add(target);
                }
            }
        }
    });

    candidateElements.forEach((element) => {
        if (!(element instanceof Element)) return;

        if (!isElementActuallyVisible(element)) {
            clearOpenedContentFeedback(element);
            if (typeof element.querySelectorAll === 'function') {
                element.querySelectorAll('.opened-content').forEach((node) => clearOpenedContentFeedback(node));
            }
            return;
        }

        if (!withinActionWindow) return;
        const container = resolveOpenedContentContainer(element, revealFeedbackState.lastActionButton);
        if (!container) return;
        if (!isElementActuallyVisible(container)) return;
        applyOpenedContentFeedback(container, revealFeedbackState.lastActionButton);
    });
}

function setupGlobalRevealFeedback() {
    if (revealFeedbackState.bound) return;
    revealFeedbackState.bound = true;
    const isLightweightMode = hasCoarsePointerInput();
    revealFeedbackState.lightweightMode = isLightweightMode;
    refreshActionButtonDecorators(document);

    const registerAction = (event) => {
        const trigger = findRevealActionButton(event.target);
        if (!trigger) return;
        if (trigger.closest('.categories-glossary-ordered-list')) return;
        revealFeedbackState.lastActionAt = Date.now();
        revealFeedbackState.lastActionButton = trigger;
        applyActionButtonVisualState(trigger, { sticky: false });
        setTimeout(() => syncActionButtonOpenState(trigger), 260);
    };

    document.addEventListener('pointerdown', registerAction, true);
    document.addEventListener('click', registerAction, true);
    document.addEventListener('keydown', (event) => {
        if (!event || (event.key !== 'Enter' && event.key !== ' ')) return;
        registerAction(event);
    }, true);
    document.addEventListener('toggle', (event) => {
        const details = event.target;
        if (!(details instanceof Element) || details.tagName !== 'DETAILS') return;
        if (details.closest('.categories-glossary-ordered-list')) {
            clearOpenedContentFeedback(details);
            return;
        }
        const summary = details.querySelector(':scope > summary');
        if (!summary) return;
        revealFeedbackState.lastActionAt = Date.now();
        revealFeedbackState.lastActionButton = summary;
        syncActionButtonOpenState(summary);
        if (isLightweightMode) {
            clearOpenedContentFeedback(details);
            return;
        }
        if (details.open) applyOpenedContentFeedback(details, summary);
        else clearOpenedContentFeedback(details);
    }, true);

    const observerTarget = document.body || document.documentElement;
    if (!isLightweightMode && window.MutationObserver && observerTarget) {
        revealFeedbackState.observer = new MutationObserver(handleRevealFeedbackMutations);
        revealFeedbackState.observer.observe(observerTarget, {
            subtree: true,
            childList: true,
            attributes: true,
            attributeFilter: OPENED_CONTENT_ATTR_NAMES
        });
    }
}

function stopOpeningMusic(resetToStart = false) {
    clearMusicSnippetTimer();
    audioState.musicTracks.forEach((track) => {
        if (!track) return;
        if (!track.paused) track.pause();
        if (resetToStart) track.currentTime = 0;
    });
    if (resetToStart) {
        audioState.openingTrack = null;
    }
    updateMusicToggleButtonUI();
}

async function playOpeningMusic({ force = false, markFirstEntry = false, source = '' } = {}) {
    if (audioState.muted && !force) return false;
    const selectedSource = String(source || '').trim() || pickRandomMusicSource(audioState.musicLastSource);
    if (!selectedSource) return false;

    try {
        const track = ensureOpeningTrack(selectedSource);
        if (!track) return false;
        stopOpeningMusic(true);
        audioState.openingTrack = track;
        track.currentTime = 0;
        await track.play();
        audioState.openingPlayed = true;
        audioState.musicLastSource = selectedSource;
        audioState.musicAutoplayPending = false;
        scheduleMusicSnippetStop(track);
        if (markFirstEntry) {
            audioState.firstEntryDone = true;
            try {
                localStorage.setItem(OPENING_TRACK_FIRST_ENTRY_KEY, 'true');
            } catch (_error) {
                // Ignore storage failures in restricted embeds/iframes.
            }
        }
        updateMusicToggleButtonUI();
        return true;
    } catch (e) {
        if (!audioState.muted) {
            audioState.musicAutoplayPending = true;
        }
        updateMusicToggleButtonUI();
        return false;
    }
}

function setupOpeningMusicOnFirstEntry() {
    if (audioState.muted) {
        updateMusicToggleButtonUI();
        return;
    }

    // Try autoplay on startup; when the browser blocks autoplay we retry on first interaction.
    playOpeningMusic({ force: true, markFirstEntry: true });

    const onFirstInteraction = () => {
        document.removeEventListener('pointerdown', onFirstInteraction, true);
        document.removeEventListener('keydown', onFirstInteraction, true);
        document.removeEventListener('touchstart', onFirstInteraction, true);
        if (audioState.muted) return;
        if (!audioState.musicAutoplayPending && isOpeningTrackPlaying()) return;
        armAudioFromUserInteraction();
        playOpeningMusic({ force: true, markFirstEntry: true });
    };

    document.addEventListener('pointerdown', onFirstInteraction, { once: true, capture: true });
    document.addEventListener('keydown', onFirstInteraction, { once: true, capture: true });
    document.addEventListener('touchstart', onFirstInteraction, { once: true, capture: true, passive: true });
}

function setupGlobalAudioSafety() {
    if (audioState.audioSafetyBound) return;
    audioState.audioSafetyBound = true;

    const stopTransientAudio = (resetTrack = false) => {
        stopAllUiSounds();
        stopOpeningMusic(resetTrack);
    };

    document.addEventListener('visibilitychange', () => {
        if (document.hidden) {
            stopTransientAudio(false);
        }
    });

    window.addEventListener('blur', () => {
        stopTransientAudio(false);
    });

    window.addEventListener('pagehide', () => {
        stopTransientAudio(true);
    });

    window.addEventListener('beforeunload', () => {
        stopTransientAudio(true);
    });
}

// Hide Splash Screen
function hideSplashScreen() {
    const splashScreen = document.getElementById('splash-screen');
    if (!splashScreen) return;

    if (document.body.classList.contains('embed-mode')) {
        splashScreen.classList.add('hidden');
        splashScreen.style.pointerEvents = 'none';
        splashScreen.style.display = 'none';
        return;
    }

    // The animation handles the fade out after 3 seconds
    // Just ensure it's hidden after animation
    setTimeout(() => {
        if (splashScreen) {
            splashScreen.classList.add('hidden');
            splashScreen.style.pointerEvents = 'none'; // Ensure clicks pass through
        }
    }, 3600);
}

function normalizeViewMode(rawMode = '') {
    const value = String(rawMode || '').trim().toLowerCase();
    if (!value) return '';
    if (value === 'mobile' || value === 'phone' || value === 'm') return 'mobile';
    if (value === 'desktop' || value === 'computer' || value === 'pc' || value === 'd') return 'desktop';
    return '';
}

function applyEmbeddedCompactMode() {
    let embedded = false;
    try {
        embedded = window.self !== window.top;
    } catch (error) {
        embedded = true;
    }

    const params = new URLSearchParams(window.location.search);
    const viewMode = normalizeViewMode(params.get('view') || params.get('device'));
    if (viewMode) {
        document.body.classList.add(`view-${viewMode}`);
        document.body.classList.remove('force-mobile-view', 'force-desktop-view');
        document.body.classList.add(viewMode === 'mobile' ? 'force-mobile-view' : 'force-desktop-view');
    }

    if (params.get('compact') === '1' || params.get('embed') === '1' || viewMode === 'mobile') {
        embedded = true;
    }

    let forceSimple = params.get('simple') === '1';
    let disableSimple = params.get('simple') === '0';
    if (viewMode === 'mobile') {
        forceSimple = true;
        disableSimple = false;
    } else if (viewMode === 'desktop') {
        disableSimple = true;
    }

    if (embedded) {
        document.body.classList.add('embed-mode');
    }

    if (forceSimple || (embedded && !disableSimple)) {
        document.body.classList.add('minimal-ui');
    }
}

function enforceTopMenuOnlyMode() {
    const body = document.body;
    if (!body) return;
    body.classList.add('hide-top-tabbar');

    ['.tabs', '.mobile-tab-nav'].forEach((selector) => {
        document.querySelectorAll(selector).forEach((el) => {
            el.setAttribute('aria-hidden', 'true');
            try {
                el.style.setProperty('display', 'none', 'important');
                el.style.setProperty('visibility', 'hidden', 'important');
                el.style.setProperty('height', '0', 'important');
                el.style.setProperty('overflow', 'hidden', 'important');
                el.style.setProperty('pointer-events', 'none', 'important');
            } catch (_error) {
                // ignore style application failures
            }
        });
    });
}

function applyHeaderDensityPreference() {
    const params = new URLSearchParams(window.location.search);
    const forceFull = params.get('fullheader') === '1';
    const forceCompact = params.get('compactheader') === '1';
    const savedMode = (localStorage.getItem('header_density_v1') || 'compact').toLowerCase();

    let mode = savedMode === 'full' ? 'full' : 'compact';
    if (forceFull) mode = 'full';
    if (forceCompact) mode = 'compact';

    document.body.classList.toggle('compact-header', mode === 'compact');
    localStorage.setItem('header_density_v1', mode);
}

function normalizeRequestedTab(tabName = '') {
    const raw = String(tabName || '').trim();
    const key = raw.toLowerCase();
    if (!raw) return '';
    if (key === 'practice' || key === 'practice-question' || key === 'question') return 'practice-question';
    if (key === 'practice-radar' || key === 'radar' || key === 'meta-radar' || key === 'meta_radar') return 'practice-radar';
    if (key === 'practice-triples-radar' || key === 'triples-radar' || key === 'triples_radar' || key === 'breen-radar' || key === 'michael-breen') return 'practice-triples-radar';
    if (key === 'practice-wizard' || key === 'wizard' || key === 'sqhcel') return 'practice-wizard';
    if (key === 'practice-verb-unzip' || key === 'verb-unzip' || key === 'unspecified-verb' || key === 'unzip') return 'practice-verb-unzip';
    return raw;
}

