function setFeatureMapToggleOpen(isOpen) {
    const featureMap = document.getElementById('feature-map-toggle');
    if (!featureMap) return;
    if (isOpen) featureMap.setAttribute('open', '');
    else featureMap.removeAttribute('open');
}

function openFeatureMapMenu() {
    if (window.MetaAppShell
        && typeof window.MetaAppShell.isHomeShellActive === 'function'
        && window.MetaAppShell.isHomeShellActive()
        && typeof window.MetaAppShell.openHomeMenu === 'function') {
        const handled = window.MetaAppShell.openHomeMenu();
        if (handled) return;
    }

    const featureMap = document.getElementById('feature-map-toggle');
    if (!featureMap) return;
    setFeatureMapToggleOpen(true);
}

function setupFeatureMapOverlayControls() {
    const featureMap = document.getElementById('feature-map-toggle');
    if (!featureMap || featureMap.dataset.boundOverlayFeatureMap === 'true') return;
    featureMap.dataset.boundOverlayFeatureMap = 'true';
    const summary = featureMap.querySelector('summary');

    const openBtn = document.getElementById('home-open-feature-map');
    if (openBtn && openBtn.dataset.boundFeatureMapOpen !== 'true') {
        openBtn.dataset.boundFeatureMapOpen = 'true';
        openBtn.addEventListener('click', () => openFeatureMapMenu());
    }

    if (summary && summary.dataset.boundFeatureMapSummaryShell !== 'true') {
        summary.dataset.boundFeatureMapSummaryShell = 'true';
        summary.addEventListener('click', (event) => {
            if (!window.MetaAppShell
                || typeof window.MetaAppShell.isHomeShellActive !== 'function'
                || !window.MetaAppShell.isHomeShellActive()) {
                return;
            }
            event.preventDefault();
            openFeatureMapMenu();
        });
    }

    featureMap.addEventListener('toggle', () => {
        document.body.classList.toggle('feature-map-open', featureMap.open);
    });

    document.addEventListener('click', (event) => {
        if (!featureMap.open) return;
        if (event.target?.closest?.('#home-open-feature-map')) return;
        if (featureMap.contains(event.target)) return;
        setFeatureMapToggleOpen(false);
    });

    document.addEventListener('keydown', (event) => {
        if (event.key !== 'Escape') return;
        if (!featureMap.open) return;
        setFeatureMapToggleOpen(false);
    });
}

function readHomeLobbyReducedMotionSetting() {
    try {
        return String(localStorage.getItem(HOME_LOBBY_REDUCED_MOTION_KEY) || '').trim().toLowerCase();
    } catch (_error) {
        return '';
    }
}

function resolveHomeLobbyReducedMotionEnabled() {
    const stored = readHomeLobbyReducedMotionSetting();
    if (stored === 'true') return true;
    if (stored === 'false') return false;
    try {
        return Boolean(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches);
    } catch (_error) {
        return false;
    }
}

function applyHomeLobbyMotionPreference() {
    const homeRoot = document.getElementById('home');
    const toggle = document.getElementById('home-lobby-reduce-motion-toggle');
    const reduced = resolveHomeLobbyReducedMotionEnabled();

    if (homeRoot) {
        homeRoot.classList.toggle('is-reduced-motion', reduced);
    }

    if (toggle) {
        toggle.setAttribute('aria-pressed', reduced ? 'true' : 'false');
        toggle.textContent = reduced ? 'הפחת אנימציות: פעיל' : 'הפחת אנימציות: כבוי';
    }
}

function updateHomeLobbyMuteToggleLabel() {
    const toggle = document.getElementById('home-lobby-mute-toggle');
    if (!toggle) return;
    const muted = Boolean(audioState.muted);
    toggle.setAttribute('aria-pressed', muted ? 'true' : 'false');
    toggle.textContent = muted ? 'צלילים: כבוי' : 'צלילים: פעיל';
}

function triggerHomeLobbyDemoConfetti(confettiRoot) {
    if (!confettiRoot) return;
    const palette = ['#2dd4bf', '#22d3ee', '#38bdf8', '#34d399', '#14b8a6', '#0ea5e9'];
    const dots = Array.from({ length: 8 }).map((_, index) => {
        const right = 10 + Math.round(Math.random() * 78);
        const top = 52 + Math.round(Math.random() * 30);
        const color = palette[index % palette.length];
        const delay = (Math.random() * 120).toFixed(0);
        return `<span class="home-lobby-confetti-dot" style="right:${right}%;top:${top}%;background:${color};animation-delay:${delay}ms;"></span>`;
    }).join('');
    confettiRoot.innerHTML = dots;
    confettiRoot.classList.remove('is-burst');
    // Reflow to restart animation cleanly.
    void confettiRoot.offsetWidth;
    confettiRoot.classList.add('is-burst');
    setTimeout(() => {
        confettiRoot.classList.remove('is-burst');
    }, 760);
}

function setupHomeLobbyMicroDemo() {
    const demo = document.getElementById('home-lobby-micro-demo');
    if (!demo || demo.dataset.boundMicroDemo === 'true') return;
    demo.dataset.boundMicroDemo = 'true';

    const feedback = document.getElementById('home-lobby-demo-feedback');
    const confetti = document.getElementById('home-lobby-confetti');
    const choiceButtons = Array.from(demo.querySelectorAll('[data-home-demo-choice]'));

    const clearChoiceState = () => {
        choiceButtons.forEach((btn) => {
            btn.classList.remove('is-correct', 'is-wrong');
        });
        if (feedback) {
            feedback.classList.remove('is-correct', 'is-wrong');
            feedback.textContent = '';
        }
    };

    choiceButtons.forEach((button) => {
        button.addEventListener('click', () => {
            clearChoiceState();
            const choice = String(button.getAttribute('data-home-demo-choice') || '').trim();
            const isCorrect = choice === '2';

            if (isCorrect) {
                button.classList.add('is-correct');
                if (feedback) {
                    feedback.textContent = 'בום 🎯 פתאום יש חריגים → ויש עם מה לעבוד.';
                    feedback.classList.add('is-correct');
                }
                triggerHomeLobbyDemoConfetti(confetti);
                playUISound('success');
                return;
            }

            button.classList.add('is-wrong');
            if (feedback) {
                feedback.textContent = 'חפש את המילה שעושה "הכל או כלום"…';
                feedback.classList.add('is-wrong');
            }
            demo.classList.remove('is-shake');
            void demo.offsetWidth;
            demo.classList.add('is-shake');
            setTimeout(() => demo.classList.remove('is-shake'), 320);
            playUISound('tap_soft');
        });
    });
}

function setupHomeLobbyExperience() {
    const homeRoot = document.getElementById('home');
    if (!homeRoot) return;

    applyHomeLobbyMotionPreference();
    updateHomeLobbyMuteToggleLabel();
    setupHomeLobbyMicroDemo();

    const reduceMotionToggle = document.getElementById('home-lobby-reduce-motion-toggle');
    if (reduceMotionToggle && reduceMotionToggle.dataset.boundReducedMotion !== 'true') {
        reduceMotionToggle.dataset.boundReducedMotion = 'true';
        reduceMotionToggle.addEventListener('click', () => {
            const nextState = !resolveHomeLobbyReducedMotionEnabled();
            try {
                localStorage.setItem(HOME_LOBBY_REDUCED_MOTION_KEY, String(nextState));
            } catch (_error) {
                // ignore storage write issues
            }
            applyHomeLobbyMotionPreference();
            playUISound('tap_soft');
        });
    }

    const muteToggle = document.getElementById('home-lobby-mute-toggle');
    if (muteToggle && muteToggle.dataset.boundHomeMute !== 'true') {
        muteToggle.dataset.boundHomeMute = 'true';
        muteToggle.addEventListener('click', () => {
            toggleAudioMute();
            updateHomeLobbyMuteToggleLabel();
        });
    }
}

function stripIdsFromCloneTree(root) {
    if (!root || !(root instanceof Element)) return;
    if (root.hasAttribute('id')) root.removeAttribute('id');
    root.querySelectorAll('[id]').forEach((node) => node.removeAttribute('id'));
}

function resolveMobileAccordionTitle(source) {
    const explicit = String(source?.getAttribute?.('data-mobile-collapsible-title') || '').trim();
    if (explicit) return explicit;
    const key = `${String(source?.id || '')} ${String(source?.className || '')}`.toLowerCase();
    if (/setting|advanced|מתקד|אפשרויות/.test(key)) return 'אפשרויות מתקדמות';
    if (/stat|score|history|תוצאה|נתונ|סטטיסט/.test(key)) return 'סטטיסטיקות';
    if (/example|demo|דוגמ/.test(key)) return 'דוגמאות';
    return 'הסבר';
}

function isEligibleMobileAccordionSource(source) {
    if (!source || !(source instanceof Element)) return false;
    if (source.closest('.mobile-accordion') || source.classList.contains('mobile-accordion-source')) return false;
    if (source.matches('.hidden, [hidden], [aria-hidden="true"]')) return false;
    if (source.querySelector('input, select, textarea, button, iframe, canvas, video')) return false;
    const text = normalizeUiText(source.textContent || '');
    return text.length >= 55;
}

function injectMobileAccordionFromSource(source) {
    if (!isEligibleMobileAccordionSource(source)) return;
    source.classList.add('mobile-accordion-source');
    source.setAttribute('data-mobile-collapsed', '1');

    const accordion = document.createElement('details');
    accordion.className = 'mobile-accordion';
    accordion.setAttribute('data-mobile-accordion', 'true');

    const summary = document.createElement('summary');
    summary.className = 'mobile-accordion-summary';
    summary.textContent = resolveMobileAccordionTitle(source);

    const body = document.createElement('div');
    body.className = 'mobile-accordion-body';

    const clone = source.cloneNode(true);
    stripIdsFromCloneTree(clone);
    body.appendChild(clone);

    accordion.appendChild(summary);
    accordion.appendChild(body);
    source.insertAdjacentElement('afterend', accordion);
}

function setupMobileAccordions() {
    if (mobileExperienceRuntime.accordionsBuilt) return;
    if (!isMobileViewportMode()) return;
    const sections = Array.from(document.querySelectorAll('.tab-content[id]'));
    if (!sections.length) return;
    sections.forEach((section) => {
        const tabId = String(section.id || '').trim();
        if (!tabId || tabId === 'home' || tabId === 'debug') return;
        const candidates = [];
        section.querySelectorAll('.subtitle').forEach((node) => candidates.push(node));
        section.querySelectorAll('[data-mobile-collapsible]').forEach((node) => candidates.push(node));
        section.querySelectorAll('.muted-note').forEach((node) => candidates.push(node));
        candidates.forEach((candidate) => injectMobileAccordionFromSource(candidate));
    });
    mobileExperienceRuntime.accordionsBuilt = true;
}

function scheduleMobileAccordionBuild() {
    if (mobileExperienceRuntime.accordionsBuilt || mobileExperienceRuntime.accordionBuildScheduled) return;
    if (!isMobileViewportMode()) return;
    mobileExperienceRuntime.accordionBuildScheduled = true;

    const run = () => {
        mobileExperienceRuntime.accordionBuildScheduled = false;
        setupMobileAccordions();
    };

    if (typeof window.requestIdleCallback === 'function') {
        window.requestIdleCallback(() => run(), { timeout: 480 });
        return;
    }
    setTimeout(run, 0);
}

function ensureMobileStickyCta() {
    let root = document.getElementById(MOBILE_STICKY_CTA_ID);
    if (root) return root;

    root = document.createElement('div');
    root.id = MOBILE_STICKY_CTA_ID;
    root.className = 'mobile-sticky-cta hidden';
    root.innerHTML = `
        <button type="button" class="btn btn-primary" data-mobile-sticky-primary>פעולה ראשית</button>
        <button type="button" class="btn btn-secondary" data-mobile-sticky-menu>תפריט</button>
    `;

    root.addEventListener('click', (event) => {
        const primaryBtn = event.target?.closest?.('[data-mobile-sticky-primary]');
        if (primaryBtn) {
            const target = mobileExperienceRuntime.stickyPrimaryTarget;
            if (target && typeof target.click === 'function' && !target.disabled) {
                target.click();
                return;
            }
        }

        const menuBtn = event.target?.closest?.('[data-mobile-sticky-menu]');
        if (menuBtn) {
            openFeatureMapMenu();
        }
    });

    document.body.appendChild(root);
    return root;
}

function isEligibleStickyActionButton(button) {
    if (!button || !(button instanceof HTMLButtonElement)) return false;
    if (button.disabled) return false;
    if (!isElementActuallyVisible(button)) return false;
    if (button.closest(`#${MOBILE_STICKY_CTA_ID}`)) return false;
    if (button.closest('.feature-home-back-bar')) return false;
    if (button.closest('.screen-read-guide')) return false;
    if (button.closest('.global-theory-launcher')) return false;
    const text = normalizeUiText(button.textContent || '');
    if (!text) return false;
    if (/חזרה|back/i.test(text)) return false;
    if (/קרא\/?י לפני|דיאלוג טיפולי|תיאוריה|קטגוריות/i.test(text)) return false;
    return true;
}

function resolveStickyPrimaryButton(section) {
    if (!section) return null;
    const selectorPriority = [
        '[data-mobile-primary-action]',
        'button.btn.btn-primary',
        'button.btn-primary',
        'button[data-tr-action="next"]',
        'button[id*="start"]',
        'button[id*="next"]'
    ];
    for (const selector of selectorPriority) {
        const nodes = Array.from(section.querySelectorAll(selector));
        const match = nodes.find((node) => isEligibleStickyActionButton(node));
        if (match) return match;
    }
    return null;
}

function setMobileStickyCtaVisibility(isVisible) {
    const root = ensureMobileStickyCta();
    root.classList.toggle('hidden', !isVisible);
    document.body.classList.toggle('mobile-sticky-cta-visible', Boolean(isVisible));
}

function updateMobileStickyCta(tabName = '') {
    const activeTab = normalizeRequestedTab(tabName) || getCurrentActiveTabName();
    syncGlobalTheoryLauncherVisibility(activeTab);
    if (!isMobileViewportMode() || !activeTab || MOBILE_STICKY_DISABLED_TABS.has(activeTab)) {
        mobileExperienceRuntime.stickyPrimaryTarget = null;
        setMobileStickyCtaVisibility(false);
        return;
    }

    const activeSection = document.getElementById(activeTab);
    if (!activeSection || !activeSection.classList.contains('active')) {
        mobileExperienceRuntime.stickyPrimaryTarget = null;
        setMobileStickyCtaVisibility(false);
        return;
    }

    const primaryTarget = resolveStickyPrimaryButton(activeSection);
    if (!primaryTarget) {
        mobileExperienceRuntime.stickyPrimaryTarget = null;
        setMobileStickyCtaVisibility(false);
        return;
    }

    mobileExperienceRuntime.stickyPrimaryTarget = primaryTarget;
    const root = ensureMobileStickyCta();
    const primaryBtn = root.querySelector('[data-mobile-sticky-primary]');
    if (primaryBtn) {
        const label = normalizeUiText(primaryTarget.textContent || '') || 'המשך';
        primaryBtn.textContent = label.length > 28 ? `${label.slice(0, 28)}…` : label;
    }

    setMobileStickyCtaVisibility(true);
}

function setupMobileStickyCta() {
    if (mobileExperienceRuntime.stickyBound) return;
    mobileExperienceRuntime.stickyBound = true;
    ensureMobileStickyCta();

    if (!mobileExperienceRuntime.stickyPollTimerId) {
        mobileExperienceRuntime.stickyPollTimerId = setInterval(() => {
            if (!isMobileViewportMode() || document.hidden) return;
            const activeTab = getCurrentActiveTabName();
            updateMobileStickyCta(activeTab);
        }, MOBILE_STICKY_CTA_POLL_INTERVAL_MS);
    }
}

function setupMobileExperienceLayer() {
    setupMobileViewportWatcher();
    scheduleMobileAccordionBuild();
    setupMobileStickyCta();
    const activeTab = getCurrentActiveTabName();
    syncHomeMobileFeedMode(activeTab);
    updateMobileStickyCta(activeTab);
}

function setupGlobalFeatureMenuDropdown() {
    const featureMap = document.getElementById('feature-map-toggle');
    const body = featureMap?.querySelector('.feature-map-body');
    if (!featureMap || !body || featureMap.dataset.globalFeatureMenuBound === 'true') return;
    featureMap.dataset.globalFeatureMenuBound = 'true';

    const summary = featureMap.querySelector('.feature-map-summary');
    const summaryTitle = featureMap.querySelector('.feature-map-summary-title');
    const featureMapIntro = featureMap.querySelector('.feature-map-intro');
    if (summaryTitle) summaryTitle.textContent = 'תפריט האימונים';
    if (featureMapIntro) {
        featureMapIntro.textContent = 'תפריט אחד לשני סוגי כלים: בוחרים מהתפריט המתאים והניווט נפתח מיד.';
    }
    if (summary && !summary.querySelector('small')) {
        const badge = document.createElement('small');
        badge.textContent = 'פתוח';
        summary.appendChild(badge);
    }

    const menuBox = document.createElement('div');
    menuBox.className = 'feature-map-menu-box';
    menuBox.innerHTML = `
        <div class="feature-map-menu-head">
            <strong>תפריט האימונים והתרגילים</strong>
            <small>בחירה אחת וכניסה מיידית</small>
        </div>
        <div class="feature-map-menu-sections">
            <section class="feature-map-menu-section">
                <label class="feature-map-menu-label" for="global-feature-menu-in-app">מסכים בתוך האפליקציה</label>
                <select id="global-feature-menu-in-app" class="feature-map-menu-select" data-global-feature-menu-select="in-app" aria-label="בחירת מסך בתוך האפליקציה"></select>
            </section>
            <section class="feature-map-menu-section">
                <label class="feature-map-menu-label" for="global-feature-menu-standalone">כלים נפרדים</label>
                <select id="global-feature-menu-standalone" class="feature-map-menu-select" data-global-feature-menu-select="standalone" aria-label="בחירת כלי חיצוני"></select>
            </section>
        </div>
        <p class="feature-map-menu-tip">אין כפתור נוסף: כל בחירה בתפריט פותחת את המסך מיד.</p>
    `;
    body.prepend(menuBox);
    featureMap.classList.add('is-menu-enhanced');
    setFeatureMapToggleOpen(false);

    const inAppSelect = menuBox.querySelector('[data-global-feature-menu-select="in-app"]');
    const standaloneSelect = menuBox.querySelector('[data-global-feature-menu-select="standalone"]');
    if (!inAppSelect || !standaloneSelect) return;

    const resolveTabFeatureTitle = (tabId = '', fallbackLabel = '') => {
        const safeTabId = String(tabId || '').trim();
        const fallback = String(fallbackLabel || '').trim();
        if (!safeTabId || safeTabId === 'home') return fallback;
        const section = document.getElementById(safeTabId);
        if (!section) return fallback;
        const heading = section.querySelector('[data-feature-title], h2, h3');
        const headingText = normalizeUiText(String(heading?.textContent || '').replace(/\s+/g, ' ').trim());
        if (!headingText || looksLikeMojibakeText(headingText)) return fallback;
        return headingText;
    };

    const entries = [];
    const seenKeys = new Set();
    const labelOverrides = Object.freeze({
        'tab:home': 'בית · התחלה והכוונה',
        'tab:scenario-trainer': 'סימולטור סצנות · משגר',
        'tab:comic-engine': 'במת קומיקס רגשי · תגובות ומהלכים',
        'tab:categories': 'מילון קטגוריות המטה-מודל',
        'tab:practice-question': 'תרגול זיהוי מטה-מודל',
        'tab:practice-radar': 'מכ"ם מטה-מודל',
        'tab:practice-triples-radar': 'מכ"ם שלשות (ברין)',
        'tab:practice-wizard': 'גשר תחושה-שפה · הלימה לפני שינוי',
        'tab:practice-verb-unzip': 'מרכז כלים',
        'tab:blueprint': 'בונה מהלך',
        'tab:prismlab': 'מעבדת פריזמות · רמות לוגיות',
        'tab:about': 'על המוצר',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.classicClassic, 'classic_classic_trainer.html')]: 'קלאסיק 1 · המבנה הקלאסי',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.classic2, 'classic2_trainer.html')]: 'קלאסיק 2 · מבנה הקסם',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.iceberg, 'iceberg_templates_trainer.html')]: 'קצה קרחון / שלדי עומק',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.prismResearch, 'prism_research_trainer.html')]: 'מחקר פריזמות · חקירה בשרשרת',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.livingTriples, 'living_triples_trainer.html')]: 'שלשות חיות · תרגול מלא',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.verbUnzipStandalone, 'verb_unzip_trainer.html')]: 'כלי פירוק פועל · חלון נפרד',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.verbUnzipWorksheet, 'worksheets/verb-unzip/')]: 'דף עבודה מעוגל · פירוק פועל',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.sentenceMorpher, 'sentence_morpher_trainer.html')]: 'מעבדת שינוי ניסוח',
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.prismLabStandalone, 'prism_lab_trainer.html')]: 'מעבדת פריזמות · חלון נפרד'
    });
    const groupLabels = Object.freeze({
        home: 'בית',
        exercises: 'תרגול',
        lab: 'מעבדה',
        knowledge: 'ידע',
        settings: 'הגדרות'
    });
    const groupOrder = Object.freeze([
        groupLabels.home,
        groupLabels.exercises,
        groupLabels.lab,
        groupLabels.knowledge,
        groupLabels.settings
    ]);
    const classifyEntryGroup = (key) => {
        if (!key) return groupLabels.exercises;
        if (key === 'tab:home') return groupLabels.home;
        if (key === 'tab:about') return groupLabels.settings;
        if ([
            'tab:practice-question',
            'tab:practice-radar',
            'tab:practice-triples-radar',
            'tab:practice-wizard',
            'tab:practice-verb-unzip',
            'tab:scenario-trainer',
            'tab:comic-engine',
            'tab:blueprint'
        ].includes(key)) return groupLabels.exercises;
        if (key === 'tab:prismlab') return groupLabels.lab;
        if ([
            'tab:categories',
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.classicClassic, 'classic_classic_trainer.html'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.classic2, 'classic2_trainer.html'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.iceberg, 'iceberg_templates_trainer.html'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.livingTriples, 'living_triples_trainer.html'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.verbUnzipStandalone, 'verb_unzip_trainer.html'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.verbUnzipWorksheet, 'worksheets/verb-unzip/'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.sentenceMorpher, 'sentence_morpher_trainer.html')
        ].includes(key)) return groupLabels.knowledge;
        if ([
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.prismResearch, 'prism_research_trainer.html'),
            getNavHrefFeatureKey(STANDALONE_NAV_KEYS.prismLabStandalone, 'prism_lab_trainer.html')
        ].includes(key)) return groupLabels.lab;
        return groupLabels.exercises;
    };
    const pushEntry = (entry) => {
        if (!entry || !entry.key || seenKeys.has(entry.key)) return;
        const isTabEntry = String(entry.key || '').startsWith('tab:');
        const resolvedLabel = normalizeUiText((isTabEntry ? entry.label : labelOverrides[entry.key]) || entry.label || '').trim();
        if (!resolvedLabel) return;
        seenKeys.add(entry.key);
        entries.push({
            ...entry,
            label: resolvedLabel,
            group: classifyEntryGroup(entry.key)
        });
    };

    Array.from(document.querySelectorAll('.tab-btn')).forEach((btn) => {
        const tabId = String(btn.getAttribute('data-tab') || '').trim();
        const rawLabel = normalizeUiText((btn.textContent || '').trim());
        const label = resolveTabFeatureTitle(tabId, rawLabel);
        if (!tabId || !label) return;
        pushEntry({
            key: `tab:${tabId}`,
            label,
            actionType: 'navigate',
            actionValue: tabId,
            element: btn
        });
    });

    Array.from(featureMap.querySelectorAll('.feature-map-grid a.btn')).forEach((anchor) => {
        const hrefKey = getNavHrefFeatureKeyFromElement(anchor);
        const label = normalizeUiText((anchor.textContent || '').replace(/\s+/g, ' ').trim());
        if (!hrefKey || !label) return;
        pushEntry({
            key: hrefKey,
            label,
            actionType: 'anchor',
            actionValue: String(anchor.getAttribute('data-versioned-href') || anchor.getAttribute('href') || '').trim(),
            element: anchor
        });
    });

    const resolveEntryScope = (entry) => {
        const key = String(entry?.key || '');
        return key.startsWith('tab:') ? 'in-app' : 'standalone';
    };
    const inAppEntries = entries.filter((entry) => resolveEntryScope(entry) === 'in-app');
    const standaloneEntries = entries.filter((entry) => resolveEntryScope(entry) === 'standalone');

    const renderSelect = (selectNode, sourceEntries, placeholderText) => {
        const groups = groupOrder.filter((groupName) => sourceEntries.some((entry) => entry.group === groupName));
        const html = [`<option value="">${escapeHtml(placeholderText)}</option>`];
        groups.forEach((groupName) => {
            const groupEntries = sourceEntries.filter((entry) => entry.group === groupName);
            if (!groupEntries.length) return;
            html.push(`<optgroup label="${escapeHtml(groupName)}">`);
            groupEntries.forEach((entry) => {
                html.push(`<option value="${escapeHtml(entry.key)}">${escapeHtml(entry.label)}</option>`);
            });
            html.push('</optgroup>');
        });
        selectNode.innerHTML = html.join('');
    };

    renderSelect(inAppSelect, inAppEntries, 'בחר/י מסך…');
    renderSelect(standaloneSelect, standaloneEntries, 'בחר/י כלי…');

    const entryMap = entries.reduce((acc, entry) => {
        acc[entry.key] = entry;
        return acc;
    }, {});

    const syncToActiveTab = () => {
        const activeTab = document.querySelector('.tab-btn.active')?.getAttribute('data-tab') || 'home';
        const key = `tab:${activeTab}`;
        inAppSelect.value = entryMap[key] ? key : '';
    };
    syncToActiveTab();

    const executeSelectedKey = (selectedKey = '') => {
        const selected = entryMap[selectedKey];
        if (!selected) return;
        try {
            if (selected.actionType === 'navigate') {
                navigateTo(selected.actionValue);
            } else if (selected.element && typeof selected.element.click === 'function') {
                selected.element.click();
            }
        } finally {
            setFeatureMapToggleOpen(false);
        }
    };

    const bindImmediateSelect = (selectNode) => {
        selectNode.addEventListener('change', () => {
            const selectedKey = String(selectNode.value || '');
            if (!selectedKey) return;
            executeSelectedKey(selectedKey);
            if (selectNode === standaloneSelect) {
                selectNode.value = '';
            } else {
                standaloneSelect.value = '';
                syncToActiveTab();
            }
        });

        selectNode.addEventListener('keydown', (event) => {
            if (event.key !== 'Enter') return;
            const selectedKey = String(selectNode.value || '');
            if (!selectedKey) return;
            event.preventDefault();
            executeSelectedKey(selectedKey);
            if (selectNode === standaloneSelect) {
                selectNode.value = '';
            } else {
                standaloneSelect.value = '';
                syncToActiveTab();
            }
        });
    };

    bindImmediateSelect(inAppSelect);
    bindImmediateSelect(standaloneSelect);

    document.addEventListener('click', (event) => {
        const btn = event.target?.closest?.('.tab-btn');
        if (btn) syncToActiveTab();
    });

    featureMap.addEventListener('toggle', () => {
        if (!featureMap.open) return;
        syncToActiveTab();
    });
}

function buildScreenReadGuide(screenId) {
    const rawCopy = SCREEN_READ_GUIDES[screenId] || DEFAULT_SCREEN_READ_GUIDE;
    const copy = getCleanScreenGuideCopy(screenId, rawCopy);
    const wrapper = document.createElement('div');
    wrapper.className = 'screen-read-guide';
    wrapper.dataset.screenGuide = screenId;

    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'btn btn-primary screen-read-guide-btn';
    button.innerHTML = `
        <span class="screen-read-guide-btn-main">לפני שמתחילים</span>
        <span class="screen-read-guide-btn-sub">מה מחפשים כאן ואיך ניגשים לסבב ראשון</span>
    `;

    const modal = document.createElement('div');
    const modalId = `screen-read-guide-modal-${screenId}`;
    modal.className = 'screen-read-guide-modal hidden';
    modal.id = modalId;
    modal.setAttribute('role', 'dialog');
    modal.setAttribute('aria-modal', 'true');
    button.setAttribute('aria-controls', modalId);
    button.setAttribute('aria-haspopup', 'dialog');
    button.setAttribute('aria-expanded', 'false');

    const title = getScreenReadGuideTitle(screenId);
    const expected = copy.expected || `לאחר התרגול במסך הזה תדע/י: ${copy.goal}`;
    const success = copy.success || DEFAULT_SCREEN_READ_GUIDE.success;
    const demo = getTherapeuticDemoContent(screenId, title, copy);
    const philosopherIconSrc = resolveVersionedAssetPath('assets/svg/props/philosopher-guide.svg');
    const philosopherTeaser = screenId === 'categories'
        ? 'כאן נפתחת מפת ברין המלאה: לא רק שמות תבניות, אלא איך כל תבנית חושפת מידע שהיה חסר.'
        : 'לחיצה פותחת את מנגנון העומק: מאיפה נולד הדפוס, מה המחיר שלו, ומה השאלה שמחזירה תנועה.';

    const philosopherToggle = document.createElement('details');
    philosopherToggle.className = 'screen-read-guide-philosopher-toggle';
    philosopherToggle.innerHTML = `
        <summary class="screen-read-guide-philosopher-summary" aria-label="פילוסוף מסך - פתיחת ההיגיון מאחורי התרגול">
            <div class="screen-read-guide-illustration-media">
                <img class="screen-read-guide-philosopher" src="${escapeHtml(philosopherIconSrc || 'assets/svg/props/philosopher-guide.svg')}" alt="פילוסוף מסביר" loading="lazy">
            </div>
            <div class="screen-read-guide-illustration-copy">
                <strong>פילוסוף מסך · מה נפתח כאן באמת</strong>
                <span>${escapeHtml(philosopherTeaser)}</span>
            </div>
        </summary>
        <div class="screen-read-guide-philosopher-panel">
            <p>${escapeHtml(demo.banner)}</p>
            <div class="screen-read-guide-philosopher-meta">
                <p><strong>מה ההיגיון של התהליך כאן?</strong> ${escapeHtml(copy.logic)}</p>
                <p><strong>מה בדיוק מתרגלים במסך הזה?</strong> ${escapeHtml(copy.goal)}</p>
            </div>
        </div>
    `;

    const toolbar = document.createElement('div');
    toolbar.className = 'screen-read-guide-toolbar';

    const demoBtn = document.createElement('button');
    demoBtn.type = 'button';
    demoBtn.className = 'btn btn-secondary screen-read-guide-demo-btn';
    demoBtn.innerHTML = `
        <span class="screen-read-guide-btn-main">כך זה נראה בשיחה</span>
        <span class="screen-read-guide-btn-sub">דוגמה קצרה שממחישה איך הכלי עובד בתוך הקשר אמיתי</span>
    `;

    const demoModal = document.createElement('div');
    const demoModalId = `screen-demo-dialogue-modal-${screenId}`;
    demoModal.className = 'screen-read-guide-modal hidden';
    demoModal.id = demoModalId;
    demoModal.setAttribute('role', 'dialog');
    demoModal.setAttribute('aria-modal', 'true');
    demoBtn.setAttribute('aria-controls', demoModalId);
    demoBtn.setAttribute('aria-haspopup', 'dialog');
    demoBtn.setAttribute('aria-expanded', 'false');

    modal.innerHTML = `
        <div class="screen-read-guide-dialog">
            <button type="button" class="screen-read-guide-close" aria-label="סגירה">×</button>
            <h3>לפני שמתחילים ב${escapeHtml(title)}</h3>
            <p class="screen-read-guide-lead">הכוונה כאן היא שהסבב הראשון לא ירגיש אקראי: להבין מה מחפשים, איך ניגשים, ומה שווה לקחת אחר כך לשיחה אמיתית.</p>
            <div class="screen-read-guide-content">
                <h4>מה ההיגיון של התרגול?</h4>
                <p>${escapeHtml(copy.logic)}</p>
                <h4>מה בדיוק המטרה במסך הזה?</h4>
                <p>${escapeHtml(copy.goal)}</p>
                <h4>איך לגשת לתרגול שלב-שלב?</h4>
                <p>${escapeHtml(copy.approach)}</p>
                <h4>סדר עבודה מומלץ כדי להפיק תוצאה אמיתית</h4>
                <ol class="screen-read-guide-steps">
                    <li>לעבור פעם ראשונה על המשפט/המשימה כדי להבין הקשר כללי.</li>
                    <li>לעבור שוב ולזהות מילה/הנחה שיוצרות עמימות, לחץ או הכללה.</li>
                    <li>לבחור שאלה/תגובה שמפרקת את העמימות לצעד ברור.</li>
                    <li>להסתכל על המשוב, לתקן אם צריך, ואז להמשיך לסבב הבא.</li>
                </ol>
                <h4>מה צפוי שתדע/י לעשות אחרי התרגול?</h4>
                <p>${escapeHtml(expected)}</p>
                <h4>איך תזהה/י שהתקדמת?</h4>
                <p>${escapeHtml(success)}</p>
                <p class="screen-read-guide-summary">התוצאה הרצויה בסוף התרגול: לא רק "לענות נכון", אלא לדעת להסביר את ההיגיון מאחורי הבחירה וליישם אותו בשיחה אמיתית.</p>
            </div>
            <div class="screen-read-guide-actions">
                <button type="button" class="btn btn-primary screen-read-guide-confirm">הבנתי, אפשר להתחיל</button>
            </div>
        </div>
    `;

    const demoTurnsHtml = (Array.isArray(demo.turns) ? demo.turns : []).map((turn) => `
        <div class="screen-demo-dialogue-turn">
            <span class="screen-demo-dialogue-role">${escapeHtml(turn.role || 'דובר')}</span>
            <p class="screen-demo-dialogue-text">${escapeHtml(turn.text || '')}</p>
        </div>
    `).join('');
    const demoOutcomesHtml = (Array.isArray(demo.outcomes) ? demo.outcomes : [])
        .slice(0, 4)
        .map((item) => `<li>${escapeHtml(item)}</li>`)
        .join('');

    demoModal.innerHTML = `
        <div class="screen-read-guide-dialog screen-read-guide-dialog-demo">
            <button type="button" class="screen-read-guide-close" aria-label="סגירה">×</button>
            <h3>כך זה נראה בשיחה: ${escapeHtml(title)}</h3>
            <p class="screen-read-guide-lead">${escapeHtml(demo.frame)}</p>
            <div class="screen-demo-dialogue-box">${demoTurnsHtml}</div>
            <div class="screen-demo-dialogue-summary">
                <h4>${escapeHtml(demo.outcomeTitle || 'מה מקבלים מהכלי הזה')}</h4>
                <ul class="screen-demo-dialogue-list">${demoOutcomesHtml}</ul>
                <p class="screen-demo-dialogue-footnote">זו דוגמת שימוש לימודית. המטרה היא להבין איזה סוג כלי זה נותן לך, ואיך לשלב אותו עם שאר הכלים כדי לקבל שיח מדויק ויעיל יותר.</p>
            </div>
            <div class="screen-read-guide-actions">
                <button type="button" class="btn btn-primary screen-read-guide-confirm">סגור דוגמה</button>
            </div>
        </div>
    `;

    const closeBtn = modal.querySelector('.screen-read-guide-close');
    const confirmBtn = modal.querySelector('.screen-read-guide-confirm');
    const openModal = () => {
        modal.classList.remove('hidden');
        button.setAttribute('aria-expanded', 'true');
        document.body.classList.add('screen-guide-open');
        playUISound('hint');
    };
    const closeModal = () => {
        modal.classList.add('hidden');
        button.setAttribute('aria-expanded', 'false');
        if (!document.querySelector('.screen-read-guide-modal:not(.hidden)')) {
            document.body.classList.remove('screen-guide-open');
        }
    };

    button.addEventListener('click', openModal);
    closeBtn?.addEventListener('click', closeModal);
    confirmBtn?.addEventListener('click', closeModal);
    modal.addEventListener('click', (event) => {
        if (event.target === modal) closeModal();
    });
    document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape' && !modal.classList.contains('hidden')) {
            closeModal();
        }
    });

    const demoCloseButtons = demoModal.querySelectorAll('.screen-read-guide-close, .screen-read-guide-confirm');
    const openDemoModal = () => {
        demoModal.classList.remove('hidden');
        demoBtn.setAttribute('aria-expanded', 'true');
        document.body.classList.add('screen-guide-open');
        playUISound('hint');
    };
    const closeDemoModal = () => {
        demoModal.classList.add('hidden');
        demoBtn.setAttribute('aria-expanded', 'false');
        if (!document.querySelector('.screen-read-guide-modal:not(.hidden)')) {
            document.body.classList.remove('screen-guide-open');
        }
    };

    demoBtn.addEventListener('click', openDemoModal);
    demoCloseButtons.forEach((btn) => btn.addEventListener('click', closeDemoModal));
    demoModal.addEventListener('click', (event) => {
        if (event.target === demoModal) closeDemoModal();
    });
    document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape' && !demoModal.classList.contains('hidden')) {
            closeDemoModal();
        }
    });

    toolbar.appendChild(button);
    toolbar.appendChild(demoBtn);
    wrapper.appendChild(philosopherToggle);
    wrapper.appendChild(toolbar);
    wrapper.appendChild(modal);
    wrapper.appendChild(demoModal);
    return wrapper;
}

function getScreenReadGuideTitle(screenId) {
    const screen = document.getElementById(screenId);
    if (!screen) return 'מסך תרגול';
    const heading = screen.querySelector('h2, h3');
    const title = normalizeUiText(heading?.textContent?.trim() || '');
    if (looksLikeMojibakeText(title)) return 'מסך תרגול';
    const cleaned = title
        .replace(/^(קרא\/י לפני שמתחילים|דיאלוג טיפולי לדוגמה|כך זה נראה בשיחה)\s*:\s*/u, '')
        .replace(/^שם הלשונית של\s*/u, '')
        .trim();
    if (cleaned) return cleaned;
    const fallback = normalizeUiText(APP_STICKY_TAB_TITLE_OVERRIDES[screenId] || getTabTitle(screenId) || '');
    return fallback || 'מסך תרגול';
}

function setupReadBeforeStartGuides() {
    SCREEN_READ_GUIDE_TARGET_IDS.forEach((screenId) => {
        const screen = document.getElementById(screenId);
        if (!screen) return;
        if (screen.getAttribute('data-skip-generic-screen-guide') === 'true') return;
        if (screen.querySelector(`.screen-read-guide[data-screen-guide="${screenId}"]`)) return;
        screen.prepend(buildScreenReadGuide(screenId));
    });
}

function getVersionFromAppScriptQuery() {
    const appScript = document.querySelector('script[src*="js/app.js"]');
    const src = appScript?.getAttribute('src') || '';
    const match = src.match(/[?&]v=([^&]+)/i);
    return match ? decodeURIComponent(match[1]).trim() : '';
}

function getVersionFromHtmlAttribute() {
    try {
        const version = (document.documentElement?.getAttribute('data-app-version') || '').trim();
        return version || '';
    } catch (error) {
        return '';
    }
}

function getBuildMetaFromHtmlAttributes() {
    try {
        const rootEl = document.documentElement;
        if (!rootEl) return {};
        const buildTime = (rootEl.getAttribute('data-build-time') || '').trim();
        const buildIso = (rootEl.getAttribute('data-build-iso') || '').trim();
        const gitCommit = (rootEl.getAttribute('data-git-commit') || '').trim();
        return { buildTime, buildIso, gitCommit };
    } catch (error) {
        return {};
    }
}

function normalizeVersionManifest(payload) {
    if (!payload || typeof payload !== 'object') return null;
    const appVersion = String(payload.appVersion || payload.version || '').trim();
    const commitSha = String(payload.commitSha || payload.gitCommit || '').trim();
    const builtAt = String(payload.builtAt || payload.buildIso || '').trim();
    const buildTime = String(payload.buildTime || '').trim();
    if (!appVersion && !commitSha && !builtAt && !buildTime) return null;
    return { appVersion, commitSha, builtAt, buildTime };
}

function applyRuntimeBuildMetaFromManifest(meta) {
    if (!meta || !document.documentElement) return;
    if (meta.appVersion) document.documentElement.setAttribute('data-app-version', meta.appVersion);
    if (meta.commitSha) document.documentElement.setAttribute('data-git-commit', meta.commitSha);
    if (meta.builtAt) document.documentElement.setAttribute('data-build-iso', meta.builtAt);
    if (meta.buildTime) document.documentElement.setAttribute('data-build-time', meta.buildTime);
}

async function fetchVersionManifest() {
    try {
        const response = await fetch(`version.json?t=${encodeURIComponent(Date.now())}`, {
            cache: 'no-store',
            headers: { 'Cache-Control': 'no-cache' }
        });
        if (!response.ok) return null;
        const json = await response.json();
        const meta = normalizeVersionManifest(json);
        if (!meta) return null;
        applyRuntimeBuildMetaFromManifest(meta);
        return meta;
    } catch (_error) {
        return null;
    }
}

function getShortBuildCommit() {
    const gitCommit = String(getBuildMetaFromHtmlAttributes().gitCommit || '').trim();
    if (!gitCommit || gitCommit === 'unknown') return '';
    return gitCommit.slice(0, 7);
}

function formatAppVersionDisplay(version) {
    const resolvedVersion = String(version || '').trim() || 'unknown';
    return resolvedVersion;
}

function formatVersionWithCommit(version) {
    const visibleVersion = formatAppVersionDisplay(version);
    const shortCommit = getShortBuildCommit();
    if (!shortCommit) return visibleVersion;
    return `${visibleVersion} (${shortCommit})`;
}

function buildAppVersionTitle(version) {
    const resolvedVersion = String(version || '').trim() || 'unknown';
    const meta = getBuildMetaFromHtmlAttributes();
    const parts = [`v${resolvedVersion}`];
    if (meta.gitCommit) parts.push(`commit ${meta.gitCommit}`);
    if (meta.buildIso) parts.push(`build ${meta.buildIso}`);
    else if (meta.buildTime) parts.push(`buildTime ${meta.buildTime}`);
    return parts.join(' | ');
}

async function resolveAppVersion() {
    // 1. Source of truth: fetch the live version manifest with no-store.
    const manifestMeta = await fetchVersionManifest();
    if (manifestMeta?.appVersion) return manifestMeta.appVersion;

    // 2. Fallback: HTML data-app-version attribute.
    const htmlVersion = getVersionFromHtmlAttribute();
    if (htmlVersion) return htmlVersion;

    // 3. Fallback: script query parameter.
    const scriptVersion = getVersionFromAppScriptQuery();
    if (scriptVersion) return scriptVersion;

    // 4. Fallback: package.json (may fail on static hosting without CORS).
    try {
        const response = await fetch('package.json', { cache: 'no-store' });
        if (response.ok) {
            const pkg = await response.json();
            const version = typeof pkg?.version === 'string' ? pkg.version.trim() : '';
            if (version) return version;
        }
    } catch (error) {
        console.warn('Could not read package.json version:', error);
    }

    return 'unknown';
}

const APP_VERSION_CHIP_LABEL = '\u05d2\u05e8\u05e1\u05d4 \u05e0\u05d5\u05db\u05d7\u05d9\u05ea';
const APP_VERSION_FLOATING_LABEL = '\u05d2\u05e8\u05e1\u05d4 \u05e4\u05e2\u05d9\u05dc\u05d4';

function applyAppVersion(version) {
    const resolvedVersion = String(version || '').trim() || 'unknown';
    const visibleVersion = formatVersionWithCommit(resolvedVersion);
    const versionTitle = buildAppVersionTitle(resolvedVersion);
    const chip = document.getElementById('app-version-chip');
    if (chip) {
        chip.textContent = `${APP_VERSION_CHIP_LABEL}: ${visibleVersion}`;
        chip.dataset.version = resolvedVersion;
        chip.dataset.buildCommit = getShortBuildCommit();
        chip.setAttribute('title', versionTitle);
    }

    const floating = document.getElementById('app-version-floating');
    if (floating) {
        floating.textContent = `${APP_VERSION_FLOATING_LABEL}: ${visibleVersion}`;
        floating.dataset.version = resolvedVersion;
        floating.dataset.buildCommit = getShortBuildCommit();
        floating.setAttribute('title', versionTitle);
    }

    const stickyVersion = document.getElementById('app-sticky-version-chip');
    if (stickyVersion) {
        stickyVersion.textContent = `גרסה: ${visibleVersion}`;
        stickyVersion.dataset.version = resolvedVersion;
        stickyVersion.dataset.buildCommit = getShortBuildCommit();
        stickyVersion.setAttribute('title', versionTitle);
    }

    if (typeof document.title === 'string' && document.title) {
        const baseTitle = document.title.replace(/\s+\[v[^\]]+\]$/i, '');
        document.title = `${baseTitle} [v${visibleVersion}]`;
    }

    if (!window.__APP_VERSION_LOGGED__) {
        window.__APP_VERSION_LOGGED__ = true;
        try {
            const meta = getBuildMetaFromHtmlAttributes();
            console.info('[Meta Model] Active build', {
                version: resolvedVersion,
                visibleVersion,
                gitCommit: meta.gitCommit || '',
                buildIso: meta.buildIso || '',
                buildTime: meta.buildTime || ''
            });
        } catch (error) {
            // ignore
        }
    }

    syncAppStickyBannerOffset();
}

async function setupAppVersionChip() {
    const hasChip = Boolean(document.getElementById('app-version-chip'));
    const hasFloating = Boolean(document.getElementById('app-version-floating'));
    if (!hasChip && !hasFloating) return;

    const immediateVersion = getVersionFromHtmlAttribute() || getVersionFromAppScriptQuery();
    if (immediateVersion) applyAppVersion(immediateVersion);

    const version = await resolveAppVersion();
    applyAppVersion(version);
}

function setupFeatureLauncherTabs() {
    const launchers = document.querySelectorAll('[data-feature-launcher]');
    if (!launchers.length) return;

    const featureLabelOverrides = Object.freeze({
        "nav:practice-question": "תרגול זיהוי מטה-מודל",
        "nav:practice-radar": "מכ״ם מטה-מודל",
        "nav:practice-wizard": "גשר תחושה-שפה · הלימה לפני שינוי",
        "nav:practice-verb-unzip": "מרכז כלים",
        "nav:blueprint": "בונה מהלך",
        "nav:prismlab": "מעבדת פריזמות · רמות לוגיות",
        "nav:practice-triples-radar": "מכ״ם שלשות (ברין)",
        "nav:categories": "מילון קטגוריות המטה-מודל",
        "nav:comic-engine": "במת קומיקס רגשי",
        "nav:scenario-trainer": "סימולטור סצנות · משגר",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.verbUnzipStandalone, 'verb_unzip_trainer.html')]: "כלי פירוק פועל · חלון נפרד",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.verbUnzipWorksheet, 'worksheets/verb-unzip/')]: "דף עבודה מעוגל · פירוק פועל",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.sentenceMorpher, 'sentence_morpher_trainer.html')]: "מעבדת שינוי ניסוח",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.prismResearch, 'prism_research_trainer.html')]: "מחקר פריזמות · חקירה בשרשרת",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.iceberg, 'iceberg_templates_trainer.html')]: "קצה קרחון / שלדי עומק",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.livingTriples, 'living_triples_trainer.html')]: "שלשות חיות · תרגול מלא",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.classicClassic, 'classic_classic_trainer.html')]: "קלאסיק 1 · המבנה הקלאסי",
        [getNavHrefFeatureKey(STANDALONE_NAV_KEYS.classic2, 'classic2_trainer.html')]: "קלאסיק 2 · מבנה הקסם"
    });

    function parseLauncherEntry(element) {
        if (!element) return null;
        const panel = element.closest('[data-feature-group-panel]');
        const group = panel ? String(panel.getAttribute('data-feature-group-panel') || '') : '';
        let key = '';
        let actionType = '';
        let actionValue = '';
        if (element.tagName === 'A') {
            actionType = 'href';
            actionValue = String(element.getAttribute('data-versioned-href') || element.getAttribute('href') || '').trim();
            key = getNavHrefFeatureKeyFromElement(element) || toHrefFeatureKeyFromPath(actionValue);
        } else {
            const onclick = String(element.getAttribute('onclick') || '');
            const navMatch = onclick.match(/navigateTo\('([^']+)'\)/);
            if (navMatch) {
                actionType = 'navigate';
                actionValue = navMatch[1];
                key = `nav:${actionValue}`;
            }
        }
        if (!actionType) return null;
        const fallbackLabel = String(element.textContent || '').replace(/\s+/g, ' ').trim();
        return {
            key,
            group,
            label: featureLabelOverrides[key] || (looksLikeMojibakeText(fallbackLabel) ? (featureLabelOverrides[key] || actionValue || 'פיצ\'ר') : fallbackLabel),
            actionType,
            actionValue,
            target: element.getAttribute('target') || '',
            element
        };
    }

    function executeLauncherEntry(entry) {
        if (!entry) return;
        if (entry.actionType === 'navigate') {
            try {
                navigateTo(entry.actionValue);
                return;
            } catch (_error) {
                // fall back to click
            }
        }
        if (entry.element && typeof entry.element.click === 'function') {
            entry.element.click();
        }
    }

    launchers.forEach((launcher) => {
        if (launcher.dataset.featureLauncherBound === '1') return;
        launcher.dataset.featureLauncherBound = '1';
        launcher.classList.add('feature-launcher--compact');

        const headStrong = launcher.querySelector('.feature-launcher-head strong');
        const headP = launcher.querySelector('.feature-launcher-head p');
        if (headStrong) headStrong.textContent = 'בחירת כלי מהירה';
        if (headP) headP.textContent = 'בחר/י כלי אחד מהתפריט היורד. הכפתורים הארוכים הוסתרו כדי לשמור על מסך נקי.';

        const buttons = Array.from(launcher.querySelectorAll('[data-feature-group-btn]'));
        const panels = Array.from(launcher.querySelectorAll('[data-feature-group-panel]'));
        if (!buttons.length || !panels.length) return;

        function activate(groupName) {
            const target = String(groupName || '').trim();
            buttons.forEach((button) => {
                const active = button.getAttribute('data-feature-group-btn') === target;
                button.classList.toggle('is-active', active);
                button.setAttribute('aria-selected', active ? 'true' : 'false');
            });
            panels.forEach((panel) => {
                const active = panel.getAttribute('data-feature-group-panel') === target;
                panel.classList.toggle('is-active', active);
                if (active) panel.removeAttribute('hidden');
                else panel.setAttribute('hidden', '');
            });
        }

        buttons.forEach((button) => {
            button.addEventListener('click', () => {
                activate(button.getAttribute('data-feature-group-btn'));
            });
        });

        const initialButton = buttons.find((button) => button.classList.contains('is-active')) || buttons[0];
        activate(initialButton.getAttribute('data-feature-group-btn'));

        const existingPicker = launcher.querySelector('[data-feature-launcher-picker]');
        const pickerWrap = existingPicker || document.createElement('div');
        if (!existingPicker) {
            pickerWrap.setAttribute('data-feature-launcher-picker', '1');
            pickerWrap.className = 'feature-launcher-picker';
            launcher.insertBefore(pickerWrap, launcher.querySelector('.feature-launcher-tabs') || launcher.firstChild);
        }

        const allEntryElements = Array.from(launcher.querySelectorAll('.feature-launcher-grid .btn'));
        const entries = allEntryElements
            .map((el) => parseLauncherEntry(el))
            .filter(Boolean);

        const groupLabelMap = {
            'without-breen': 'ללא טבלאות ברין',
            'with-breen': 'עם טבלאות ברין'
        };

        const groupedHtml = Object.keys(groupLabelMap).map((groupKey) => {
            const groupEntries = entries.filter((entry) => entry.group === groupKey);
            if (!groupEntries.length) return '';
            const options = groupEntries.map((entry) => (
                `<option value="${escapeHtml(entry.key)}">${escapeHtml(entry.label)}</option>`
            )).join('');
            return `<optgroup label="${escapeHtml(groupLabelMap[groupKey])}">${options}</optgroup>`;
        }).join('');

        const selectId = `feature-launcher-select-${Math.random().toString(36).slice(2, 7)}`;
        pickerWrap.innerHTML = `
            <div class="feature-launcher-picker-head">
                <label for="${selectId}">בחר/י כלי</label>
                <small>תפריט יורד במקום שורת כפתורים עליונה</small>
            </div>
            <div class="feature-launcher-picker-controls">
                <select id="${selectId}" class="feature-launcher-select" data-feature-picker-select>
                    <option value="">בחר/י כלי...</option>
                    ${groupedHtml}
                </select>
                <button type="button" class="btn btn-primary" data-feature-picker-open>פתח</button>
            </div>
        `;

        const select = pickerWrap.querySelector('[data-feature-picker-select]');
        const openBtn = pickerWrap.querySelector('[data-feature-picker-open]');
        const entryByKey = entries.reduce((acc, entry) => {
            acc[entry.key] = entry;
            return acc;
        }, {});

        if (select && !select.dataset.boundFeaturePicker) {
            select.dataset.boundFeaturePicker = '1';
            select.addEventListener('change', () => {
                const selected = entryByKey[select.value];
                if (selected && selected.group) activate(selected.group);
            });
        }

        if (openBtn && !openBtn.dataset.boundFeaturePicker) {
            openBtn.dataset.boundFeaturePicker = '1';
            openBtn.addEventListener('click', () => {
                const selected = select ? entryByKey[select.value] : null;
                if (!selected) return;
                executeLauncherEntry(selected);
            });
        }
    });
}

function resolveVersionedAssetPath(rawPath = '') {
    const source = String(rawPath || '').trim();
    if (!source) return '';
    try {
        const versioner = (typeof window.__withAssetVersion === 'function')
            ? window.__withAssetVersion
            : (typeof window.withAssetVersion === 'function' ? window.withAssetVersion : null);
        if (typeof versioner === 'function') {
            return String(versioner(source) || source);
        }
    } catch (_error) {
        // fall back to raw path
    }
    return source;
}

function clearUnzipEmbedLoadTimer() {
    if (unzipEmbedRuntime.timerId) {
        clearTimeout(unzipEmbedRuntime.timerId);
        unzipEmbedRuntime.timerId = null;
    }
}

function setUnzipEmbedStatus(message = '', tone = 'info') {
    const statusBox = document.getElementById('unzip-embed-status');
    const statusText = document.getElementById('unzip-embed-status-text');
    if (!statusBox || !statusText) return;
    statusBox.setAttribute('data-tone', tone);
    statusText.textContent = String(message || '').trim();
}

function syncUnzipEmbedButtons() {
    const loadBtn = document.getElementById('unzip-embed-load-btn');
    const reloadBtn = document.getElementById('unzip-embed-reload-btn');
    if (loadBtn) {
        loadBtn.disabled = !!unzipEmbedRuntime.loading;
        loadBtn.hidden = !!unzipEmbedRuntime.loaded && !unzipEmbedRuntime.failed;
    }
    if (reloadBtn) {
        reloadBtn.disabled = !!unzipEmbedRuntime.loading;
        reloadBtn.hidden = !unzipEmbedRuntime.loaded && !unzipEmbedRuntime.failed;
    }
}

function loadUnzipEmbedFrame({ forceReload = false } = {}) {
    const frame = document.getElementById('unzip-embed-frame');
    if (!frame) return;

    const source = String(frame.getAttribute('data-versioned-src') || '').trim();
    if (!source) {
        unzipEmbedRuntime.failed = true;
        setUnzipEmbedStatus('לא נמצא מקור תקין לכלי המוטמע.', 'danger');
        syncUnzipEmbedButtons();
        return;
    }

    if (unzipEmbedRuntime.loading) return;
    if (unzipEmbedRuntime.loaded && !forceReload) return;

    const resolvedSrc = resolveVersionedAssetPath(source);
    unzipEmbedRuntime.loading = true;
    unzipEmbedRuntime.failed = false;
    syncUnzipEmbedButtons();
    setUnzipEmbedStatus('טוען את הכלי המוטמע...', 'info');

    const handleLoaded = () => {
        clearUnzipEmbedLoadTimer();
        unzipEmbedRuntime.loading = false;
        unzipEmbedRuntime.loaded = true;
        unzipEmbedRuntime.failed = false;
        syncUnzipEmbedButtons();
        setUnzipEmbedStatus('הכלי המוטמע נטען בהצלחה.', 'success');
    };

    const handleFailed = () => {
        clearUnzipEmbedLoadTimer();
        unzipEmbedRuntime.loading = false;
        unzipEmbedRuntime.loaded = true;
        unzipEmbedRuntime.failed = true;
        syncUnzipEmbedButtons();
        setUnzipEmbedStatus('טעינת הכלי המוטמע נכשלה או התעכבה. אפשר לנסות טעינה מחדש.', 'danger');
    };

    frame.addEventListener('load', handleLoaded, { once: true });
    frame.addEventListener('error', handleFailed, { once: true });

    if (forceReload) {
        frame.setAttribute('src', 'about:blank');
    }

    requestAnimationFrame(() => {
        frame.setAttribute('src', resolvedSrc);
    });

    clearUnzipEmbedLoadTimer();
    unzipEmbedRuntime.timerId = setTimeout(handleFailed, UNZIP_EMBED_LOAD_TIMEOUT_MS);
}

function setupUnzipEmbedLazyLoad() {
    const frame = document.getElementById('unzip-embed-frame');
    if (!frame || frame.dataset.unzipLazyBound === '1') return;
    frame.dataset.unzipLazyBound = '1';

    const loadBtn = document.getElementById('unzip-embed-load-btn');
    const reloadBtn = document.getElementById('unzip-embed-reload-btn');

    if (loadBtn && loadBtn.dataset.unzipLoadBound !== '1') {
        loadBtn.dataset.unzipLoadBound = '1';
        loadBtn.addEventListener('click', () => {
            loadUnzipEmbedFrame();
        });
    }

    if (reloadBtn && reloadBtn.dataset.unzipReloadBound !== '1') {
        reloadBtn.dataset.unzipReloadBound = '1';
        reloadBtn.addEventListener('click', () => {
            loadUnzipEmbedFrame({ forceReload: true });
        });
    }

    setUnzipEmbedStatus('כדי למנוע תקיעות, הכלי המוטמע נטען רק בעת כניסה למסך או בלחיצה ידנית.', 'info');
    syncUnzipEmbedButtons();
}

function escapeRegExpForPattern(value = '') {
    return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function normalizeTrapPhrase(value = '') {
    return String(value || '')
        .toLowerCase()
        .replace(/[^\u0590-\u05FFa-z0-9\s]/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
}

function getCodexUnresolvedCount() {
    return codexTrapLabState.activeTraps.filter((trap) => {
        return !codexTrapLabState.resolvedByWord[trap.normalizedWord];
    }).length;
}

function setCodexFeedback(text = '', tone = 'info') {
    const feedback = codexTrapLabState.elements?.feedback;
    if (!feedback) return;
    feedback.textContent = String(text || '').trim();
    feedback.setAttribute('data-tone', tone);
}

function setCodexBiteMessage(text = '', tone = 'warn') {
    const bite = codexTrapLabState.elements?.bite;
    if (!bite) return;
    const message = String(text || '').trim();
    if (!message) {
        bite.textContent = '';
        bite.classList.add('hidden');
        bite.removeAttribute('data-tone');
        return;
    }
    bite.classList.remove('hidden');
    bite.textContent = message;
    bite.setAttribute('data-tone', tone);
}

function syncCodexSaveState() {
    const saveBtn = codexTrapLabState.elements?.saveBtn;
    const counter = codexTrapLabState.elements?.counter;
    if (!saveBtn || !counter) return;

    const unresolved = getCodexUnresolvedCount();
    counter.textContent = `${unresolved} קופסאות סגורות`;
    counter.setAttribute('data-tone', unresolved > 0 ? 'warn' : 'success');
    saveBtn.disabled = unresolved > 0;
}

function pruneCodexResolvedWords() {
    const activeSet = new Set(codexTrapLabState.activeTraps.map((trap) => trap.normalizedWord));
    Object.keys(codexTrapLabState.resolvedByWord).forEach((key) => {
        if (!activeSet.has(key)) {
            delete codexTrapLabState.resolvedByWord[key];
        }
    });
}

function detectCodexTraps(text = '') {
    const normalizedText = ` ${normalizeTrapPhrase(text)} `;
    if (!normalizedText.trim()) return [];

    const active = [];
    codexTrapLabState.trapWords.forEach((trap) => {
        if (!trap?.normalizedWord) return;
        const pattern = new RegExp(`(?:^|\\s)${escapeRegExpForPattern(trap.normalizedWord)}(?=\\s|$)`, 'g');
        const matches = normalizedText.match(pattern);
        if (!matches || !matches.length) return;
        active.push({
            ...trap,
            count: matches.length
        });
    });
    return active;
}

function renderCodexTrapList() {
    const list = codexTrapLabState.elements?.list;
    if (!list) return;
    list.innerHTML = '';

    if (!codexTrapLabState.activeTraps.length) {
        const empty = document.createElement('p');
        empty.className = 'codex-trap-empty';
        empty.textContent = 'אין כרגע מילים עמומות פתוחות. אפשר לשמור.';
        list.appendChild(empty);
        return;
    }

    codexTrapLabState.activeTraps.forEach((trap) => {
        const isResolved = !!codexTrapLabState.resolvedByWord[trap.normalizedWord];
        const token = document.createElement('button');
        token.type = 'button';
        token.className = `codex-trap-token ${isResolved ? 'is-resolved' : 'is-open'}`;
        token.dataset.trapWord = trap.normalizedWord;

        const word = document.createElement('span');
        word.className = 'codex-trap-token-word';
        word.textContent = `"${trap.word}"`;

        const meta = document.createElement('span');
        meta.className = 'codex-trap-token-meta';
        meta.textContent = isResolved
            ? `נפתח ✓ → ${codexTrapLabState.resolvedByWord[trap.normalizedWord]}`
            : `x${trap.count} · ${trap.hint}`;

        token.appendChild(word);
        token.appendChild(meta);
        token.addEventListener('click', () => {
            openCodexTrapModal(trap.normalizedWord);
        });

        list.appendChild(token);
    });
}

function refreshCodexTrapAnalysis() {
    const input = codexTrapLabState.elements?.input;
    if (!input) return;
    codexTrapLabState.activeTraps = detectCodexTraps(input.value || '');
    pruneCodexResolvedWords();
    renderCodexTrapList();
    syncCodexSaveState();
    if (!codexTrapLabState.activeTraps.length) {
        setCodexBiteMessage('');
    }
}

function closeCodexTrapModal() {
    const modal = codexTrapLabState.elements?.modal;
    if (!modal) return;
    modal.classList.add('hidden');
    modal.setAttribute('aria-hidden', 'true');
    codexTrapLabState.selectedTrapWord = '';
}

function openCodexTrapModal(normalizedWord = '') {
    const trap = codexTrapLabState.trapByWord.get(normalizedWord);
    const els = codexTrapLabState.elements;
    if (!trap || !els) return;

    codexTrapLabState.selectedTrapWord = trap.normalizedWord;

    if (els.modalTitle) {
        els.modalTitle.textContent = `מי זה "${trap.word}" בעצם?`;
    }
    if (els.modalHint) {
        els.modalHint.textContent = trap.hint || 'כתבו ניסוח מדויק יותר.';
    }
    if (els.modalInput) {
        els.modalInput.value = codexTrapLabState.resolvedByWord[trap.normalizedWord] || '';
    }

    if (els.suggestions) {
        els.suggestions.innerHTML = '';
        const suggestions = Array.isArray(trap.suggestions) && trap.suggestions.length
            ? trap.suggestions
            : ['ההורים שלי', 'הבוס שלי', 'בן/בת הזוג'];
        suggestions.forEach((suggestion) => {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'codex-trap-suggestion-chip';
            btn.textContent = suggestion;
            btn.addEventListener('click', () => {
                if (!els.modalInput) return;
                els.modalInput.value = suggestion;
                els.modalInput.focus();
            });
            els.suggestions.appendChild(btn);
        });
    }

    els.modal.classList.remove('hidden');
    els.modal.setAttribute('aria-hidden', 'false');
    if (els.modalInput) {
        els.modalInput.focus();
        els.modalInput.select();
    }
}

function saveCodexTrapResolution() {
    const selected = codexTrapLabState.selectedTrapWord;
    const input = codexTrapLabState.elements?.modalInput;
    if (!selected || !input) return;

    const value = String(input.value || '').trim();
    if (!value) {
        setCodexFeedback('כדי לפתוח קופסה צריך ניסוח מדויק יותר.', 'warn');
        input.focus();
        return;
    }

    codexTrapLabState.resolvedByWord[selected] = value;
    closeCodexTrapModal();
    setCodexFeedback('הקופסה נפתחה בהצלחה.', 'success');
    setCodexBiteMessage('');
    refreshCodexTrapAnalysis();
}

async function loadCodexTrapWords() {
    if (codexTrapLabState.trapWords.length) return codexTrapLabState.trapWords;

    let sourceWords = CODEX_TRAP_FALLBACK_WORDS;
    try {
        const response = await fetch(resolveVersionedAssetPath('data/trap-words.json'), { cache: 'no-store' });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const payload = await response.json();
        if (Array.isArray(payload?.trapWords) && payload.trapWords.length) {
            sourceWords = payload.trapWords;
        }
    } catch (error) {
        console.warn('Codex trap words: fallback list in use', error);
    }

    const normalizedWords = sourceWords.map((entry) => {
        const word = String(entry?.word || '').trim();
        const normalizedWord = normalizeTrapPhrase(word);
        if (!word || !normalizedWord) return null;
        return {
            word,
            normalizedWord,
            category: String(entry?.category || '').trim() || 'general',
            severity: String(entry?.severity || '').trim() || 'medium',
            hint: String(entry?.hint || '').trim() || 'מי בדיוק?',
            suggestions: Array.isArray(entry?.suggestions)
                ? entry.suggestions.map((item) => String(item || '').trim()).filter(Boolean)
                : []
        };
    }).filter(Boolean);

    codexTrapLabState.trapWords = normalizedWords;
    codexTrapLabState.trapByWord = new Map(normalizedWords.map((entry) => [entry.normalizedWord, entry]));
    return normalizedWords;
}

async function setupCodexTrapWordLab() {
    const root = document.getElementById('codex-trap-lab');
    if (!root || root.dataset.codexBound === '1') return;
    root.dataset.codexBound = '1';

    codexTrapLabState.elements = {
        input: document.getElementById('codex-trap-input'),
        list: document.getElementById('codex-trap-list'),
        counter: document.getElementById('codex-trap-counter'),
        challengeBtn: document.getElementById('codex-trap-challenge-btn'),
        clearBtn: document.getElementById('codex-trap-clear-btn'),
        saveBtn: document.getElementById('codex-trap-save-btn'),
        feedback: document.getElementById('codex-trap-feedback'),
        bite: document.getElementById('codex-trap-bite'),
        modal: document.getElementById('codex-trap-modal'),
        modalTitle: document.getElementById('codex-trap-modal-title'),
        modalHint: document.getElementById('codex-trap-modal-hint'),
        modalInput: document.getElementById('codex-trap-modal-input'),
        modalClose: document.getElementById('codex-trap-modal-close'),
        modalSave: document.getElementById('codex-trap-modal-save'),
        suggestions: document.getElementById('codex-trap-suggestions')
    };

    await loadCodexTrapWords();
    refreshCodexTrapAnalysis();
    setCodexFeedback('הכלי פעיל. אפשר להתחיל להקליד.', 'info');

    const els = codexTrapLabState.elements;

    if (els.input && els.input.dataset.codexBound !== '1') {
        els.input.dataset.codexBound = '1';
        els.input.addEventListener('input', () => {
            setCodexFeedback('', 'info');
            refreshCodexTrapAnalysis();
        });
    }

    if (els.clearBtn && els.clearBtn.dataset.codexBound !== '1') {
        els.clearBtn.dataset.codexBound = '1';
        els.clearBtn.addEventListener('click', () => {
            if (els.input) els.input.value = '';
            codexTrapLabState.activeTraps = [];
            codexTrapLabState.resolvedByWord = {};
            renderCodexTrapList();
            syncCodexSaveState();
            setCodexBiteMessage('');
            setCodexFeedback('הטקסט נוקה.', 'info');
        });
    }

    if (els.challengeBtn && els.challengeBtn.dataset.codexBound !== '1') {
        els.challengeBtn.dataset.codexBound = '1';
        els.challengeBtn.addEventListener('click', () => {
            const firstOpen = codexTrapLabState.activeTraps.find((trap) => !codexTrapLabState.resolvedByWord[trap.normalizedWord]);
            if (!firstOpen) {
                setCodexFeedback('אין קופסאות פתוחות כרגע. אפשר לשמור.', 'success');
                return;
            }
            openCodexTrapModal(firstOpen.normalizedWord);
        });
    }

    if (els.saveBtn && els.saveBtn.dataset.codexBound !== '1') {
        els.saveBtn.dataset.codexBound = '1';
        els.saveBtn.addEventListener('click', () => {
            const unresolved = getCodexUnresolvedCount();
            if (unresolved > 0) {
                setCodexBiteMessage(`🦷 גראווררר! נשארו ${unresolved} קופסאות פתוחות.`, 'warn');
                setCodexFeedback('צריך לפתוח את כל הקופסאות לפני שמירה.', 'warn');
                const firstOpen = codexTrapLabState.activeTraps.find((trap) => !codexTrapLabState.resolvedByWord[trap.normalizedWord]);
                if (firstOpen) openCodexTrapModal(firstOpen.normalizedWord);
                return;
            }
            setCodexBiteMessage('');
            setCodexFeedback('הערה נשמרה בהצלחה.', 'success');
        });
    }

    if (els.modalClose && els.modalClose.dataset.codexBound !== '1') {
        els.modalClose.dataset.codexBound = '1';
        els.modalClose.addEventListener('click', closeCodexTrapModal);
    }

    if (els.modalSave && els.modalSave.dataset.codexBound !== '1') {
        els.modalSave.dataset.codexBound = '1';
        els.modalSave.addEventListener('click', saveCodexTrapResolution);
    }

    if (els.modalInput && els.modalInput.dataset.codexBound !== '1') {
        els.modalInput.dataset.codexBound = '1';
        els.modalInput.addEventListener('keydown', (event) => {
            if (event.key === 'Enter') {
                event.preventDefault();
                saveCodexTrapResolution();
            }
        });
    }

    if (els.modal && els.modal.dataset.codexBound !== '1') {
        els.modal.dataset.codexBound = '1';
        els.modal.addEventListener('click', (event) => {
            if (event.target === els.modal) closeCodexTrapModal();
        });
    }

    if (window.__codexTrapEscBound !== true) {
        window.__codexTrapEscBound = true;
        document.addEventListener('keydown', (event) => {
            if (event.key !== 'Escape') return;
            const modal = codexTrapLabState.elements?.modal;
            if (!modal || modal.classList.contains('hidden')) return;
            closeCodexTrapModal();
        });
    }
}

