function updateRuntimeDebugInfoCard() {
    const statusRoot = document.getElementById('feature-runtime-status');
    if (!statusRoot) return;

    const viewEl = document.getElementById('runtime-view-mode');
    const viewportEl = document.getElementById('runtime-viewport-size');
    const tabEl = document.getElementById('runtime-saved-tab');
    const densityEl = document.getElementById('runtime-header-density');

    let isEmbedded = false;
    try {
        isEmbedded = window.self !== window.top;
    } catch (error) {
        isEmbedded = true;
    }

    const width = Math.max(0, Math.round(window.innerWidth || 0));
    const height = Math.max(0, Math.round(window.innerHeight || 0));
    const savedTab = normalizeRequestedTab(localStorage.getItem(PRACTICE_ACTIVE_TAB_STORAGE_KEY) || '') || 'home';
    const density = (localStorage.getItem('header_density_v1') || 'compact').toLowerCase();

    if (viewEl) viewEl.textContent = isEmbedded ? 'מוטמע (בתוך מסגרת)' : 'ישיר (עמוד מלא)';
    if (viewportEl) viewportEl.textContent = `${width}×${height}`;
    if (tabEl) tabEl.textContent = savedTab;
    if (densityEl) densityEl.textContent = density === 'cozy' ? 'cozy' : 'compact';
}

function resetLocalUiState() {
    const keysToClear = [
        PRACTICE_ACTIVE_TAB_STORAGE_KEY,
        'header_density_v1',
        'meta_audio_muted',
        OPENING_TRACK_FIRST_ENTRY_KEY,
        AUDIO_FLOATING_CONTROLS_POSITION_KEY
    ];
    let cleared = 0;
    keysToClear.forEach((key) => {
        try {
            if (localStorage.getItem(key) !== null) {
                localStorage.removeItem(key);
                cleared += 1;
            }
        } catch (error) {
            // ignore storage access issues
        }
    });
    try {
        alert(`אופס מצב UI מקומי (${cleared} מפתחות). הדף יטען מחדש.`);
    } catch (error) {
        // ignore alert failures
    }
    window.location.reload();
}

// Scripts are injected dynamically from index.html, so DOMContentLoaded may have
// already fired by the time this file executes (especially on cached loads).
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initializeMetaModelApp, { once: true });
} else {
    // Defer init until after the rest of this file finishes evaluating.
    if (typeof queueMicrotask === 'function') {
        queueMicrotask(initializeMetaModelApp);
    } else {
        setTimeout(initializeMetaModelApp, 0);
    }
}

// Load Meta Model data from JSON
async function loadMetaModelData() {
    try {
        const [response, glossaryResponse, patternsResponse, glossaryConfigResponse, glossaryBlueprintResponse] = await Promise.all([
            fetch(resolveVersionedAssetPath('data/meta-model-violations.json'), { cache: 'no-store' }),
            fetch(resolveVersionedAssetPath('data/meta_model_glossary_breakthroughs.he.json'), { cache: 'no-store' }).catch(() => null),
            fetch(resolveVersionedAssetPath('data/metaModelPatterns.he.json'), { cache: 'no-store' }).catch(() => null),
            fetch(resolveVersionedAssetPath('data/meta_model_glossary_config.he.json'), { cache: 'no-store' }).catch(() => null),
            fetch(resolveVersionedAssetPath('data/meta_model_glossary_blueprint.he.json'), { cache: 'no-store' }).catch(() => null)
        ]);
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        metaModelData = deepNormalizeUiPayload(await response.json());
        if (glossaryResponse && glossaryResponse.ok) {
            metaModelGlossaryData = deepNormalizeUiPayload(await glossaryResponse.json());
        } else {
            metaModelGlossaryData = { items: [] };
        }
        if (patternsResponse && patternsResponse.ok) {
            metaModelPatternLibraryData = deepNormalizeUiPayload(await patternsResponse.json());
        } else {
            metaModelPatternLibraryData = { patterns: [] };
        }
        if (glossaryConfigResponse && glossaryConfigResponse.ok) {
            try {
                metaModelGlossaryConfigData = normalizeGlossaryConfig(deepNormalizeUiPayload(await glossaryConfigResponse.json()));
            } catch (error) {
                console.warn('[glossary] invalid config payload, using defaults', error);
                metaModelGlossaryConfigData = normalizeGlossaryConfig({});
            }
        } else {
            metaModelGlossaryConfigData = normalizeGlossaryConfig({});
        }
        if (glossaryBlueprintResponse && glossaryBlueprintResponse.ok) {
            const payload = deepNormalizeUiPayload(await glossaryBlueprintResponse.json());
            metaModelGlossaryBlueprintData = {
                item_template: payload?.item_template && typeof payload.item_template === 'object' ? payload.item_template : {},
                items: Array.isArray(payload?.items) ? payload.items : []
            };
        } else {
            metaModelGlossaryBlueprintData = { items: [] };
        }
        
        // Populate categories
        populateCategories();
        
        // Populate category select in practice
        populateCategorySelect();
        
        // Initialize Prism Lab (after data loads)
        if (document.getElementById('prism-library')) {
            renderPrismLibrary();
        }
        
        hideLoadingIndicator();
    } catch (error) {
        console.error('Error loading data:', error);
        hideLoadingIndicator();
        showErrorMessage('שגיאה בטעינת הנתונים');
    }
}

function activateTabByName(tabName = '', { playSound = false, scrollToTop = true } = {}) {
    const resolvedTab = normalizeRequestedTab(tabName);
    if (!resolvedTab) return false;

    const tabBtns = Array.from(document.querySelectorAll('.tab-btn'));
    const tabContents = Array.from(document.querySelectorAll('.tab-content'));
    const content = document.getElementById(resolvedTab);
    if (!content) return false;

    tabBtns.forEach((btn) => btn.classList.remove('active'));
    tabContents.forEach((tab) => tab.classList.remove('active'));

    const btn = tabBtns.find((node) => node.getAttribute('data-tab') === resolvedTab);
    if (btn) btn.classList.add('active');
    content.classList.add('active');
    if (document.body) {
        document.body.dataset.activeTab = resolvedTab;
    }
    ensurePracticeTabHydration(resolvedTab);
    if (resolvedTab === 'practice-verb-unzip') {
        loadUnzipEmbedFrame();
    }
    if (resolvedTab === 'comic-engine') {
        ensureComicEngineFlowReady();
    }
    if (resolvedTab === 'categories') {
        collapseAllGlossaryCategories(document.getElementById('categories-container'));
    }

    if (resolvedTab !== 'practice-radar') {
        setRapidPatternFocusMode(false);
        hideRapidPatternExplanation({ resumeIfNeeded: false });
    }

    persistPracticeTabPreference(resolvedTab);

    const mobileTabSelect = document.getElementById('mobile-tab-select');
    if (mobileTabSelect && mobileTabSelect.value !== resolvedTab) {
        mobileTabSelect.value = resolvedTab;
    }

    const scenarioContext = resolvedTab === 'scenario-trainer' ? scenarioTrainer.activeScenario : null;
    closeComicPreviewModal();
    renderGlobalComicStrip(resolvedTab, scenarioContext);
    if (window.MetaAppShell && typeof window.MetaAppShell.notifyTabActivated === 'function') {
        window.MetaAppShell.notifyTabActivated(resolvedTab);
    }

    syncHomeMobileFeedMode(resolvedTab);
    updateMobileStickyCta(resolvedTab);
    syncGlobalTheoryLauncherVisibility(resolvedTab);
    updateAppStickyBanner(resolvedTab);

    if (scrollToTop) {
        scrollPageToTop();
    }

    if (playSound) playUISound('next');
    return true;
}

function normalizeStepBackTab(tabName = '') {
    const tab = normalizeRequestedTab(tabName);
    if (!tab || tab === 'debug') return '';
    return tab;
}

function loadFeatureStepBackHistory() {
    let parsed = [];
    try {
        parsed = JSON.parse(sessionStorage.getItem(FEATURE_STEP_BACK_STACK_KEY) || '[]');
    } catch (_error) {
        parsed = [];
    }
    featureStepBackRuntime.stack = (Array.isArray(parsed) ? parsed : [])
        .map((item) => normalizeStepBackTab(item))
        .filter(Boolean)
        .slice(-FEATURE_STEP_BACK_STACK_LIMIT);
}

function saveFeatureStepBackHistory() {
    try {
        sessionStorage.setItem(FEATURE_STEP_BACK_STACK_KEY, JSON.stringify(featureStepBackRuntime.stack.slice(-FEATURE_STEP_BACK_STACK_LIMIT)));
    } catch (_error) {
        // Ignore session storage errors.
    }
}

function pushFeatureStepBackEntry(fromTab = '', toTab = '') {
    const from = normalizeStepBackTab(fromTab);
    const to = normalizeStepBackTab(toTab);
    if (!from || !to || from === to) return;
    if (!featureStepBackRuntime.stack.length) {
        loadFeatureStepBackHistory();
    }
    const stack = featureStepBackRuntime.stack;
    if (stack[stack.length - 1] === from) return;
    stack.push(from);
    if (stack.length > FEATURE_STEP_BACK_STACK_LIMIT) {
        stack.splice(0, stack.length - FEATURE_STEP_BACK_STACK_LIMIT);
    }
    saveFeatureStepBackHistory();
}

function popFeatureStepBackEntry(currentTab = '') {
    const current = normalizeStepBackTab(currentTab);
    if (!featureStepBackRuntime.stack.length) {
        loadFeatureStepBackHistory();
    }
    let next = '';
    while (featureStepBackRuntime.stack.length) {
        const candidate = normalizeStepBackTab(featureStepBackRuntime.stack.pop());
        if (!candidate || candidate === current) continue;
        if (!document.getElementById(candidate)) continue;
        next = candidate;
        break;
    }
    saveFeatureStepBackHistory();
    return next;
}

function hasFeatureStepBackTarget(currentTab = '') {
    const current = normalizeStepBackTab(currentTab || getCurrentActiveTabName());
    if (!featureStepBackRuntime.stack.length) {
        loadFeatureStepBackHistory();
    }
    return featureStepBackRuntime.stack.some((candidate) => {
        const tab = normalizeStepBackTab(candidate);
        return Boolean(tab && tab !== current && document.getElementById(tab));
    });
}

function navigateFeatureStepBack() {
    const current = normalizeRequestedTab(getCurrentActiveTabName());
    const previous = popFeatureStepBackEntry(current);
    if (!previous) return false;
    navigateTo(previous, {
        playSound: true,
        scrollToTop: true,
        trackStepBack: false
    });
    return true;
}

function refreshFeatureBackControls(activeTab = '') {
    const currentTab = normalizeRequestedTab(activeTab) || getCurrentActiveTabName();
    const hasStepBack = hasFeatureStepBackTarget(currentTab);
    document.querySelectorAll('[data-feature-step-back-btn]').forEach((button) => {
        const targetSection = button.closest('.tab-content');
        const targetTab = normalizeRequestedTab(String(targetSection?.id || ''));
        const disabled = !hasStepBack || !targetTab || targetTab === 'home' || targetTab === 'debug';
        button.disabled = disabled;
        button.setAttribute('aria-disabled', disabled ? 'true' : 'false');
        button.title = disabled ? 'אין עדיין צעד קודם לחזרה' : 'חזרה צעד למסך הקודם';
    });
}

function setupFeatureHomeBackButtons() {
    loadFeatureStepBackHistory();
    const sections = Array.from(document.querySelectorAll('.tab-content[id]'));
    if (!sections.length) return;

    sections.forEach((section) => {
        const tabId = String(section.id || '').trim();
        if (!tabId || tabId === 'home' || tabId === 'debug') return;
        if (section.querySelector('[data-feature-back-home-btn], [data-feature-step-back-btn]')) return;

        const bar = document.createElement('div');
        bar.className = 'feature-home-back-bar';

        const stepBackBtn = document.createElement('button');
        stepBackBtn.type = 'button';
        stepBackBtn.className = 'btn btn-secondary feature-step-back-btn';
        stepBackBtn.textContent = '↩ חזרה צעד';
        stepBackBtn.dataset.featureStepBackBtn = 'true';
        stepBackBtn.addEventListener('click', () => {
            if (navigateFeatureStepBack()) return;
            navigateTo('home', { playSound: true, scrollToTop: true, trackStepBack: false });
        });

        const homeBtn = document.createElement('button');
        homeBtn.type = 'button';
        homeBtn.className = 'btn btn-primary feature-home-back-btn';
        homeBtn.textContent = 'חזרה למסך הראשי';
        homeBtn.dataset.featureBackHomeBtn = 'true';
        homeBtn.addEventListener('click', () => navigateTo('home', { playSound: true, scrollToTop: true }));

        bar.append(stepBackBtn, homeBtn);
        section.prepend(bar);
    });

    refreshFeatureBackControls(getCurrentActiveTabName());
}

function bindElementToNavKey(element, navKey = '') {
    const node = element instanceof Element ? element : null;
    const resolvedNavKey = String(navKey || '').trim();
    if (!node || !resolvedNavKey) return false;
    if (node.dataset.navKeyBound === '1') return true;

    const entry = typeof window.getMetaModelNavEntry === 'function'
        ? window.getMetaModelNavEntry(resolvedNavKey)
        : null;
    if (!entry) return false;

    const canonicalPath = getGlobalNavPathByKey(resolvedNavKey, String(entry.path || '').trim());
    const versionedHref = typeof window.getMetaModelNavHref === 'function'
        ? window.getMetaModelNavHref(resolvedNavKey, { versioned: true })
        : (typeof window.__withAssetVersion === 'function' ? window.__withAssetVersion(canonicalPath) : canonicalPath);
    node.dataset.navKey = resolvedNavKey;

    if (node.tagName === 'A') {
        if (canonicalPath && !node.hasAttribute('data-versioned-href')) {
            node.setAttribute('data-versioned-href', canonicalPath);
        }
        if (versionedHref) {
            node.setAttribute('href', versionedHref);
        }
        if (entry.type === 'tab') {
            node.addEventListener('click', (event) => {
                event.preventDefault();
                if (typeof window.navigateByNavKey === 'function' && window.navigateByNavKey(resolvedNavKey, { versioned: true }) !== false) {
                    return;
                }
                if (entry.tab) navigateTo(entry.tab, { playSound: true, scrollToTop: true });
            });
        }
    } else {
        node.addEventListener('click', (event) => {
            event.preventDefault();
            if (typeof window.navigateByNavKey === 'function' && window.navigateByNavKey(resolvedNavKey, { versioned: true }) !== false) {
                return;
            }
            if (entry.type === 'tab' && entry.tab) {
                navigateTo(entry.tab, { playSound: true, scrollToTop: true });
                return;
            }
            if (versionedHref) {
                window.location.href = versionedHref;
            }
        });
    }

    node.dataset.navKeyBound = '1';
    return true;
}

function setupCanonicalNavLaunchers() {
    const directLaunchers = Array.from(document.querySelectorAll('[data-nav-key]'));
    directLaunchers.forEach((node) => {
        bindElementToNavKey(node, node.getAttribute('data-nav-key'));
    });

    const navFromInline = Array.from(document.querySelectorAll(
        '.home-route [onclick*="navigateTo("], #feature-map-toggle [onclick*="navigateTo("], [data-feature-launcher] [onclick*="navigateTo("]'
    ));
    navFromInline.forEach((node) => {
        const onclick = String(node.getAttribute('onclick') || '').trim();
        const match = onclick.match(/navigateTo\('([^']+)'\)/);
        if (!match) return;
        const tab = normalizeRequestedTab(match[1]);
        const navKey = getNavKeyByTab(tab);
        if (!navKey) return;
        node.removeAttribute('onclick');
        bindElementToNavKey(node, navKey);
    });

    const linkedAnchors = Array.from(document.querySelectorAll(
        '.home-route a[data-versioned-href], #feature-map-toggle a[data-versioned-href], [data-feature-launcher] a[data-versioned-href]'
    ));
    linkedAnchors.forEach((anchor) => {
        if (anchor.dataset.navKeyBound === '1') return;
        const href = String(anchor.getAttribute('data-versioned-href') || anchor.getAttribute('href') || '').trim();
        if (!href) return;
        const navKey = typeof window.getMetaModelNavKeyByPath === 'function'
            ? String(window.getMetaModelNavKeyByPath(href) || '').trim()
            : '';
        if (!navKey) return;
        bindElementToNavKey(anchor, navKey);
    });
}

function normalizeUserLevelMode(mode = '') {
    const key = String(mode || '').trim().toLowerCase();
    if (key === USER_LEVELS.advanced) return USER_LEVELS.advanced;
    return USER_LEVELS.beginner;
}

function loadUserLevelMode() {
    try {
        return normalizeUserLevelMode(localStorage.getItem(USER_LEVEL_STORAGE_KEY) || USER_LEVEL_DEFAULT);
    } catch (_error) {
        return USER_LEVEL_DEFAULT;
    }
}

function syncUserLevelToggleButtons() {
    const mode = normalizeUserLevelMode(userLevelMode);
    document.querySelectorAll('[data-user-level-set]').forEach((button) => {
        const buttonMode = normalizeUserLevelMode(button.getAttribute('data-user-level-set'));
        const active = buttonMode === mode;
        button.classList.toggle('is-active', active);
        button.setAttribute('aria-pressed', active ? 'true' : 'false');
    });
}

function applyUserLevelMode(mode = USER_LEVEL_DEFAULT, { persist = true } = {}) {
    userLevelMode = normalizeUserLevelMode(mode);
    if (document.body) {
        document.body.dataset.userLevel = userLevelMode;
    }
    if (persist) {
        try {
            localStorage.setItem(USER_LEVEL_STORAGE_KEY, userLevelMode);
        } catch (_error) {
            // Ignore storage errors.
        }
    }
    syncUserLevelToggleButtons();
}

function buildFeatureTermTooltipHtml(termKeys = []) {
    const terms = (Array.isArray(termKeys) ? termKeys : [])
        .map((key) => TERM_TOOLTIP_COPY[String(key || '').trim()])
        .filter(Boolean);
    if (!terms.length) return '';
    return `
        <div class="feature-onboarding-terms" aria-label="מונחים מהירים">
            ${terms.map((term) => `
                <button type="button" class="feature-term-pill" title="${escapeHtml(term.help)}" aria-label="${escapeHtml(`${term.label}: ${term.help}`)}">
                    ${escapeHtml(term.label)}
                </button>
            `).join('')}
        </div>
    `;
}

function setupFeatureOnboardingCards() {
    Object.entries(FEATURE_ONBOARDING_COPY).forEach(([tabId, copy]) => {
        const section = document.getElementById(tabId);
        if (!section || section.querySelector('[data-feature-onboarding="1"]')) return;
        const title = APP_STICKY_TAB_TITLE_OVERRIDES[tabId] || String(copy.kicker || tabId).trim();
        const steps = Array.isArray(copy.steps) ? copy.steps : [];

        const card = document.createElement('section');
        card.className = 'feature-onboarding-card';
        card.setAttribute('data-feature-onboarding', '1');
        card.innerHTML = `
            <div class="feature-onboarding-head">
                <p class="feature-onboarding-kicker">${escapeHtml(String(copy.icon || '🧭').trim())} ${escapeHtml(String(copy.kicker || title).trim())}</p>
                <h3 class="feature-onboarding-title">שם הלשונית של ${escapeHtml(title)}</h3>
            </div>
            <p class="feature-onboarding-what"><strong>מה עושים כאן?</strong> ${escapeHtml(String(copy.what || '').trim())}</p>
            <div class="feature-onboarding-details">
                <p><strong>שלבים עיקריים:</strong></p>
                <ol class="feature-onboarding-steps">
                    ${steps.map((step) => `<li>${escapeHtml(String(step || '').trim())}</li>`).join('')}
                </ol>
                <p class="feature-onboarding-success"><strong>מה נחשב הצלחה?</strong> ${escapeHtml(String(copy.success || '').trim())}</p>
            </div>
            ${buildFeatureTermTooltipHtml(copy.termKeys)}
            <div class="feature-onboarding-levels" role="group" aria-label="בחירת רמת תצוגה">
                <button type="button" class="feature-onboarding-level-btn" data-user-level-set="beginner">למתחילים</button>
                <button type="button" class="feature-onboarding-level-btn" data-user-level-set="advanced">למתקדמים</button>
            </div>
        `;

        const backBar = section.querySelector('.feature-home-back-bar');
        if (backBar) {
            backBar.insertAdjacentElement('afterend', card);
        } else {
            section.prepend(card);
        }
    });

    if (window.__featureOnboardingLevelBound !== true) {
        window.__featureOnboardingLevelBound = true;
        document.addEventListener('click', (event) => {
            const button = event.target?.closest?.('[data-user-level-set]');
            if (!button) return;
            applyUserLevelMode(button.getAttribute('data-user-level-set') || USER_LEVEL_DEFAULT, { persist: true });
        });
    }

    applyUserLevelMode(loadUserLevelMode(), { persist: false });
}

// Setup Tab Navigation
function setupTabNavigation() {
    const tabBtns = document.querySelectorAll('.tab-btn');
    const mobileTabSelect = document.getElementById('mobile-tab-select');
    
    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const tabName = btn.getAttribute('data-tab');
            navigateTo(tabName, { playSound: true, scrollToTop: true });
        });
    });

    if (mobileTabSelect) {
        mobileTabSelect.innerHTML = Array.from(tabBtns)
            .map(btn => `<option value="${btn.getAttribute('data-tab')}">${btn.textContent.trim()}</option>`)
            .join('');

        const activeBtn = document.querySelector('.tab-btn.active');
        if (activeBtn) mobileTabSelect.value = activeBtn.getAttribute('data-tab');

        mobileTabSelect.addEventListener('change', () => {
            const targetTab = mobileTabSelect.value;
            navigateTo(targetTab, { playSound: true, scrollToTop: true });
        });
    }
}

// Populate Categories Section
function getBreenPrismPhilosophyEntry(subcategoryId = '') {
    const lib = window.prismResearchPhilosophyLibrary || {};
    const id = String(subcategoryId || '').trim().toLowerCase();
    const aliasMap = {
        lack_referential_index: 'lack_ref_index',
        presupposition: 'presuppositions',
        universal_quantifier: 'universal_quantifiers'
    };

    if (id === 'modal_operator') {
        return {
            ask3x: 'מה יקרה אם לא...? מה מונע? מה צריך כדי שזה יתאפשר?',
            school: 'אילוצים / אפשרויות (Modal Operators)',
            why: 'אופרטורים מודליים יוצרים תחושת חוק: "חייב", "צריך", "אי אפשר". בפריזמה אנחנו בודקים גם את המחיר/האיום (necessity) וגם את תנאי האפשרות (possibility).',
            creates: 'מיפוי של פחד/אילוץ מול תנאים שמאפשרים תנועה. במקום "אין ברירה" נוצרת סקאלה של אפשרויות.',
            therapistCalm: 'לא מבטלים את הפחד או הדרישה; בודקים מה הם מנסים להגן עליו ואיפה יש חופש פעולה.',
            patientGain: 'פחות קיפאון. יותר בחירה מודעת בין חובה, רצוי, אפשרי, וצעד קטן.',
            trap: 'להתווכח עם "חייב" לפני שמבינים את העלות שהמוח מנסה למנוע.',
            fix: 'קודם למפות מחיר/איום, ואז לשאול על תנאי אפשרות וצעד ניסויי.',
            tooltip: 'מאחורי "חייב/אי אפשר" יושבים לרוב פחד, ערך או הרגל.'
        };
    }

    return lib[aliasMap[id] || id] || null;
}

function getBreenPatternGoalText(category, subcategory) {
    const subId = String(subcategory?.id || '').toLowerCase();
    const goalMap = {
        mind_reading: 'להפריד בין סימנים/תחושות לבין המסקנה, ולבדוק ראיות. כולל Mind Reading עצמי (למשל: "אני רעב" - איך אני יודע?) וקפיצה למסקנות.',
        universal_quantifier: 'לבדוק היקף, חריגים ותנאים: להפוך "תמיד/אף פעם" למפה שניתנת לבדיקה.',
        modal_operator: 'לפרק "חייב/צריך/אי אפשר" למחיר, פחד, אילוץ ותנאי אפשרות.',
        cause_effect: 'לפרק קשר סיבתי אוטומטי לשלבים/מנגנון כדי למצוא נקודת התערבות.',
        complex_equivalence: 'לחשוף את חוק התרגום ("X אומר Y") ולבדוק אם יש תרגומים חלופיים.'
    };
    if (goalMap[subId]) return goalMap[subId];

    const family = String(subcategory?.category || category?.name || '').toUpperCase();
    if (family.includes('DELETION')) return 'להחזיר מידע חסר למפה: מי/מה/מתי/לפי מה - כדי שאפשר יהיה לעבוד עם המציאות ולא עם ערפל.';
    if (family.includes('DISTORTION')) return 'להפריד בין נתון, פירוש ומסקנה - כדי לבדוק מה באמת ידוע ומה רק הונח.';
    if (family.includes('GENERALIZATION')) return 'להחזיר גבולות ותנאים להכללה - כדי לפתוח יותר אפשרויות תגובה.';
    return 'להפוך ניסוח מעורפל למבנה ברור שניתן לבדוק, לשקף ולעבוד איתו.';
}

function renderBreenPatternPhilosophyLayer(category, subcategory) {
    const ph = getBreenPrismPhilosophyEntry(subcategory?.id);
    if (!ph) {
        return `
            <p>תיאוריה פילוסופית מפורטת תתווסף כאן בהמשך. כרגע השתמשו בשאלות ובמטרה של התבנית כדי לעבוד בצורה מדויקת.</p>
        `;
    }

    const mindReadingExtra = String(subcategory?.id || '') === 'mind_reading'
        ? `<p><strong>הרחבה חשובה:</strong> קריאת מחשבות כוללת גם <em>מיינד-רידינג עצמי</em> ("אני רעב / אני פגוע - איך אני יודע?") וגם <em>קפיצה למסקנות</em> מתוך סימן קטן.</p>`
        : '';

    return `
        <p><strong>המסגרת הפילוסופית:</strong> ${escapeHtml(ph.school || 'פריזמה לשונית-לוגית')}</p>
        <p><strong>למה זה חשוב:</strong> ${escapeHtml(ph.why || '')}</p>
        <p><strong>מה זה מייצר בתרגול:</strong> ${escapeHtml(ph.creates || '')}</p>
        <p><strong>שקט של המטפל:</strong> ${escapeHtml(ph.therapistCalm || '')}</p>
        <p><strong>רווח למטופל:</strong> ${escapeHtml(ph.patientGain || '')}</p>
        ${mindReadingExtra}
    `;
}

