function getBreenReferenceRowMeta(rowId = '') {
    const meta = {
        row1: {
            colorClass: 'row-sky',
            heLabel: 'שלשה 1 | מקור, הנחה וכוונה',
            heInsight: 'בודקים מי מקור הסמכות, איזו הנחה עובדת מתחת לפני השטח, ואיזו כוונה מיוחסת בלי ראיה ישירה.'
        },
        row2: {
            colorClass: 'row-teal',
            heLabel: 'שלשה 2 | חוקי משחק וגבולות',
            heInsight: 'כאן חוקרים את חוקי המשחק: חייב/צריך/יכול, גבולות הנכונות, והנגזרת התפקודית של החוקים האלה על האדם.'
        },
        row3: {
            colorClass: 'row-amber',
            heLabel: 'שלשה 3 | משמעות, זהות והסקה',
            heInsight: 'מפרידים בין פעולה לזהות ובין סימן למסקנה, כדי לא להפוך תיאור רגעי להגדרה קבועה של האדם.'
        },
        row4: {
            colorClass: 'row-violet',
            heLabel: 'שלשה 4 | הקשר, זמן וייחוס',
            heInsight: 'מחדדים זמן, מקום והקשר: מול מי, ביחס למה, ומתי בדיוק המשפט נכון או לא נכון.'
        },
        row5: {
            colorClass: 'row-rose',
            heLabel: 'שלשה 5 | קרקע חושית ופעולה',
            heInsight: 'מורידים לקרקע מדידה: מי/מה בדיוק, מה רואים ושומעים בפועל, ומה הצעד ההתנהגותי הבא.'
        }
    };
    return meta[rowId] || meta.row1;
}

function normalizeBreenReferenceCategoryId(categoryId = '') {
    const raw = String(categoryId || '').trim().toLowerCase().replace(/\s+/g, '_');
    if (!raw) return '';
    const aliases = {
        assumption: 'assumptions',
        presupposition: 'assumptions',
        presuppositions: 'assumptions',
        modal_necessity: 'modal_operator',
        modal_possibility: 'modal_operator',
        nominalization: 'nominalisations',
        nominalisation: 'nominalisations',
        time_space: 'time_space_predicates',
        lack_of_referential_index: 'lack_referential_index',
        unspecified_verb: 'unspecified_verbs',
        unspecified_noun: 'non_referring_nouns',
        simple_deletion: 'simple_deletion'
    };
    return aliases[raw] || raw;
}

function getBreenReferenceCategoryLabelHe(categoryId = '') {
    const id = normalizeBreenReferenceCategoryId(categoryId);
    const labels = {
        lost_performative: 'חסרון הדובר',
        assumptions: 'הנחות מוקדמות',
        mind_reading: 'קריאת מחשבות',
        universal_quantifier: 'הכללה',
        modal_operator: 'מודל פעולה',
        cause_effect: 'סיבה ותוצאה',
        nominalisations: 'נומינליזציה',
        identity_predicates: 'פרדיקטים של זהות',
        complex_equivalence: 'הקבלה מורכבת',
        comparative_deletion: 'השמטה השוואתית',
        time_space_predicates: 'פרדיקטים של זמן ומקום',
        lack_referential_index: 'אובדן המצביע',
        non_referring_nouns: 'שם עצם לא מפורט',
        sensory_predicates: 'פרדיקטים חושיים',
        unspecified_verbs: 'פועל לא מפורט'
    };
    return labels[id] || id;
}

function getBreenReferenceCategoryChip(categoryId = '') {
    const id = normalizeBreenReferenceCategoryId(categoryId);
    const chips = {
        lost_performative: 'LOST PERFORMATIVE',
        assumptions: 'ASSUMPTIONS',
        mind_reading: 'MIND READING',
        universal_quantifier: 'UNIVERSAL QUANTIFIER',
        modal_operator: 'MODAL OPERATOR',
        cause_effect: 'CAUSE EFFECT',
        nominalisations: 'NOMINALISATIONS',
        identity_predicates: 'IDENTITY PREDICATES',
        complex_equivalence: 'COMPLEX EQUIVALENCE',
        comparative_deletion: 'COMPARATIVE DELETION',
        time_space_predicates: 'TIME SPACE PREDICATES',
        lack_referential_index: 'LACK REFERENTIAL INDEX',
        non_referring_nouns: 'NON REFERRING NOUNS',
        sensory_predicates: 'SENSORY PREDICATES',
        unspecified_verbs: 'UNSPECIFIED VERBS'
    };
    return chips[id] || id.replace(/_/g, ' ').toUpperCase();
}

function getBreenReferenceRowIdByCategory(categoryId = '') {
    const normalized = normalizeBreenReferenceCategoryId(categoryId);
    const rows = getBreenReferenceRows();
    const row = rows.find(item => (item.categories || []).some(cat => normalizeBreenReferenceCategoryId(cat) === normalized));
    return row?.id || '';
}

function buildBreenReferenceBoardHtml({
    title = 'טבלת ברין (מפת הדפוסים המלאה)',
    note = '',
    activeCategoryId = '',
    mode = 'static',
    availableCategoryIds = null
} = {}) {
    const normalizedActive = normalizeBreenReferenceCategoryId(activeCategoryId);
    const activeRowId = getBreenReferenceRowIdByCategory(normalizedActive);
    const rows = getBreenReferenceRows();
    const availableMap = availableCategoryIds instanceof Map ? availableCategoryIds : null;
    const availableSet = availableMap ? new Set(availableMap.keys()) : (availableCategoryIds instanceof Set ? availableCategoryIds : null);
    const categoryLinkAliases = {
        assumptions: ['presupposition'],
        nominalisations: ['nominalization', 'nominalisation'],
        non_referring_nouns: ['simple_deletion'],
        unspecified_verbs: ['simple_deletion']
    };

    const rowsHtml = rows.map((row) => {
        const rowMeta = getBreenReferenceRowMeta(row.id);
        const isActiveRow = !!activeRowId && activeRowId === row.id;
        const cellsHtml = (row.categories || []).map((rawCategoryId) => {
            const categoryId = normalizeBreenReferenceCategoryId(rawCategoryId);
            const isActive = !!normalizedActive && categoryId === normalizedActive;
            const commonClasses = ['tr-phone-breen-cell', 'breen-reference-cell'];
            if (isActiveRow) commonClasses.push('is-row-locked');
            if (isActive) commonClasses.push('is-correct');

            if (mode === 'category-links') {
                let targetCategoryId = categoryId;
                if (availableMap && availableMap.has(targetCategoryId)) {
                    targetCategoryId = availableMap.get(targetCategoryId) || targetCategoryId;
                } else if (availableSet && !availableSet.has(targetCategoryId)) {
                    const aliasMatch = (categoryLinkAliases[targetCategoryId] || [])
                        .map(alias => normalizeBreenReferenceCategoryId(alias))
                        .find(alias => availableSet.has(alias));
                    if (aliasMatch && availableMap && availableMap.has(aliasMatch)) {
                        targetCategoryId = availableMap.get(aliasMatch) || aliasMatch;
                    } else if (aliasMatch) {
                        targetCategoryId = aliasMatch;
                    }
                }
                const canLink = !availableSet || availableSet.has(normalizeBreenReferenceCategoryId(targetCategoryId)) || (availableMap ? Array.from(availableMap.values()).includes(targetCategoryId) : false);
                const tag = canLink ? 'a' : 'div';
                const hrefAttr = canLink ? ` href="#pattern-${escapeHtml(targetCategoryId)}" data-breen-pattern-link="${escapeHtml(targetCategoryId)}"` : '';
                return `
                    <${tag} class="${commonClasses.join(' ')}${canLink ? '' : ' is-missing'}"${hrefAttr}>
                        <span class="tr-phone-breen-chip">${escapeHtml(getBreenReferenceCategoryChip(categoryId))}</span>
                        <small>${escapeHtml(getBreenReferenceCategoryLabelHe(categoryId))}</small>
                    </${tag}>
                `;
            }

            return `
                <div class="${commonClasses.join(' ')}">
                    <span class="tr-phone-breen-chip">${escapeHtml(getBreenReferenceCategoryChip(categoryId))}</span>
                    <small>${escapeHtml(getBreenReferenceCategoryLabelHe(categoryId))}</small>
                </div>
            `;
        }).join('');

        return `
            <div class="tr-phone-breen-row ${escapeHtml(rowMeta.colorClass || '')} ${isActiveRow ? 'is-active' : ''}">
                <div class="tr-phone-breen-row-head">
                    <strong>${escapeHtml(rowMeta.heLabel || row.id)}</strong>
                    <small>${escapeHtml(rowMeta.heInsight || '')}</small>
                </div>
                <div class="tr-phone-breen-row-cells">${cellsHtml}</div>
            </div>
        `;
    }).join('');

    return `
        <section class="tr-phone-panel tr-phone-breen-panel breen-reference-panel">
            <div class="tr-phone-panel-title">${escapeHtml(title)}</div>
            ${note ? `<p class="breen-reference-panel-note">${escapeHtml(note)}</p>` : ''}
            <div class="tr-phone-breen-grid">${rowsHtml}</div>
        </section>
    `;
}

function buildCategorySubPatternCard(category, subcategory) {
    const questionText = String(subcategory?.question || '').trim();
    const exampleText = String(subcategory?.example || '').trim();
    const goalText = getBreenPatternGoalText(category, subcategory);
    const isMindReading = String(subcategory?.id || '') === 'mind_reading';
    const questionsExtra = isMindReading
        ? '<li><strong>הרחבה:</strong> זה כולל גם מיינד-רידינג עצמי ("אני רעב" / "אני לא מסוגל") וגם קפיצה למסקנות.</li>'
        : '';

    return `
        <details id="pattern-${escapeHtml(subcategory.id || '')}" class="subcategory-item subcategory-layered" data-pattern-id="${escapeHtml(subcategory.id || '')}">
            <summary class="subcategory-summary">
                <span class="subcategory-title">${escapeHtml(subcategory.hebrew || subcategory.name || subcategory.id || 'תבנית')}</span>
                <span class="subcategory-desc">${escapeHtml(subcategory.description || '')}</span>
            </summary>

            <div class="subcategory-layers">
                <details class="subcategory-layer">
                    <summary>שאלות עבודה</summary>
                    <div class="subcategory-layer-body">
                        <ul>
                            ${questionText ? `<li><strong>שאלת בסיס:</strong> ${escapeHtml(questionText)}</li>` : ''}
                            ${exampleText ? `<li><strong>דוגמה למשפט:</strong> ${escapeHtml(exampleText)}</li>` : ''}
                            ${questionsExtra}
                        </ul>
                    </div>
                </details>

                <details class="subcategory-layer">
                    <summary>המטרה של התבנית</summary>
                    <div class="subcategory-layer-body">
                        <p>${escapeHtml(goalText)}</p>
                    </div>
                </details>

                <details class="subcategory-layer">
                    <summary>פילוסופיה של הפריזמה (קשור לתבנית)</summary>
                    <div class="subcategory-layer-body subcategory-layer-philosophy">
                        ${renderBreenPatternPhilosophyLayer(category, subcategory)}
                    </div>
                </details>
            </div>
        </details>
    `;
}

function getGlossaryGroupClass(group = '') {
    const normalized = String(group || '').trim().toUpperCase();
    if (normalized === 'DELETION') return 'deletion';
    if (normalized === 'DISTORTION') return 'distortion';
    if (normalized === 'GENERALIZATION') return 'generalization';
    return 'neutral';
}

const DEFAULT_GLOSSARY_CONFIG = Object.freeze({
    column_order: Object.freeze(['GENERALIZATION', 'DISTORTION', 'DELETION']),
    column_hebrew: Object.freeze({
        GENERALIZATION: 'הכללה',
        DISTORTION: 'עיוות',
        DELETION: 'מחיקה'
    }),
    required_order: Object.freeze([]),
    standard_meta: Object.freeze({}),
    concept_id_aliases: Object.freeze({}),
    fallback_group_by_id: Object.freeze({}),
    fallback_markers_by_id: Object.freeze({}),
    fallback_questions_by_id: Object.freeze({})
});

function pickPlainObject(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    return value;
}

function normalizeGlossaryConfig(rawConfig = {}) {
    const source = pickPlainObject(rawConfig);
    const columnOrder = Array.isArray(source.column_order) && source.column_order.length
        ? source.column_order.map((item) => String(item || '').trim().toUpperCase()).filter(Boolean)
        : [...DEFAULT_GLOSSARY_CONFIG.column_order];

    const columnHebrewSource = pickPlainObject(source.column_hebrew);
    const columnHebrew = {
        ...DEFAULT_GLOSSARY_CONFIG.column_hebrew
    };
    Object.keys(columnHebrewSource).forEach((key) => {
        const normalizedKey = String(key || '').trim().toUpperCase();
        if (!normalizedKey) return;
        columnHebrew[normalizedKey] = String(columnHebrewSource[key] || '').trim();
    });

    const requiredOrder = Array.isArray(source.required_order)
        ? source.required_order.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean)
        : [...DEFAULT_GLOSSARY_CONFIG.required_order];

    const standardMetaSource = pickPlainObject(source.standard_meta);
    const standardMeta = {};
    Object.keys(standardMetaSource).forEach((rawKey) => {
        const normalizedKey = String(rawKey || '').trim().toLowerCase();
        if (!normalizedKey) return;
        const entry = pickPlainObject(standardMetaSource[rawKey]);
        const group = String(entry.group || '').trim().toUpperCase();
        standardMeta[normalizedKey] = {
            he: String(entry.he || '').trim(),
            en: String(entry.en || '').trim(),
            group
        };
    });

    const aliasSource = pickPlainObject(source.concept_id_aliases);
    const conceptIdAliases = {};
    Object.keys(aliasSource).forEach((rawKey) => {
        const key = String(rawKey || '').trim().toLowerCase();
        const target = String(aliasSource[rawKey] || '').trim().toLowerCase();
        if (!key || !target) return;
        conceptIdAliases[key] = target;
    });

    const fallbackGroupSource = pickPlainObject(source.fallback_group_by_id);
    const fallbackGroupById = {};
    Object.keys(fallbackGroupSource).forEach((rawKey) => {
        const key = String(rawKey || '').trim().toLowerCase();
        const group = String(fallbackGroupSource[rawKey] || '').trim().toUpperCase();
        if (!key || !group) return;
        fallbackGroupById[key] = group;
    });

    const fallbackMarkersSource = pickPlainObject(source.fallback_markers_by_id);
    const fallbackMarkersById = {};
    Object.keys(fallbackMarkersSource).forEach((rawKey) => {
        const key = String(rawKey || '').trim().toLowerCase();
        const values = Array.isArray(fallbackMarkersSource[rawKey]) ? fallbackMarkersSource[rawKey] : [];
        if (!key) return;
        fallbackMarkersById[key] = values.map((item) => String(item || '').trim()).filter(Boolean);
    });

    const fallbackQuestionsSource = pickPlainObject(source.fallback_questions_by_id);
    const fallbackQuestionsById = {};
    Object.keys(fallbackQuestionsSource).forEach((rawKey) => {
        const key = String(rawKey || '').trim().toLowerCase();
        const values = Array.isArray(fallbackQuestionsSource[rawKey]) ? fallbackQuestionsSource[rawKey] : [];
        if (!key) return;
        fallbackQuestionsById[key] = values.map((item) => String(item || '').trim()).filter(Boolean);
    });

    return {
        column_order: columnOrder.length ? columnOrder : [...DEFAULT_GLOSSARY_CONFIG.column_order],
        column_hebrew: columnHebrew,
        required_order: requiredOrder,
        standard_meta: standardMeta,
        concept_id_aliases: conceptIdAliases,
        fallback_group_by_id: fallbackGroupById,
        fallback_markers_by_id: fallbackMarkersById,
        fallback_questions_by_id: fallbackQuestionsById
    };
}

function getGlossaryConfigColumnOrder() {
    const list = metaModelGlossaryConfigData?.column_order;
    if (Array.isArray(list) && list.length) return list;
    return DEFAULT_GLOSSARY_CONFIG.column_order;
}

function getGlossaryConfigColumnHebrew() {
    return metaModelGlossaryConfigData?.column_hebrew || DEFAULT_GLOSSARY_CONFIG.column_hebrew;
}

function getGlossaryConfigRequiredOrder() {
    const list = metaModelGlossaryConfigData?.required_order;
    return Array.isArray(list) ? list : DEFAULT_GLOSSARY_CONFIG.required_order;
}

function getGlossaryConfigStandardMeta() {
    return metaModelGlossaryConfigData?.standard_meta || DEFAULT_GLOSSARY_CONFIG.standard_meta;
}

function getGlossaryConfigConceptIdAliases() {
    return metaModelGlossaryConfigData?.concept_id_aliases || DEFAULT_GLOSSARY_CONFIG.concept_id_aliases;
}

function getGlossaryConfigFallbackGroupById() {
    return metaModelGlossaryConfigData?.fallback_group_by_id || DEFAULT_GLOSSARY_CONFIG.fallback_group_by_id;
}

function getGlossaryConfigFallbackMarkersById() {
    return metaModelGlossaryConfigData?.fallback_markers_by_id || DEFAULT_GLOSSARY_CONFIG.fallback_markers_by_id;
}

function getGlossaryConfigFallbackQuestionsById() {
    return metaModelGlossaryConfigData?.fallback_questions_by_id || DEFAULT_GLOSSARY_CONFIG.fallback_questions_by_id;
}

function normalizeGlossaryConceptId(raw = '') {
    const value = String(raw || '').trim();
    if (!value) return '';
    const normalized = value.toLowerCase().replace(/[\s-]+/g, '_');
    const aliases = getGlossaryConfigConceptIdAliases();
    return aliases[normalized] || normalized;
}

function normalizeGlossaryMacroGroup(group = '', conceptId = '') {
    const columnOrder = getGlossaryConfigColumnOrder();
    const normalizedGroup = String(group || '').trim().toUpperCase();
    if (columnOrder.includes(normalizedGroup)) return normalizedGroup;

    const normalizedId = normalizeGlossaryConceptId(conceptId);
    const standardMeta = getGlossaryConfigStandardMeta();
    const standard = standardMeta[normalizedId];
    if (standard?.group && columnOrder.includes(standard.group)) {
        return standard.group;
    }
    const fallbackGroupById = getGlossaryConfigFallbackGroupById();
    if (normalizedId && fallbackGroupById[normalizedId]) {
        return fallbackGroupById[normalizedId];
    }

    const asSubcategory = SUBCATEGORY_TO_CATEGORY[String(conceptId || '').trim().toUpperCase().replace(/[\s-]+/g, '_')];
    if (asSubcategory && columnOrder.includes(asSubcategory)) {
        return asSubcategory;
    }

    return 'DISTORTION';
}

function uniqueTrimmedList(items = [], limit = 10) {
    const output = [];
    const seen = new Set();
    (items || []).forEach((entry) => {
        const value = normalizeUiText(String(entry || '').trim());
        if (!value) return;
        const key = value.toLowerCase();
        if (seen.has(key)) return;
        seen.add(key);
        output.push(value);
    });
    return output.slice(0, limit);
}

function asPlainObject(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    return value;
}

function normalizeGlossaryQuestionSets(rawSets = {}, fallbackQuestions = []) {
    const sets = asPlainObject(rawSets);
    const canonical = uniqueTrimmedList(
        Array.isArray(sets.canonical) ? sets.canonical : (Array.isArray(sets.core) ? sets.core : []),
        18
    );
    const daily = uniqueTrimmedList(
        Array.isArray(sets.daily) ? sets.daily : (Array.isArray(sets.everyday) ? sets.everyday : []),
        18
    );
    const identity = uniqueTrimmedList(
        Array.isArray(sets.identity) ? sets.identity : (Array.isArray(sets.identity_predicates) ? sets.identity_predicates : []),
        18
    );

    const mergedFlat = uniqueTrimmedList([
        ...(Array.isArray(fallbackQuestions) ? fallbackQuestions : []),
        ...canonical,
        ...daily,
        ...identity
    ], 24);

    return {
        canonical,
        daily,
        identity,
        mergedFlat
    };
}

function normalizeGlossaryDiltsLevels(rawLevels = []) {
    const source = Array.isArray(rawLevels) ? rawLevels : [];
    const normalized = [];
    const seen = new Set();

    source.forEach((entry) => {
        const row = asPlainObject(entry);
        const level = normalizeUiText(String(row.level || row.id || '').trim().toUpperCase());
        const label = normalizeUiText(String(row.label || '').trim());
        const focus = normalizeUiText(String(row.focus || row.problem_focus || '').trim());
        const interventions = uniqueTrimmedList(Array.isArray(row.interventions) ? row.interventions : [], 8);
        const key = `${level}|${label}|${focus}|${interventions.join('|')}`.toLowerCase();
        if (seen.has(key)) return;
        seen.add(key);
        if (!level && !label && !focus && !interventions.length) return;
        normalized.push({ level, label, focus, interventions });
    });

    return normalized.slice(0, 8);
}

function normalizeGlossaryConcept(rawItem = {}) {
    const conceptId = normalizeGlossaryConceptId(
        rawItem.id
        || rawItem.pattern_id
        || rawItem.en_title
        || rawItem.he_title
        || rawItem.name
        || rawItem.hebrew
    );
    if (!conceptId) return null;

    const story = asPlainObject(rawItem.story);
    const clinicalStory = asPlainObject(rawItem.clinical_story);
    const standardMeta = getGlossaryConfigStandardMeta()[conceptId] || null;
    const group = normalizeGlossaryMacroGroup(rawItem.group || rawItem.category || rawItem.family, conceptId);
    const resolvedGroup = standardMeta?.group || group;
    const columnHebrew = getGlossaryConfigColumnHebrew();
    const baseMarkers = uniqueTrimmedList([
        ...(Array.isArray(rawItem.markers) ? rawItem.markers : []),
        ...(Array.isArray(rawItem.examples) ? rawItem.examples : [])
    ], 16);
    const directQuestions = uniqueTrimmedList([
        ...(Array.isArray(rawItem.meta_model_questions) ? rawItem.meta_model_questions : []),
        ...(Array.isArray(rawItem.questions) ? rawItem.questions : [])
    ], 18);
    const questionSets = normalizeGlossaryQuestionSets(rawItem.question_sets, directQuestions);

    return {
        id: conceptId,
        group: resolvedGroup,
        he_group: normalizeUiText(String(rawItem.he_group || columnHebrew[resolvedGroup] || '').trim()),
        he_title: normalizeUiText(String(standardMeta?.he || rawItem.he_title || rawItem.hebrew || rawItem.name || conceptId).trim()),
        en_title: normalizeUiText(String(standardMeta?.en || rawItem.en_title || rawItem.name || conceptId).trim()),
        icon: normalizeUiText(String(rawItem.icon || rawItem.emoji || '').trim()),
        main_category: normalizeUiText(String(rawItem.main_category || rawItem.category_root || resolvedGroup).trim().toUpperCase()),
        meta_intervention: normalizeUiText(String(rawItem.meta_intervention || rawItem.intervention || '').trim()),
        he_definition_short: normalizeUiText(String(rawItem.he_definition_short || rawItem.description || '').trim()),
        violation: normalizeUiText(String(rawItem.violation || '').trim()),
        problem: normalizeUiText(String(rawItem.problem || '').trim()),
        emotional_meaning: normalizeUiText(String(rawItem.emotional_meaning || rawItem.emotional_impact || '').trim()),
        context_signals: uniqueTrimmedList(Array.isArray(rawItem.context_signals) ? rawItem.context_signals : [], 16),
        philosophical_background: normalizeUiText(String(rawItem.philosophical_background || rawItem.philosophy || '').trim()),
        jewish_quote: normalizeUiText(String(rawItem.jewish_quote || '').trim()),
        linguistic_triggers: uniqueTrimmedList([
            ...(Array.isArray(rawItem.linguistic_triggers) ? rawItem.linguistic_triggers : []),
            ...(Array.isArray(rawItem.triggers) ? rawItem.triggers : [])
        ], 18),
        markers: baseMarkers,
        question_goal: normalizeUiText(String(rawItem.question_goal || rawItem.questions_goal || '').trim()),
        target_information: normalizeUiText(String(rawItem.target_information || rawItem.information_target || '').trim()),
        question_sets: {
            canonical: questionSets.canonical,
            daily: questionSets.daily,
            identity: questionSets.identity
        },
        meta_model_questions: questionSets.mergedFlat,
        story: {
            client_line: normalizeUiText(String(story.client_line || clinicalStory.client_line || '').trim()),
            therapist_intervention: normalizeUiText(String(story.therapist_intervention || clinicalStory.therapist_intervention || '').trim())
        },
        transformation_moment: normalizeUiText(String(rawItem.transformation_moment || clinicalStory.turning_point || '').trim()),
        positive_end: normalizeUiText(String(rawItem.positive_end || '').trim()),
        next_step_direction: normalizeUiText(String(rawItem.next_step_direction || '').trim()),
        anti_patterns: uniqueTrimmedList(Array.isArray(rawItem.anti_patterns) ? rawItem.anti_patterns : [], 14),
        dilts_levels: normalizeGlossaryDiltsLevels(rawItem.dilts_levels)
    };
}

function buildGlossaryFallbackConcept(category = {}, subcategory = {}) {
    const rawId = String(subcategory?.id || subcategory?.name || '').trim();
    if (!rawId) return null;
    const group = normalizeGlossaryMacroGroup(subcategory?.category || category?.id, rawId);
    const columnHebrew = getGlossaryConfigColumnHebrew();
    return normalizeGlossaryConcept({
        id: rawId,
        group,
        he_group: columnHebrew[group] || '',
        he_title: subcategory?.hebrew || subcategory?.name || rawId,
        en_title: subcategory?.name || rawId,
        he_definition_short: subcategory?.description || '',
        markers: [subcategory?.example || ''],
        meta_model_questions: [subcategory?.question || '']
    });
}

function mergeGlossaryConcept(primary, secondary) {
    if (!primary) return secondary;
    if (!secondary) return primary;

    const merged = { ...primary };
    merged.group = normalizeGlossaryMacroGroup(primary.group || secondary.group, primary.id || secondary.id);
    merged.he_group = String(primary.he_group || secondary.he_group || getGlossaryConfigColumnHebrew()[merged.group] || '').trim();
    merged.he_title = String(primary.he_title || secondary.he_title || primary.id || '').trim();
    merged.en_title = String(primary.en_title || secondary.en_title || primary.id || '').trim();
    merged.icon = String(primary.icon || secondary.icon || '').trim();
    merged.main_category = String(primary.main_category || secondary.main_category || merged.group || '').trim().toUpperCase();
    merged.meta_intervention = String(primary.meta_intervention || secondary.meta_intervention || '').trim();
    merged.he_definition_short = String(primary.he_definition_short || secondary.he_definition_short || '').trim();
    merged.violation = String(primary.violation || secondary.violation || '').trim();
    merged.problem = String(primary.problem || secondary.problem || '').trim();
    merged.emotional_meaning = String(primary.emotional_meaning || secondary.emotional_meaning || '').trim();
    merged.philosophical_background = String(primary.philosophical_background || secondary.philosophical_background || '').trim();
    merged.jewish_quote = String(primary.jewish_quote || secondary.jewish_quote || '').trim();
    merged.question_goal = String(primary.question_goal || secondary.question_goal || '').trim();
    merged.target_information = String(primary.target_information || secondary.target_information || '').trim();
    merged.markers = uniqueTrimmedList([...(primary.markers || []), ...(secondary.markers || [])]);
    merged.context_signals = uniqueTrimmedList([...(primary.context_signals || []), ...(secondary.context_signals || [])], 16);
    merged.linguistic_triggers = uniqueTrimmedList([...(primary.linguistic_triggers || []), ...(secondary.linguistic_triggers || [])], 18);
    const primaryQuestionSets = asPlainObject(primary.question_sets);
    const secondaryQuestionSets = asPlainObject(secondary.question_sets);
    const mergedQuestionSets = {
        canonical: uniqueTrimmedList([...(primaryQuestionSets.canonical || []), ...(secondaryQuestionSets.canonical || [])], 18),
        daily: uniqueTrimmedList([...(primaryQuestionSets.daily || []), ...(secondaryQuestionSets.daily || [])], 18),
        identity: uniqueTrimmedList([...(primaryQuestionSets.identity || []), ...(secondaryQuestionSets.identity || [])], 18)
    };
    merged.question_sets = mergedQuestionSets;
    merged.meta_model_questions = uniqueTrimmedList([...(primary.meta_model_questions || []), ...(secondary.meta_model_questions || [])]);
    merged.meta_model_questions = uniqueTrimmedList([
        ...merged.meta_model_questions,
        ...mergedQuestionSets.canonical,
        ...mergedQuestionSets.daily,
        ...mergedQuestionSets.identity
    ], 24);
    merged.story = {
        client_line: String(primary.story?.client_line || secondary.story?.client_line || '').trim(),
        therapist_intervention: String(primary.story?.therapist_intervention || secondary.story?.therapist_intervention || '').trim()
    };
    merged.transformation_moment = String(primary.transformation_moment || secondary.transformation_moment || '').trim();
    merged.positive_end = String(primary.positive_end || secondary.positive_end || '').trim();
    merged.next_step_direction = String(primary.next_step_direction || secondary.next_step_direction || '').trim();
    merged.anti_patterns = uniqueTrimmedList([...(primary.anti_patterns || []), ...(secondary.anti_patterns || [])], 14);
    merged.dilts_levels = normalizeGlossaryDiltsLevels([...(primary.dilts_levels || []), ...(secondary.dilts_levels || [])]);
    return merged;
}

function extractPatternLibraryTextList(items = [], limit = 12) {
    const source = Array.isArray(items) ? items : [];
    const normalized = source
        .map((entry) => (typeof entry === 'string' ? entry : entry?.text))
        .map((entry) => normalizeUiText(String(entry || '').trim()))
        .filter(Boolean);
    return uniqueTrimmedList(normalized, limit);
}

function buildPatternLibraryConcept(pattern = {}) {
    const patternId = normalizeGlossaryConceptId(pattern?.id || pattern?.name || '');
    if (!patternId) return null;
    return normalizeGlossaryConcept({
        id: patternId,
        group: normalizeGlossaryMacroGroup(pattern?.family || '', patternId),
        he_group: getGlossaryConfigColumnHebrew()[normalizeGlossaryMacroGroup(pattern?.family || '', patternId)] || '',
        he_title: pattern?.name || '',
        he_definition_short: pattern?.definition || pattern?.problem?.oneLiner || '',
        markers: extractPatternLibraryTextList(pattern?.examples || [], 14),
        meta_model_questions: extractPatternLibraryTextList(pattern?.goodQuestions || [], 18)
    });
}

function enrichGlossaryConceptDepth(item = {}) {
    const id = normalizeGlossaryConceptId(item.id);
    const standard = getGlossaryConfigStandardMeta()[id] || null;
    const group = normalizeGlossaryMacroGroup(item.group, id);
    const fallbackMarkersById = getGlossaryConfigFallbackMarkersById();
    const fallbackQuestionsById = getGlossaryConfigFallbackQuestionsById();
    const mergedMarkers = uniqueTrimmedList([...(item.markers || []), ...((fallbackMarkersById[id]) || [])], 16);
    const mergedQuestions = uniqueTrimmedList([...(item.meta_model_questions || []), ...((fallbackQuestionsById[id]) || [])], 18);
    const normalizedQuestionSets = normalizeGlossaryQuestionSets(item.question_sets, mergedQuestions);
    return {
        ...item,
        id,
        group,
        he_group: normalizeUiText(String(item.he_group || getGlossaryConfigColumnHebrew()[group] || '').trim()),
        he_title: normalizeUiText(String(standard?.he || item.he_title || id).trim()),
        en_title: normalizeUiText(String(standard?.en || item.en_title || id).trim()),
        markers: mergedMarkers,
        meta_model_questions: normalizedQuestionSets.mergedFlat,
        question_sets: {
            canonical: normalizedQuestionSets.canonical,
            daily: normalizedQuestionSets.daily,
            identity: normalizedQuestionSets.identity
        },
        context_signals: uniqueTrimmedList(item.context_signals || [], 16),
        linguistic_triggers: uniqueTrimmedList(item.linguistic_triggers || [], 18),
        anti_patterns: uniqueTrimmedList(item.anti_patterns || [], 14),
        dilts_levels: normalizeGlossaryDiltsLevels(item.dilts_levels || [])
    };
}

function getGlossaryRequiredOrderRank(item = {}) {
    const id = normalizeGlossaryConceptId(item?.id || '');
    const idx = getGlossaryConfigRequiredOrder().indexOf(id);
    return idx === -1 ? Number.MAX_SAFE_INTEGER : idx;
}

function sortGlossaryConceptsByRequiredOrder(concepts = []) {
    return [...(Array.isArray(concepts) ? concepts : [])].sort((a, b) => {
        const rankDiff = getGlossaryRequiredOrderRank(a) - getGlossaryRequiredOrderRank(b);
        if (rankDiff !== 0) return rankDiff;
        return String(a?.he_title || '').localeCompare(String(b?.he_title || ''), 'he');
    });
}

function collectGlossaryConcepts() {
    const byId = new Map();

    const upsert = (rawConcept, { preferred = false } = {}) => {
        const normalized = normalizeGlossaryConcept(rawConcept);
        if (!normalized) return;
        const key = normalized.id;
        if (!byId.has(key)) {
            byId.set(key, normalized);
            return;
        }
        const existing = byId.get(key);
        byId.set(key, preferred ? mergeGlossaryConcept(normalized, existing) : mergeGlossaryConcept(existing, normalized));
    };

    (metaModelData.categories || []).forEach((category) => {
        (category?.subcategories || []).forEach((subcategory) => {
            const fallback = buildGlossaryFallbackConcept(category, subcategory);
            upsert(fallback, { preferred: false });
        });
    });

    (metaModelGlossaryData?.items || []).forEach((item) => {
        upsert(item, { preferred: true });
    });

    (metaModelGlossaryBlueprintData?.items || []).forEach((item) => {
        upsert(item, { preferred: true });
    });

    (metaModelPatternLibraryData?.patterns || []).forEach((pattern) => {
        const concept = buildPatternLibraryConcept(pattern);
        upsert(concept, { preferred: false });
    });

    getBreenReferenceRows().forEach((row) => {
        (row?.categories || []).forEach((categoryId) => {
            const normalizedId = normalizeGlossaryConceptId(categoryId);
            if (!normalizedId || byId.has(normalizedId)) return;
            upsert({
                id: normalizedId,
                group: normalizeGlossaryMacroGroup('', normalizedId),
                he_group: getGlossaryConfigColumnHebrew()[normalizeGlossaryMacroGroup('', normalizedId)] || '',
                he_title: getBreenReferenceCategoryLabelHe(categoryId) || normalizedId,
                en_title: getBreenReferenceCategoryChip(categoryId) || normalizedId.replace(/_/g, ' '),
                he_definition_short: 'הרחבה תיאורטית תתווסף בהמשך. בינתיים מומלץ לתרגל זיהוי ושאלת דיוק אחת לפחות עבור תבנית זו.',
                markers: [],
                meta_model_questions: []
            }, { preferred: false });
        });
    });

    getGlossaryConfigRequiredOrder().forEach((requiredId) => {
        if (byId.has(requiredId)) return;
        const standard = getGlossaryConfigStandardMeta()[requiredId];
        if (!standard) return;
        upsert({
            id: requiredId,
            group: standard.group,
            he_group: getGlossaryConfigColumnHebrew()[standard.group] || '',
            he_title: standard.he,
            en_title: standard.en,
            he_definition_short: 'הגדרה מלאה תתווסף בהמשך. כרגע אפשר להתחיל עם הדוגמאות ושאלות הדיוק שבכרטיס.',
            markers: [],
            meta_model_questions: []
        }, { preferred: false });
    });

    return sortGlossaryConceptsByRequiredOrder(Array.from(byId.values()).map((item) => enrichGlossaryConceptDepth(item)));
}

function buildGlossaryConceptBody(item = {}) {
    const definition = normalizeUiText(String(item.he_definition_short || item.definition || '').trim());
    const metaIntervention = normalizeUiText(String(item.meta_intervention || '').trim());
    const violation = normalizeUiText(String(item.violation || '').trim());
    const problem = normalizeUiText(String(item.problem || '').trim());
    const emotionalMeaning = normalizeUiText(String(item.emotional_meaning || '').trim());
    const philosophicalBackground = normalizeUiText(String(item.philosophical_background || '').trim());
    const jewishQuote = normalizeUiText(String(item.jewish_quote || '').trim());
    const questionGoal = normalizeUiText(String(item.question_goal || '').trim());
    const targetInformation = normalizeUiText(String(item.target_information || '').trim());
    const storyClient = normalizeUiText(String(item.story?.client_line || '').trim());
    const storyIntervention = normalizeUiText(String(item.story?.therapist_intervention || '').trim());
    const transformation = normalizeUiText(String(item.transformation_moment || '').trim());
    const positiveEnd = normalizeUiText(String(item.positive_end || '').trim());
    const nextStep = normalizeUiText(String(item.next_step_direction || '').trim());
    const contextSignals = uniqueTrimmedList(item.context_signals || [], 16);
    const triggers = uniqueTrimmedList(item.linguistic_triggers || [], 18);
    const antiPatterns = uniqueTrimmedList(item.anti_patterns || [], 14);
    const diltsLevels = normalizeGlossaryDiltsLevels(item.dilts_levels || []);

    const markers = Array.isArray(item.markers)
        ? item.markers.map((entry) => normalizeUiText(String(entry || '').trim())).filter(Boolean).slice(0, 12)
        : [];
    const questionsAll = Array.isArray(item.meta_model_questions)
        ? item.meta_model_questions.map((entry) => normalizeUiText(String(entry || '').trim())).filter(Boolean).slice(0, 14)
        : [];
    const questionSets = asPlainObject(item.question_sets);
    const questionsCanonical = uniqueTrimmedList(questionSets.canonical || [], 14);
    const questionsDaily = uniqueTrimmedList(questionSets.daily || [], 14);
    const questionsIdentity = uniqueTrimmedList(questionSets.identity || [], 14);

    const markersHtml = markers.length
        ? `<ul class="glossary-inline-list">${markers.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>דוגמאות יתווספו בהמשך.</p>';
    const triggerHtml = triggers.length
        ? `<ul class="glossary-inline-list">${triggers.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>טריגרים לשוניים יתווספו בהמשך.</p>';
    const contextSignalsHtml = contextSignals.length
        ? `<ul class="glossary-inline-list">${contextSignals.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>סממנים לשוניים/קונטקסטואליים יתווספו בהמשך.</p>';
    const questionsHtml = questionsAll.length
        ? `<ul class="glossary-inline-list">${questionsAll.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>שאלות מטא־מודל יתווספו בהמשך.</p>';
    const questionsCanonicalHtml = questionsCanonical.length
        ? `<ul class="glossary-inline-list">${questionsCanonical.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>שאלות קאנוניות יתווספו בהמשך.</p>';
    const questionsDailyHtml = questionsDaily.length
        ? `<ul class="glossary-inline-list">${questionsDaily.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>שאלות יומיומיות יתווספו בהמשך.</p>';
    const questionsIdentityHtml = questionsIdentity.length
        ? `<ul class="glossary-inline-list">${questionsIdentity.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>שאלות זהות יתווספו בהמשך.</p>';
    const antiPatternsHtml = antiPatterns.length
        ? `<ul class="glossary-inline-list">${antiPatterns.map((entry) => `<li>${escapeHtml(entry)}</li>`).join('')}</ul>`
        : '<p>אנטי-פאטרנים יתווספו בהמשך.</p>';
    const diltsHtml = diltsLevels.length
        ? `<ul class="glossary-inline-list">${diltsLevels.map((entry) => {
            const levelHead = [entry.level, entry.label].filter(Boolean).join(' ');
            const interventions = entry.interventions.length ? ` | התערבויות: ${entry.interventions.join(' · ')}` : '';
            const focus = entry.focus ? ` — ${entry.focus}` : '';
            return `<li><strong>${escapeHtml(levelHead || 'רמה')}</strong>${escapeHtml(focus + interventions)}</li>`;
        }).join('')}</ul>`
        : '<p>רמות נוירולוגיות + התערבויות יתווספו בהמשך.</p>';
    const storyEmpty = !storyClient && !storyIntervention && !transformation && !positiveEnd && !nextStep;
    const mapSectionEmpty = !violation && !problem && !emotionalMeaning && !philosophicalBackground && !jewishQuote;

    return `
        ${definition ? `<p class="glossary-definition">${escapeHtml(definition)}</p>` : ''}
        ${metaIntervention ? `<p><strong>התערבות מטא-מודל:</strong> ${escapeHtml(metaIntervention)}</p>` : ''}

        <details class="glossary-layer">
            <summary>מפת פרמטרים מלאה</summary>
            <div class="glossary-layer-body">
                ${violation ? `<p><strong>הפרה:</strong> ${escapeHtml(violation)}</p>` : ''}
                ${problem ? `<p><strong>הבעיה:</strong> ${escapeHtml(problem)}</p>` : ''}
                ${emotionalMeaning ? `<p><strong>משמעות רגשית:</strong> ${escapeHtml(emotionalMeaning)}</p>` : ''}
                ${philosophicalBackground ? `<p><strong>רקע פילוסופי:</strong> ${escapeHtml(philosophicalBackground)}</p>` : ''}
                ${jewishQuote ? `<p><strong>ציטוט יהודי:</strong> ${escapeHtml(jewishQuote)}</p>` : ''}
                ${mapSectionEmpty ? '<p>שדות ההפרה/בעיה/משמעות/פילוסופיה יוזנו בהמשך.</p>' : ''}
            </div>
        </details>

        <details class="glossary-layer">
            <summary>סממנים לשוניים וקונטקסטואליים</summary>
            <div class="glossary-layer-body">
                <p><strong>סממנים:</strong></p>
                ${contextSignalsHtml}
                <p><strong>טריגרים לשוניים:</strong></p>
                ${triggerHtml}
            </div>
        </details>

        <details class="glossary-layer">
            <summary>הסיפור הקליני + נקודת השינוי</summary>
            <div class="glossary-layer-body">
                ${storyClient ? `<p><strong>משפט מטופל:</strong> ${escapeHtml(storyClient)}</p>` : ''}
                ${storyIntervention ? `<p><strong>התערבות מטפל:</strong> ${escapeHtml(storyIntervention)}</p>` : ''}
                ${transformation ? `<p><strong>רגע טרנספורמציה:</strong> ${escapeHtml(transformation)}</p>` : ''}
                ${positiveEnd ? `<p><strong>סיום חיובי:</strong> ${escapeHtml(positiveEnd)}</p>` : ''}
                ${nextStep ? `<p><strong>המשך:</strong> ${escapeHtml(nextStep)}</p>` : ''}
                ${storyEmpty ? '<p>הרחבה קלינית מלאה תתווסף בהמשך. בינתיים התקדמו דרך הדוגמאות והשאלות של התבנית.</p>' : ''}
            </div>
        </details>

        <details class="glossary-layer">
            <summary>דוגמאות</summary>
            <div class="glossary-layer-body">${markersHtml}</div>
        </details>

        <details class="glossary-layer">
            <summary>מטרת שאלות + אוסף שאלות</summary>
            <div class="glossary-layer-body">
                ${questionGoal ? `<p><strong>מטרת השאלות:</strong> ${escapeHtml(questionGoal)}</p>` : ''}
                ${targetInformation ? `<p><strong>מידע שאנחנו רוצים להשיג:</strong> ${escapeHtml(targetInformation)}</p>` : ''}
                <p><strong>שאלות קאנוניות:</strong></p>
                ${questionsCanonicalHtml}
                <p><strong>שאלות יומיומיות:</strong></p>
                ${questionsDailyHtml}
                <p><strong>שאלות זהות / Identity:</strong></p>
                ${questionsIdentityHtml}
                <p><strong>מאגר שאלות כללי:</strong></p>
                ${questionsHtml}
            </div>
        </details>

        <details class="glossary-layer">
            <summary>אנטי-פאטרנים + רמות נוירולוגיות</summary>
            <div class="glossary-layer-body">
                <p><strong>אנטי-פאטרנים:</strong></p>
                ${antiPatternsHtml}
                <p><strong>רמות נוירולוגיות (דילטס) + התערבויות:</strong></p>
                ${diltsHtml}
            </div>
        </details>
    `;
}

function buildGlossaryConceptCard(item = {}, { lazyBody = false } = {}) {
    const heTitle = normalizeUiText(String(item.he_title || item.hebrew || item.en_title || item.id || 'מושג').trim());
    const enTitle = normalizeUiText(String(item.en_title || '').trim());
    const title = heTitle && enTitle ? `${heTitle} — ${enTitle}` : (heTitle || enTitle || 'מושג');
    const icon = normalizeUiText(String(item.icon || '').trim());
    const mainCategory = normalizeUiText(String(item.main_category || '').trim());
    const groupHe = normalizeUiText(String(item.he_group || '').trim());
    const groupEn = normalizeUiText(String(item.group || '').trim());
    const normalizedId = normalizeGlossaryConceptId(item.id || '') || normalizeUiText(String(item.id || '').trim());
    const bodyMarkup = lazyBody ? '' : buildGlossaryConceptBody(item);
    const lazyAttr = lazyBody ? ' data-glossary-lazy="true"' : '';
    const pills = [];
    const seenPills = new Set();
    [
        { text: groupHe, className: 'glossary-pill glossary-pill-he' },
        { text: groupEn, className: 'glossary-pill glossary-pill-en' },
        { text: mainCategory, className: 'glossary-pill glossary-pill-en' }
    ].forEach((pill) => {
        const text = normalizeUiText(String(pill?.text || '').trim());
        if (!text) return;
        const key = text.toUpperCase();
        if (seenPills.has(key)) return;
        seenPills.add(key);
        pills.push(`<span class="${pill.className}">${escapeHtml(text)}</span>`);
    });

    return `
        <details class="category-card glossary-card glossary-category ${escapeHtml(getGlossaryGroupClass(groupEn))}" data-glossary-id="${escapeHtml(normalizedId)}">
            <summary class="glossary-category-summary">
                <div class="glossary-card-head">
                    <h3>${icon ? `${escapeHtml(icon)} ` : ''}${escapeHtml(title)}</h3>
                    <div class="glossary-pills">
                        ${pills.join('')}
                    </div>
                </div>
            </summary>
            <div class="glossary-category-body"${lazyAttr}>${bodyMarkup}</div>
        </details>
    `;
}

function hydrateGlossaryCategoryCard(detailsEl) {
    if (!(detailsEl instanceof HTMLElement)) return;
    if (detailsEl.dataset.glossaryHydrated === 'true') return;
    const body = detailsEl.querySelector(':scope > .glossary-category-body');
    if (!body) return;
    const rawId = normalizeUiText(String(detailsEl.dataset.glossaryId || '').trim());
    const conceptId = normalizeGlossaryConceptId(rawId);
    const concept = (conceptId && glossaryConceptIndex.get(conceptId))
        || (rawId && glossaryConceptIndex.get(rawId))
        || null;
    if (!concept) return;
    body.innerHTML = buildGlossaryConceptBody(concept);
    detailsEl.dataset.glossaryHydrated = 'true';
    body.removeAttribute('data-glossary-lazy');
}

function collapseGlossarySubLayers(categoryDetails = null) {
    if (!(categoryDetails instanceof HTMLElement)) return;
    categoryDetails.querySelectorAll('details[open]').forEach((detailsEl) => {
        if (detailsEl === categoryDetails) return;
        detailsEl.open = false;
    });
}

function collapseAllGlossaryCategories(root = null) {
    const host = root || document;
    if (!host || !host.querySelectorAll) return;
    host.querySelectorAll('details.glossary-category').forEach((detailsEl) => {
        collapseGlossarySubLayers(detailsEl);
        detailsEl.open = false;
    });
}

function findGlossaryLinkedTarget(host, rawTargetId = '') {
    if (!(host instanceof HTMLElement) || !host.querySelectorAll) return null;
    const normalizedTarget = normalizeGlossaryConceptId(rawTargetId);
    if (!normalizedTarget) return null;

    const directCategory = Array.from(host.querySelectorAll('details.glossary-category')).find((detailsEl) => {
        const glossaryId = normalizeGlossaryConceptId(String(detailsEl.dataset.glossaryId || '').trim());
        return glossaryId === normalizedTarget;
    });
    if (directCategory) return directCategory;

    return Array.from(host.querySelectorAll('details[data-pattern-id]')).find((detailsEl) => {
        const patternId = normalizeGlossaryConceptId(
            String(detailsEl.dataset.patternId || detailsEl.id || '').replace(/^pattern-/, '').trim()
        );
        return patternId === normalizedTarget;
    }) || null;
}

function openGlossaryDetailsBranch(host, targetEl) {
    if (!(host instanceof HTMLElement) || !(targetEl instanceof HTMLElement)) return false;

    const detailsChain = [];
    let node = targetEl;
    while (node && node !== host) {
        if (node instanceof HTMLDetailsElement) detailsChain.push(node);
        node = node.parentElement;
    }
    if (!detailsChain.length) return false;

    let activeCategory = null;
    detailsChain.reverse().forEach((detailsEl) => {
        if (detailsEl.classList.contains('glossary-category')) {
            hydrateGlossaryCategoryCard(detailsEl);
            activeCategory = detailsEl;
        }
        detailsEl.open = true;
    });

    if (activeCategory) {
        host.querySelectorAll('details.glossary-category').forEach((detailsEl) => {
            if (detailsEl === activeCategory) return;
            collapseGlossarySubLayers(detailsEl);
            detailsEl.open = false;
        });
    }

    try {
        targetEl.scrollIntoView({
            behavior: prefersReducedMotion() ? 'auto' : 'smooth',
            block: 'start',
            inline: 'nearest'
        });
    } catch (_error) {
        try {
            targetEl.scrollIntoView();
        } catch (_ignored) {}
    }

    return true;
}

function syncGlossaryHashTarget(host = null) {
    const root = host instanceof HTMLElement ? host : null;
    if (!root) return false;
    const hash = String(window.location.hash || '').trim().replace(/^#/, '');
    if (!hash) return false;
    const rawTargetId = hash.replace(/^pattern-/, '');
    const target = findGlossaryLinkedTarget(root, rawTargetId);
    if (!target) return false;
    return openGlossaryDetailsBranch(root, target);
}

function setupGlossarySingleCategoryBehavior(root = null) {
    const host = root && root instanceof HTMLElement ? root : null;
    if (!host || host.dataset.glossarySingleBound === 'true') return;
    host.dataset.glossarySingleBound = 'true';

    const handleSummaryActivation = (event) => {
        const summary = event.target?.closest?.('summary');
        if (!summary || !host.contains(summary)) return false;
        const details = summary.parentElement;
        if (!(details instanceof HTMLDetailsElement)) return false;

        const isSupportedDetails = details.classList.contains('glossary-category')
            || details.classList.contains('glossary-layer')
            || details.classList.contains('subcategory-layered')
            || details.classList.contains('subcategory-layer');
        if (!isSupportedDetails) return false;

        event.preventDefault();
        if (!details.open && details.classList.contains('glossary-category')) {
            hydrateGlossaryCategoryCard(details);
        }
        details.open = !details.open;
        if (!details.open) collapseGlossarySubLayers(details);
        return true;
    };

    const handlePatternLinkActivation = (event) => {
        const link = event.target?.closest?.('[data-breen-pattern-link]');
        if (!link || !host.contains(link)) return false;
        event.preventDefault();

        const rawTargetId = String(link.getAttribute('data-breen-pattern-link') || '').trim()
            || String(link.getAttribute('href') || '').trim().replace(/^#pattern-/, '');
        const target = findGlossaryLinkedTarget(host, rawTargetId);
        if (!target) return false;

        const normalizedTarget = normalizeGlossaryConceptId(rawTargetId);
        if (normalizedTarget) {
            const nextHash = `#pattern-${normalizedTarget}`;
            if (window.location.hash !== nextHash) {
                try {
                    window.history.replaceState(null, '', nextHash);
                } catch (_error) {
                    window.location.hash = nextHash;
                }
            }
        }

        return openGlossaryDetailsBranch(host, target);
    };

    host.addEventListener('click', (event) => {
        if (handlePatternLinkActivation(event)) return;
        handleSummaryActivation(event);
    });

    host.addEventListener('keydown', (event) => {
        if (!event || (event.key !== 'Enter' && event.key !== ' ')) return;
        if (handlePatternLinkActivation(event)) return;
        handleSummaryActivation(event);
    });

    host.addEventListener('toggle', (event) => {
        const target = event.target;
        if (!(target instanceof HTMLDetailsElement)) return;
        if (!target.classList.contains('glossary-category')) return;
        if (!target.open) {
            collapseGlossarySubLayers(target);
            return;
        }
        hydrateGlossaryCategoryCard(target);
        host.querySelectorAll('details.glossary-category').forEach((detailsEl) => {
            if (detailsEl === target) return;
            collapseGlossarySubLayers(detailsEl);
            detailsEl.open = false;
        });
    });
}

function renderGlossaryColumn(columnKey = '', concepts = []) {
    const group = String(columnKey || '').trim().toUpperCase();
    const groupHe = getGlossaryConfigColumnHebrew()[group] || '';
    const items = concepts
        .filter((item) => normalizeGlossaryMacroGroup(item.group, item.id) === group)
        .sort((a, b) => String(a.he_title || '').localeCompare(String(b.he_title || ''), 'he'));

    const cardsHtml = items.length
        ? items.map((item) => buildGlossaryConceptCard(item, { lazyBody: true })).join('')
        : '<div class="card glossary-column-empty">אין קטגוריות להצגה בעמודה זו.</div>';

    return `
        <section class="glossary-column glossary-column-${escapeHtml(getGlossaryGroupClass(group))}" data-glossary-column="${escapeHtml(group)}">
            <header class="glossary-column-head">
                <h3 class="glossary-column-title">${escapeHtml(group)}</h3>
                <p class="glossary-column-subtitle">${escapeHtml(groupHe)}</p>
            </header>
            <div class="glossary-column-list">${cardsHtml}</div>
        </section>
    `;
}

function populateCategories() {
    const container = document.getElementById('categories-container');
    if (!container) return;
    container.innerHTML = '';

    const glossaryItems = collectGlossaryConcepts();
    if (!glossaryItems.length) {
        container.innerHTML = '<section class="card categories-theory-intro"><h2>מילון קטגוריות המטה-מודל</h2><p>לא נמצאו נתוני קטגוריות להצגה.</p></section>';
        return;
    }

    const theoryIntro = document.createElement('section');
    theoryIntro.className = 'card categories-theory-intro categories-glossary-intro';
    theoryIntro.innerHTML = `
        <h2>מילון קטגוריות המטה-מודל</h2>
        <p>
            דף זה מציג את כל הקטגוריות בסדר המלא של Michael Breen,
            ובסיומן הקטגוריות המורחבות של חגי.
            לכל קטגוריה תמצאו שם סטנדרטי (עברית + אנגלית), דוגמאות ושאלות מטא־מודל.
        </p>
        <p class="categories-theory-note"><strong>למה:</strong> מעבר עקבי על הסדר הזה בונה שפה אחידה ומונע כפילויות/בלבול בין קטגוריות.</p>
    `;
    container.appendChild(theoryIntro);

    const orderedList = document.createElement('section');
    orderedList.className = 'categories-glossary-ordered-list';
    const orderedConcepts = sortGlossaryConceptsByRequiredOrder(glossaryItems);
    glossaryConceptIndex = new Map();
    orderedConcepts.forEach((item) => {
        const normalizedId = normalizeGlossaryConceptId(item?.id || '');
        const rawId = normalizeUiText(String(item?.id || '').trim());
        if (normalizedId) glossaryConceptIndex.set(normalizedId, item);
        if (rawId && !glossaryConceptIndex.has(rawId)) glossaryConceptIndex.set(rawId, item);
    });
    orderedList.innerHTML = orderedConcepts
        .map((item) => buildGlossaryConceptCard(item, { lazyBody: true }))
        .join('');
    container.appendChild(orderedList);
    setupGlossarySingleCategoryBehavior(orderedList);
    collapseAllGlossaryCategories(orderedList);
    syncGlossaryHashTarget(orderedList);
}

// Populate Category Select in Practice Mode
function populateCategorySelect() {
    const select = document.getElementById('category-select');
    
    metaModelData.categories.forEach(category => {
        const option = document.createElement('option');
        option.value = category.id;
        option.textContent = category.hebrew_name;
        select.appendChild(option);
    });
}

function normalizePracticePageKey(pageKey = '') {
    const key = String(pageKey || '').trim().toLowerCase();
    if (key === 'meta-radar' || key === 'meta_radar') return 'radar';
    if (key === 'triples_radar' || key === 'breen-radar' || key === 'michael-breen') return 'triples-radar';
    if (key === 'sqhcel' || key === 'wizard') return 'wizard';
    if (key === 'question' || key === 'questions' || key === 'drill') return 'question';
    return PRACTICE_PAGE_KEYS.includes(key) ? key : 'question';
}

function getPracticeTabIdFromPageKey(pageKey = 'question') {
    const resolvedPage = normalizePracticePageKey(pageKey);
    return PRACTICE_TAB_BY_PAGE_KEY[resolvedPage] || PRACTICE_TAB_BY_PAGE_KEY.question;
}

function navigateToPracticePage(pageKey = 'question') {
    const targetTab = getPracticeTabIdFromPageKey(pageKey);
    persistPracticeTabPreference(targetTab);
    navigateTo(targetTab, { playSound: false, scrollToTop: true });
}

// Setup Practice Mode
function setupPracticeMode() {
    const nextBtn = document.getElementById('next-btn');
    const showAnswerBtn = document.getElementById('show-answer-btn');
    const hintBtn = document.getElementById('hint-btn');

    // Legacy practice controls may not exist in the current UI.
    if (!nextBtn || !showAnswerBtn || !hintBtn) return;

    nextBtn.addEventListener('click', getNextStatement);
    showAnswerBtn.addEventListener('click', showAnswer);
    hintBtn.addEventListener('click', showLegacyPracticeHint);
}

