function ceflowNormalizeCopy(value, fallback = '') {
    const text = String(value || '').trim();
    if (!text || looksLikeMojibakeText(text)) return String(fallback || '').trim();
    return text;
}

function ceflowClampInt(value, fallback, min, max) {
    const n = Number(value);
    const base = Number.isFinite(n) ? n : Number(fallback);
    const low = Number.isFinite(min) ? min : 0;
    const high = Number.isFinite(max) ? max : 100;
    if (!Number.isFinite(base)) return low;
    return Math.max(low, Math.min(high, Math.round(base)));
}

function ceflowClamp(value, fallback) {
    const n = Number(value);
    if (!Number.isFinite(n)) return fallback;
    return Math.max(0, Math.min(100, Math.round(n)));
}

function ceflowNormBlueprint(raw) {
    if (!raw || typeof raw !== 'object') return null;
    return {
        goal: String(raw.goal || '').trim(),
        first: String(raw.first || raw.first_step || '').trim(),
        middle: (Array.isArray(raw.middle) ? raw.middle : raw.middle_steps || []).map(v => String(v || '').trim()).filter(Boolean).slice(0, 3),
        last: String(raw.last || raw.last_step || '').trim(),
        alternatives: (raw.alternatives || []).map(v => String(v || '').trim()).filter(Boolean).slice(0, 2),
        preconditions: (raw.preconditions || []).map(v => String(v || '').trim()).filter(Boolean).slice(0, 3)
    };
}

function ceflowNormImpact(raw, id) {
    const fallback = CEFLOW_FALLBACKS[id] || CEFLOW_FALLBACKS.meta;
    const stats = raw?.stats || {};
    return {
        stats: {
            flow: ceflowClamp(stats.flow, fallback.impact.stats.flow),
            agency: ceflowClamp(stats.agency, fallback.impact.stats.agency),
            shame: ceflowClamp(stats.shame, fallback.impact.stats.shame)
        },
        xrayTags: Array.isArray(raw?.xrayTags) && raw.xrayTags.length ? raw.xrayTags.slice(0, 3) : [...fallback.impact.xrayTags],
        microOutcome: Array.isArray(raw?.microOutcome) && raw.microOutcome.length ? raw.microOutcome.slice(0, 3) : [...fallback.impact.microOutcome]
    };
}

function ceflowNormChoice(raw, fallbackId) {
    const id = String(raw?.id || fallbackId || '').toLowerCase();
    const f = CEFLOW_FALLBACKS[id] || CEFLOW_FALLBACKS[fallbackId] || CEFLOW_FALLBACKS.meta;
    const natural = CEFLOW_NATURAL_CHOICE_COPY[id] || {};
    const replyOptions = Array.isArray(raw?.replyOptions)
        ? raw.replyOptions.map(v => ceflowNormalizeCopy(v, '')).filter(Boolean).slice(0, 4)
        : [];
    const fallbackReplyOptions = Array.isArray(natural.replyOptions)
        ? natural.replyOptions.map(v => ceflowNormalizeCopy(v, '')).filter(Boolean).slice(0, 4)
        : [];
    const repairOptions = Array.isArray(raw?.repairOptions)
        ? raw.repairOptions.map(v => ceflowNormalizeCopy(v, '')).filter(Boolean).slice(0, 4)
        : [];
    const fallbackRepairOptions = Array.isArray(natural.repairOptions)
        ? natural.repairOptions.map(v => ceflowNormalizeCopy(v, '')).filter(Boolean).slice(0, 4)
        : [];
    return {
        id,
        label: ceflowNormalizeCopy(raw?.label, natural.label || CEFLOW_DEFAULT_LABELS[id] || f.label || 'תגובה'),
        tone: ceflowNormalizeCopy(raw?.tone, f.tone || 'muted'),
        emoji: ceflowNormalizeCopy(raw?.emoji, f.emoji || '💬'),
        say: ceflowNormalizeCopy(raw?.say, natural.say || ''),
        counterReply: ceflowNormalizeCopy(raw?.counterReply, natural.counterReply || f.counterReply || ''),
        replyPrompt: ceflowNormalizeCopy(raw?.replyPrompt, 'איך את/ה עונה עכשיו?'),
        replyOptions: replyOptions.length ? replyOptions : (fallbackReplyOptions.length ? fallbackReplyOptions : [
            'בוא/י ננשום רגע ונגדיר צעד ראשון.',
            'איפה בדיוק נתקעת?',
            'מה כבר כן עובד, אפילו חלקית?'
        ]),
        repairOptions: id === 'meta'
            ? []
            : (repairOptions.length ? repairOptions : (fallbackRepairOptions.length ? fallbackRepairOptions : [...CEFLOW_DEFAULT_REPAIR_OPTIONS])),
        interpretation: ceflowNormalizeCopy(raw?.interpretation, natural.interpretation || f.interpretation || ''),
        badge: ceflowNormalizeCopy(raw?.badge, ''),
        sfx: ceflowNormalizeCopy(raw?.sfx, ''),
        rightSpriteOverride: ceflowNormalizeCopy(raw?.rightSpriteOverride, ''),
        impact: ceflowNormImpact(raw?.impact, id),
        powerQuestions: Array.isArray(raw?.powerQuestions)
            ? raw.powerQuestions.slice(0, 6).map(v => ceflowNormalizeCopy(v, '')).filter(Boolean)
            : [],
        newInfoBubble: ceflowNormalizeCopy(raw?.newInfoBubble, ''),
        blueprint: ceflowNormBlueprint(raw?.blueprint)
    };
}

function ceflowNormContext(raw) {
    const source = raw?.context && typeof raw.context === 'object' ? raw.context : (raw || {});
    const distractors = Array.isArray(source?.distractors)
        ? source.distractors.map(v => ceflowNormalizeCopy(v, '')).filter(Boolean).slice(0, 4)
        : [];
    const contextIntro = ceflowNormalizeCopy(source?.contextIntro || source?.context_intro || source?.intro || '', '');
    const defaultSnap = CEFLOW_NATURAL_CHOICE_COPY.angry.say || 'די... אני לא יכול עכשיו עם זה.';
    return {
        contextIntro,
        role: ceflowNormalizeCopy(source?.role, 'אדם תחת לחץ'),
        stakes: ceflowNormalizeCopy(source?.stakes, 'יש מחיר מיידי לדרך שבה תגיב/י עכשיו.'),
        trigger: ceflowNormalizeCopy(source?.trigger, 'משהו קטן מפעיל תגובה אוטומטית.'),
        dominantEmotion: ceflowNormalizeCopy(source?.dominantEmotion, 'לחץ'),
        snapLine: ceflowNormalizeCopy(source?.snapLine, defaultSnap),
        distractors: distractors.length
            ? distractors
            : [
                'הטלפון מצפצף: הודעה דחופה.',
                'מישהו קורא לך מהחדר השני.',
                'עוד משימה קופצת בדיוק באמצע השיחה.'
            ],
        shotClockSeconds: ceflowClampInt(
            source?.shotClockSeconds || source?.shot_clock || source?.timerSeconds,
            CEFLOW_DEFAULT_SHOT_CLOCK_SECONDS,
            CEFLOW_MIN_SHOT_CLOCK_SECONDS,
            CEFLOW_MAX_SHOT_CLOCK_SECONDS
        )
    };
}

function ceflowNormScenario(raw, i) {
    if (!raw || typeof raw !== 'object') return null;
    const map = new Map();
    (raw.choices || []).forEach((choice, idx) => {
        const idHint = CEFLOW_CHOICE_ORDER[idx] || 'meta';
        const norm = ceflowNormChoice(choice, idHint);
        map.set(norm.id, norm);
    });
    CEFLOW_CHOICE_ORDER.forEach(id => {
        if (!map.has(id)) map.set(id, ceflowNormChoice({ id }, id));
    });
    const choices = CEFLOW_CHOICE_ORDER.map(id => map.get(id)).filter(Boolean);
    const meta = choices.find(choice => choice.id === 'meta');
    if (meta && !meta.powerQuestions.length) {
        meta.powerQuestions = [
            'מה בדיוק לא ברור כרגע?',
            'איזה צעד ראשון הכי קטן כן אפשרי?',
            'איזה מידע חסר כדי להתקדם?',
            'מה אפשר להוריד מהעומס עכשיו?',
            'מה מגדיר הצלחה בדקה הקרובה?'
        ];
    }
    if (meta && !meta.newInfoBubble) {
        meta.newInfoBubble = 'עכשיו זה ברור יותר: אפשר להתחיל מצעד קטן במקום להיתקע על הכול.';
    }
    const context = ceflowNormContext(raw);
    return {
        id: ceflowNormalizeCopy(raw.id, `scene_${i + 1}`),
        domain: ceflowNormalizeCopy(raw.domain, 'כללי'),
        title: ceflowNormalizeCopy(raw.title, `סצנה ${i + 1}`),
        level: ceflowNormalizeCopy(raw.level || raw.levelTag, 'מודליות + הכללה'),
        regulationNote: ceflowNormalizeCopy(
            raw.regulationNote,
            'לכולנו יש תגובה רגשית אימפולסיבית. התרגול כאן הוא לזהות אותה, לווסת סטייט, ולעבור לתגובה שכלית מבוססת שאלה.'
        ),
        context,
        shotClockSeconds: context.shotClockSeconds,
        characters: {
            left: {
                name: ceflowNormalizeCopy(raw?.characters?.left?.name, 'דמות שמאל'),
                sprite: ceflowNormalizeCopy(raw?.characters?.left?.sprite, '')
            },
            right: {
                name: ceflowNormalizeCopy(raw?.characters?.right?.name, 'דמות ימין'),
                sprite: ceflowNormalizeCopy(raw?.characters?.right?.sprite, '')
            }
        },
        dialog: (raw.dialog || []).map(item => ({
            speaker: item?.speaker === 'right' ? 'right' : 'left',
            text: ceflowNormalizeCopy(item?.text, ''),
            highlights: Array.isArray(item?.highlights) ? item.highlights : []
        })).filter(line => line.text),
        choices
    };
}

function ceflowBuildScenarioPool(rawScenarios) {
    const external = (Array.isArray(rawScenarios) ? rawScenarios : [])
        .map((scenario, i) => ceflowNormScenario(scenario, i))
        .filter(Boolean);
    const injected = CEFLOW_PRESSURE_SCENARIOS
        .map((scenario, i) => ceflowNormScenario(scenario, i))
        .filter(Boolean);

    const byId = new Map();
    injected.forEach(scene => {
        if (!scene?.id) return;
        byId.set(scene.id, scene);
    });
    external.forEach(scene => {
        if (!scene?.id) return;
        if (!byId.has(scene.id)) byId.set(scene.id, scene);
    });

    const merged = [...byId.values()];
    if (merged.length >= 6) return merged;
    return injected.slice(0, 6);
}

function ceflowMetricMeta(metric) {
    return CEFLOW_UI.metrics[metric] || Object.freeze({ label: metric, short: metric });
}

function ceflowFormatLevelLabel(value) {
    const raw = String(value || '').trim();
    if (!raw) return 'רגע חי -> בחירה';
    return CEFLOW_UI.levelMap[raw] || raw
        .replace(/\bSnap\b/g, 'לחץ מיידי')
        .replace(/\bChoice\b/g, 'בחירה')
        .replace(/\bBlueprint\b/g, 'מהלך פעולה')
        .replace(/\bMeta Model\b/gi, 'מטה-מודל');
}

function ceflowEscRe(value) {
    return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function ceflowMarkToken(text, token, cssClass, label, mode) {
    if (!token) return text;
    const safe = escapeHtml(token);
    const tip = mode === 'learn' ? ` title="${escapeHtml(label)}" data-tip="${escapeHtml(label)}"` : '';
    const re = new RegExp(`(${ceflowEscRe(safe)})`, 'g');
    return text.replace(re, `<span class="ceflow-hl ${cssClass}"${tip}>$1</span>`);
}

function ceflowHighlight(text, explicit, mode) {
    let html = escapeHtml(text || '');
    (explicit || []).forEach(item => {
        const type = String(item?.type || '').toLowerCase();
        const rule = CEFLOW_HL_RULES.find(r => r.type === type);
        if (rule) html = ceflowMarkToken(html, item?.token, rule.css, rule.label, mode);
    });
    CEFLOW_HL_RULES.forEach(rule => {
        rule.tokens.forEach(token => {
            html = ceflowMarkToken(html, token, rule.css, rule.label, mode);
        });
    });
    return html;
}

function ceflowToneClass(tone) {
    const t = String(tone || 'muted').toLowerCase();
    return t === 'danger' ? 'ceflow-tone-danger'
        : t === 'warn' ? 'ceflow-tone-warn'
        : t === 'purple' ? 'ceflow-tone-purple'
        : t === 'good' ? 'ceflow-tone-good'
        : 'ceflow-tone-muted';
}

function renderComicEngineLoadError(els, message = 'אירעה תקלה בטעינת במת הקומיקס הרגשי. נסו שוב.') {
    const safeMessage = String(message || 'אירעה תקלה בטעינה.').trim();
    if (els.dialog) {
        els.dialog.innerHTML = `
            <article class="ceflow-bubble is-left is-counter">
                <p class="ceflow-bubble-speaker">מערכת</p>
                <p class="ceflow-bubble-text">${escapeHtml(safeMessage)}</p>
            </article>
        `;
    }
    if (els.deck) {
        els.deck.innerHTML = `
            <button type="button" class="ceflow-choice ceflow-tone-good" data-ceflow-reload="1" aria-label="טען מחדש את במת הקומיקס הרגשי">
                <span class="ceflow-choice-top"><strong>🔄 טען מחדש</strong></span>
                <span class="ceflow-choice-line">לחצו כדי לנסות שוב לטעון את הסצנה.</span>
            </button>
        `;
        const reloadBtn = els.deck.querySelector('[data-ceflow-reload="1"]');
        if (reloadBtn && reloadBtn.dataset.bound !== 'true') {
            reloadBtn.dataset.bound = 'true';
            reloadBtn.addEventListener('click', () => ensureComicEngineFlowReady({ force: true }));
        }
    }
    els.replyBox?.classList.add('hidden');
    els.feedback?.classList.add('hidden');
    els.power?.classList.add('hidden');
    els.timeout?.classList.add('hidden');
    els.blueprint?.classList.add('hidden');
    if (els.retry) els.retry.disabled = false;
    if (els.next) els.next.disabled = true;
}

function ensureComicEngineFlowReady({ force = false } = {}) {
    const root = document.getElementById('comicEngine');
    if (!root) return;
    const bootState = String(root.dataset.ceflowBootState || '').trim();
    if (!force && (bootState === 'loading' || bootState === 'ready')) return;

    Promise.resolve(setupComicEngine2({ force }))
        .catch((error) => {
            console.error('Comic Engine Flow bootstrap failed:', error);
            root.dataset.ceflowBootState = 'error';
            const els = {
                root,
                dialog: document.getElementById('ceflow-dialog'),
                deck: document.getElementById('ceflow-choice-deck'),
                replyBox: document.getElementById('ceflow-reply-box'),
                feedback: document.getElementById('ceflow-feedback'),
                power: document.getElementById('ceflow-power-card'),
                timeout: document.getElementById('ceflow-timeout'),
                blueprint: document.getElementById('ceflow-blueprint'),
                retry: document.getElementById('ceflow-retry'),
                next: document.getElementById('ceflow-next-scene')
            };
            renderComicEngineLoadError(els, 'במת הקומיקס הרגשי נכשלה באתחול. לחצו "טען מחדש".');
        });
}

async function setupComicEngine2({ force = false } = {}) {
    const root = document.getElementById('comicEngine');
    if (!root) return;
    const bootState = String(root.dataset.ceflowBootState || '').trim();
    if (!force && (bootState === 'loading' || bootState === 'ready')) return;
    root.dataset.ceflowBootState = 'loading';

    const els = {
        root,
        infoBtn: document.getElementById('ceflow-info-btn'),
        stepBack: document.getElementById('ceflow-step-back'),
        expandStage: document.getElementById('ceflow-expand-stage'),
        floatingNote: document.getElementById('ceflow-floating-note'),
        distractor: document.getElementById('ceflow-distractor'),
        domain: document.getElementById('ceflow-domain'),
        progress: document.getElementById('ceflow-progress'),
        level: document.getElementById('ceflow-level'),
        title: document.getElementById('ceflow-title'),
        sceneSubtitle: document.getElementById('ceflow-scene-subtitle'),
        contextMain: document.getElementById('ceflow-context-main'),
        contextStakes: document.getElementById('ceflow-context-stakes'),
        contextTrigger: document.getElementById('ceflow-context-trigger'),
        contextSnap: document.getElementById('ceflow-context-snap'),
        consequence: document.getElementById('ceflow-consequence-banner'),
        shotClock: document.getElementById('ceflow-shotclock'),
        shotClockRing: document.getElementById('ceflow-shotclock-ring'),
        shotClockSeconds: document.getElementById('ceflow-shotclock-seconds'),
        shotClockLabel: document.getElementById('ceflow-shotclock-label'),
        left: document.getElementById('ceflow-left-character'),
        right: document.getElementById('ceflow-right-character'),
        stage: root.querySelector('.ceflow-stage'),
        stageStatus: document.getElementById('ceflow-stage-status'),
        turnLayer: document.getElementById('ceflow-turn-transition-layer'),
        dialog: document.getElementById('ceflow-dialog'),
        overlay: document.getElementById('ceflow-overlay'),
        tags: document.getElementById('ceflow-xray-tags'),
        flow: document.getElementById('ceflow-stat-flow'),
        agency: document.getElementById('ceflow-stat-agency'),
        shame: document.getElementById('ceflow-stat-shame'),
        choiceTitle: document.getElementById('ceflow-choice-title'),
        choiceCopy: document.getElementById('ceflow-choice-copy'),
        choiceAffordance: document.getElementById('ceflow-choice-affordance'),
        deck: document.getElementById('ceflow-choice-deck'),
        replyBox: document.getElementById('ceflow-reply-box'),
        replyTitle: document.getElementById('ceflow-reply-title'),
        replyQuick: document.getElementById('ceflow-reply-quick'),
        replyInput: document.getElementById('ceflow-reply-input'),
        replyStepBack: document.getElementById('ceflow-reply-step-back'),
        replyConfirm: document.getElementById('ceflow-reply-confirm'),
        replyStatus: document.getElementById('ceflow-reply-status'),
        feedback: document.getElementById('ceflow-feedback'),
        feedbackLeft: document.getElementById('ceflow-feedback-left'),
        feedbackRight: document.getElementById('ceflow-feedback-right'),
        turnSnapshot: document.getElementById('ceflow-turn-snapshot'),
        power: document.getElementById('ceflow-power-card'),
        powerQuestions: document.getElementById('ceflow-power-questions'),
        newInfo: document.getElementById('ceflow-new-info'),
        timeout: document.getElementById('ceflow-timeout'),
        blueprint: document.getElementById('ceflow-blueprint'),
        retry: document.getElementById('ceflow-retry'),
        toggleMode: document.getElementById('ceflow-toggle-mode'),
        openBlueprint: document.getElementById('ceflow-open-blueprint'),
        openBlueprintInner: document.getElementById('ceflow-open-blueprint-inner'),
        next: document.getElementById('ceflow-next-scene')
    };
    if (!els.root || !els.deck || !els.dialog) {
        root.dataset.ceflowBootState = 'error';
        return;
    }

    let payload = null;
    try {
        const response = await fetch(resolveVersionedAssetPath('data/comic-scenarios.json'), { cache: 'no-store' });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        payload = deepNormalizeUiPayload(await response.json());
    } catch (error) {
        console.error('Cannot load data/comic-scenarios.json', error);
        root.dataset.ceflowBootState = 'error';
        renderComicEngineLoadError(els, 'שגיאה בטעינת סצנות קומיקס. בדקו חיבור רשת ונסו שוב.');
        return;
    }

    const scenarios = ceflowBuildScenarioPool(payload?.scenarios || []);
    if (!scenarios.length) {
        root.dataset.ceflowBootState = 'error';
        renderComicEngineLoadError(els, 'לא נמצאו סצנות קומיקס להצגה.');
        return;
    }

    let savedIndex = 0;
    try {
        const saved = JSON.parse(localStorage.getItem(COMIC_ENGINE_STORAGE_KEY) || '{}');
        const idx = Number(saved?.index);
        if (Number.isInteger(idx) && idx >= 0 && idx < scenarios.length) savedIndex = idx;
    } catch (error) {
        savedIndex = 0;
    }

    let savedMode = 'learn';
    try {
        const savedPrefs = JSON.parse(localStorage.getItem(COMIC_ENGINE_PREFS_KEY) || '{}');
        if (savedPrefs?.mode === 'play') savedMode = 'play';
    } catch (error) {
        savedMode = 'learn';
    }

    const state = {
        flowState: CEFLOW_STATES.SCENE_READY,
        mode: savedMode,
        index: savedIndex,
        selectedChoice: null,
        selectedRepair: '',
        replyDraft: '',
        userReply: '',
        selectedQuestion: '',
        generatedInfo: '',
        stageExpanded: false,
        floatingTimer: null,
        feedbackTimer: null,
        distractorTimer: null,
        activeDistractor: '',
        shotClockTimer: 0,
        shotClockTotalMs: 0,
        shotClockDeadlineMs: 0,
        shotClockNextTickMs: 0,
        shotClockDistractorFired: false,
        shotClockPenaltyNextMs: 0,
        roundStartedAt: Date.now(),
        lastPressureState: '',
        outcomeTrail: [],
        lastBubbleKey: '',
        shotClockFiveFired: false,
        shotClockThreeFired: false,
        historyStack: []
    };

    const currentScenario = () => scenarios[state.index];
    const metaChoice = () => (currentScenario()?.choices || []).find(choice => choice.id === 'meta') || null;
    const activeBlueprint = () => state.selectedChoice?.blueprint || metaChoice()?.blueprint || null;
    const prefersReducedMotion = () => Boolean(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches);
    const ceflowSoundEnabled = () => !(audioState?.muted);
    const CEFLOW_HISTORY_LIMIT = 20;
    const CEFLOW_ALLOWED_FLOW_STATES = new Set(Object.values(CEFLOW_STATES));
    const compactText = (text, max = 155) => {
        const raw = String(text || '').trim().replace(/\s+/g, ' ');
        if (!raw) return '';
        return raw.length > max ? `${raw.slice(0, max - 1)}...` : raw;
    };
    const captureHistorySnapshot = () => ({
        index: Number(state.index) || 0,
        flowState: String(state.flowState || CEFLOW_STATES.SCENE_READY),
        mode: state.mode === 'play' ? 'play' : 'learn',
        stageExpanded: !!state.stageExpanded,
        selectedChoiceId: String(state.selectedChoice?.id || ''),
        selectedRepair: String(state.selectedRepair || ''),
        replyDraft: String(state.replyDraft || ''),
        userReply: String(state.userReply || ''),
        selectedQuestion: String(state.selectedQuestion || ''),
        generatedInfo: String(state.generatedInfo || ''),
        outcomeTrail: Array.isArray(state.outcomeTrail)
            ? state.outcomeTrail.map((item) => ({
                outcome: String(item?.outcome || ''),
                sceneId: String(item?.sceneId || ''),
                at: Number(item?.at) || 0
            }))
            : []
    });
    const pushHistorySnapshot = (reason = '') => {
        const snapshot = captureHistorySnapshot();
        const previous = state.historyStack[state.historyStack.length - 1] || null;
        if (previous && JSON.stringify(previous) === JSON.stringify(snapshot)) {
            return;
        }
        state.historyStack.push(snapshot);
        if (state.historyStack.length > CEFLOW_HISTORY_LIMIT) {
            state.historyStack.splice(0, state.historyStack.length - CEFLOW_HISTORY_LIMIT);
        }
        if (els.root) els.root.dataset.ceflowBackReason = String(reason || '').trim();
        updateStepBackControl();
    };
    const syncStepBackButton = (button, canGoBack) => {
        if (!button) return;
        button.disabled = !canGoBack;
        button.setAttribute('aria-disabled', canGoBack ? 'false' : 'true');
        button.title = canGoBack ? 'חזרה לצעד הקודם בתוך הסצנה' : 'אין צעד קודם לחזור אליו';
    };
    const updateStepBackControl = () => {
        const canGoBack = state.historyStack.length > 0;
        syncStepBackButton(els.stepBack, canGoBack);
        syncStepBackButton(els.replyStepBack, canGoBack);
        const feedbackBack = els.feedbackRight?.querySelector('button[data-feedback-step-back]');
        syncStepBackButton(feedbackBack, canGoBack);
    };
    const restoreHistorySnapshot = (snapshot) => {
        if (!snapshot || typeof snapshot !== 'object') return false;
        stopShotClock();
        hideFeedbackNote();
        hideFloatingNote();
        hideDistractor();

        const rawIndex = Number(snapshot.index);
        const safeIndex = Number.isInteger(rawIndex) && rawIndex >= 0 && rawIndex < scenarios.length ? rawIndex : 0;
        state.index = safeIndex;
        persistIndex();
        state.mode = snapshot.mode === 'play' ? 'play' : 'learn';
        state.stageExpanded = Boolean(snapshot.stageExpanded);
        state.flowState = CEFLOW_ALLOWED_FLOW_STATES.has(snapshot.flowState)
            ? snapshot.flowState
            : CEFLOW_STATES.SCENE_READY;

        const sceneChoices = Array.isArray(currentScenario()?.choices) ? currentScenario().choices : [];
        const selectedChoiceId = String(snapshot.selectedChoiceId || '');
        state.selectedChoice = sceneChoices.find((item) => item?.id === selectedChoiceId) || null;
        state.selectedRepair = String(snapshot.selectedRepair || '');
        state.replyDraft = String(snapshot.replyDraft || '');
        state.userReply = String(snapshot.userReply || '');
        state.selectedQuestion = String(snapshot.selectedQuestion || '');
        state.generatedInfo = String(snapshot.generatedInfo || '');
        state.outcomeTrail = Array.isArray(snapshot.outcomeTrail)
            ? snapshot.outcomeTrail.map((item) => ({
                outcome: String(item?.outcome || ''),
                sceneId: String(item?.sceneId || ''),
                at: Number(item?.at) || 0
            }))
            : [];
        state.roundStartedAt = Date.now();
        state.lastPressureState = '';
        state.lastBubbleKey = '';
        state.shotClockFiveFired = false;
        state.shotClockThreeFired = false;
        return true;
    };
    const stepBackOneAction = () => {
        const snapshot = state.historyStack.pop();
        if (!snapshot) return;
        if (!restoreHistorySnapshot(snapshot)) return;
        render();
        showFloatingNote('חזרנו צעד אחד אחורה בתוך הסצנה.');
    };
    const applyMotionTokens = () => {
        if (!els.root) return;
        const reduced = prefersReducedMotion();
        const style = els.root.style;
        style.setProperty('--ceflow-motion-fast', `${reduced ? 1 : CEFLOW_MOTION.duration.fast}ms`);
        style.setProperty('--ceflow-motion-medium', `${reduced ? 1 : CEFLOW_MOTION.duration.medium}ms`);
        style.setProperty('--ceflow-motion-slow', `${reduced ? 1 : CEFLOW_MOTION.duration.slow}ms`);
        style.setProperty('--ceflow-motion-atmosphere', `${reduced ? 1 : CEFLOW_MOTION.duration.atmosphere}ms`);
        style.setProperty('--ceflow-motion-urgent', `${reduced ? 1 : CEFLOW_MOTION.duration.urgent}ms`);
        style.setProperty('--ceflow-ease-soft', CEFLOW_MOTION.ease.soft);
        style.setProperty('--ceflow-ease-standard', CEFLOW_MOTION.ease.standard);
        style.setProperty('--ceflow-ease-tension', CEFLOW_MOTION.ease.tension);
        style.setProperty('--ceflow-scale-hover', String(reduced ? 1 : CEFLOW_MOTION.scale.hover));
        style.setProperty('--ceflow-scale-press', String(reduced ? 1 : CEFLOW_MOTION.scale.press));
        style.setProperty('--ceflow-scale-spotlight', String(reduced ? 1 : CEFLOW_MOTION.scale.spotlight));
        style.setProperty('--ceflow-shake-small', `${reduced ? 0 : CEFLOW_MOTION.shake.small}px`);
        style.setProperty('--ceflow-shake-medium', `${reduced ? 0 : CEFLOW_MOTION.shake.medium}px`);
        style.setProperty('--ceflow-glow-soft', reduced ? '0 0 0 0 rgba(0,0,0,0)' : CEFLOW_MOTION.glow.soft);
        style.setProperty('--ceflow-glow-urgent', reduced ? '0 0 0 0 rgba(0,0,0,0)' : CEFLOW_MOTION.glow.urgent);
    };
    const syncMotionPreference = () => {
        if (!els.root) return;
        els.root.classList.toggle('is-reduced-motion', prefersReducedMotion());
        applyMotionTokens();
    };
    const resolveAvatarExpressionKey = (expression) => {
        const normalized = String(expression || '').trim().toLowerCase();
        return CEFLOW_EXPRESSION_ALIASES[normalized] || 'neutral';
    };
    const renderAvatarFaceSvg = (expression, side, label = 'avatar') => {
        const key = resolveAvatarExpressionKey(expression);
        const spec = CEFLOW_EXPRESSION_MAP[key] || CEFLOW_EXPRESSION_MAP.neutral;
        const leftPupilX = 44 + spec.pupilShiftX;
        const rightPupilX = 68 + spec.pupilShiftX;
        const pupilY = 60 + spec.pupilShiftY;
        const cheekMarkup = spec.cheekOpacity > 0
            ? `
                <ellipse class="ceflow-avatar-cheek" cx="40" cy="73" rx="8" ry="4.6" style="opacity:${spec.cheekOpacity};"></ellipse>
                <ellipse class="ceflow-avatar-cheek" cx="72" cy="73" rx="8" ry="4.6" style="opacity:${spec.cheekOpacity};"></ellipse>
            `
            : '';
        return `
            <svg class="ceflow-avatar-svg ceflow-avatar-svg--${escapeHtml(key)} ceflow-avatar-svg--${escapeHtml(side || 'left')}" viewBox="0 0 112 136" role="img" aria-label="${escapeHtml(label)}">
                <ellipse class="ceflow-avatar-halo" cx="56" cy="62" rx="39" ry="42" style="fill:${spec.halo};"></ellipse>
                <path class="ceflow-avatar-shoulders" d="M16 132 Q56 97 96 132 L96 136 L16 136 Z" style="fill:${spec.shoulders};"></path>
                <g transform="rotate(${spec.headTilt} 56 60)">
                    <ellipse class="ceflow-avatar-neck" cx="56" cy="88" rx="10" ry="11"></ellipse>
                    <circle class="ceflow-avatar-head" cx="56" cy="58" r="34"></circle>
                    ${cheekMarkup}
                    <path class="ceflow-avatar-brow" d="${spec.brows.left}" style="stroke-width:${spec.browWidth};"></path>
                    <path class="ceflow-avatar-brow" d="${spec.brows.right}" style="stroke-width:${spec.browWidth};"></path>
                    <ellipse class="ceflow-avatar-eye" cx="44" cy="60" rx="8" ry="${spec.eyeRy}"></ellipse>
                    <ellipse class="ceflow-avatar-eye" cx="68" cy="60" rx="8" ry="${spec.eyeRy}"></ellipse>
                    <circle class="ceflow-avatar-pupil" cx="${leftPupilX}" cy="${pupilY}" r="${spec.pupilRadius}"></circle>
                    <circle class="ceflow-avatar-pupil" cx="${rightPupilX}" cy="${pupilY}" r="${spec.pupilRadius}"></circle>
                    <path class="ceflow-avatar-nose" d="M56 62 Q54 70 57 76"></path>
                    <path class="ceflow-avatar-mouth" d="${spec.mouth}" style="stroke-width:${spec.mouthWidth};"></path>
                </g>
            </svg>
        `;
    };
    syncMotionPreference();
    const isEngineVisible = () => {
        const tab = document.getElementById('comic-engine');
        if (!tab) return true;
        return tab.classList.contains('active');
    };
    const pressureAudio = (() => {
        let ctx = null;
        let lastTickAt = 0;
        let lastBuzzerAt = 0;
        let armed = false;

        const ensureCtx = (forceResume) => {
            const AudioCtx = window.AudioContext || window.webkitAudioContext;
            if (!AudioCtx) return null;
            if (!ctx) {
                try {
                    ctx = new AudioCtx();
                } catch (_error) {
                    return null;
                }
            }
            if (forceResume && ctx.state === 'suspended') {
                try {
                    const resumePromise = ctx.resume();
                    if (resumePromise && typeof resumePromise.catch === 'function') resumePromise.catch(() => {});
                } catch (_error2) {}
            }
            return ctx;
        };

        const playTone = (options) => {
            const audioCtx = ensureCtx(true);
            if (!audioCtx || audioCtx.state !== 'running') return;
            const now = audioCtx.currentTime + Number(options?.delay || 0);
            const osc = audioCtx.createOscillator();
            const gain = audioCtx.createGain();
            osc.type = options?.type || 'sine';
            osc.frequency.setValueAtTime(Math.max(60, Number(options?.from || 440)), now);
            if (Number.isFinite(options?.to) && Number(options.to) > 0 && Number(options.to) !== Number(options.from)) {
                osc.frequency.exponentialRampToValueAtTime(Math.max(50, Number(options.to)), now + Math.max(0.02, Number(options?.dur || 0.1)));
            }
            const peak = Math.max(0.0002, Number(options?.amp || 0.02));
            const dur = Math.max(0.04, Number(options?.dur || 0.08));
            gain.gain.setValueAtTime(0.0001, now);
            gain.gain.exponentialRampToValueAtTime(peak, now + 0.015);
            gain.gain.exponentialRampToValueAtTime(0.0001, now + dur);
            osc.connect(gain);
            gain.connect(audioCtx.destination);
            try {
                osc.start(now);
                osc.stop(now + dur + 0.02);
            } catch (_error3) {}
        };

        return {
            arm() {
                armed = true;
                if (!ceflowSoundEnabled()) return;
                ensureCtx(true);
            },
            tick(urgent) {
                if (!armed || !ceflowSoundEnabled()) return;
                const now = Date.now();
                const cooldown = urgent ? 210 : 460;
                if (now - lastTickAt < cooldown) return;
                lastTickAt = now;
                playTone({ type: urgent ? 'square' : 'triangle', from: urgent ? 1040 : 780, to: urgent ? 980 : 720, dur: urgent ? 0.045 : 0.06, amp: urgent ? 0.028 : 0.02 });
            },
            distractor() {
                if (!armed || !ceflowSoundEnabled()) return;
                playTone({ type: 'sawtooth', from: 440, to: 320, dur: 0.08, amp: 0.024 });
                playTone({ type: 'triangle', from: 520, to: 620, dur: 0.06, delay: 0.05, amp: 0.018 });
            },
            buzzer() {
                if (!armed || !ceflowSoundEnabled()) return;
                const now = Date.now();
                if (now - lastBuzzerAt < 1200) return;
                lastBuzzerAt = now;
                playTone({ type: 'sawtooth', from: 220, to: 170, dur: 0.2, amp: 0.036 });
                playTone({ type: 'square', from: 180, to: 140, dur: 0.2, delay: 0.08, amp: 0.03 });
            }
        };
    })();
    const emitCeflowSoundHook = (eventName, extra = {}) => {
        try {
            document.dispatchEvent(new CustomEvent('ceflow:sound', {
                detail: {
                    event: String(eventName || '').trim(),
                    sceneId: currentScenario()?.id || '',
                    sceneTitle: currentScenario()?.title || '',
                    ...extra
                }
            }));
        } catch (_error) {}
    };
    const currentRoundOutcome = () => {
        if (state.flowState === CEFLOW_STATES.TIMEOUT) return 'timeout';
        if (!state.selectedChoice) return 'pending';
        if (state.selectedChoice.id === 'meta') return state.userReply ? 'good' : 'opening';
        if (state.selectedRepair) return 'repair';
        return 'bad';
    };
    const negativeStreak = (includeCurrent = false) => {
        const trail = state.outcomeTrail.map(item => item.outcome);
        if (includeCurrent) trail.push(currentRoundOutcome());
        let streak = 0;
        for (let i = trail.length - 1; i >= 0; i -= 1) {
            if (trail[i] === 'bad' || trail[i] === 'timeout') streak += 1;
            else break;
        }
        return streak;
    };
    const pushRoundOutcomeToTrail = () => {
        const outcome = currentRoundOutcome();
        if (!outcome || outcome === 'pending' || outcome === 'opening') return;
        state.outcomeTrail.push({
            outcome,
            sceneId: currentScenario()?.id || '',
            at: Date.now()
        });
        if (state.outcomeTrail.length > 8) state.outcomeTrail.shift();
    };
    const deriveTimeoutCounterReply = () => {
        const domain = String(currentScenario()?.domain || '');
        if (domain.includes('הורות')) return 'בסדר... אז אני כבר לא מראה לך.';
        if (domain.includes('עבודה')) return 'אוקיי, אז אני נשאר/ת לבד עם זה.';
        if (domain.includes('זוגיות')) return 'טוב, אז שוב נשארתי עם זה לבד.';
        if (domain.includes('חינוך')) return 'אז אף אחד כבר לא באמת מקשיב פה.';
        if (domain.includes('שירות')) return 'אז אין מי שמחזיק את הרגע הזה.';
        return 'בסדר, לא משנה.';
    };
    const hideFloatingNote = () => {
        if (state.floatingTimer) {
            clearTimeout(state.floatingTimer);
            state.floatingTimer = null;
        }
        if (els.floatingNote) {
            els.floatingNote.classList.add('hidden');
            els.floatingNote.classList.remove('is-visible');
            els.floatingNote.textContent = '';
        }
    };
    const showFloatingNote = (text) => {
        if (!els.floatingNote) return;
        hideFloatingNote();
        const msg = compactText(text, 170);
        if (!msg) return;
        els.floatingNote.textContent = msg;
        els.floatingNote.classList.remove('hidden');
        els.floatingNote.classList.add('is-visible');
        state.floatingTimer = window.setTimeout(() => hideFloatingNote(), 6200);
    };
    const hideDistractor = () => {
        if (state.distractorTimer) {
            clearTimeout(state.distractorTimer);
            state.distractorTimer = null;
        }
        if (els.distractor) {
            els.distractor.classList.add('hidden');
            els.distractor.textContent = '';
        }
        state.activeDistractor = '';
    };
    const showDistractor = (text) => {
        if (!els.distractor) return;
        const msg = compactText(text, 130);
        if (!msg) return;
        hideDistractor();
        state.activeDistractor = msg;
        els.distractor.textContent = `⚠️ אירוע נוסף: ${msg}`;
        els.distractor.classList.remove('hidden');
        els.root.classList.add('ceflow-pressure-pulse');
        setTimeout(() => els.root.classList.remove('ceflow-pressure-pulse'), 260);
        if (typeof navigator !== 'undefined' && typeof navigator.vibrate === 'function') {
            try { navigator.vibrate(30); } catch (_error) {}
        }
        state.distractorTimer = window.setTimeout(() => {
            if (els.distractor) els.distractor.classList.add('hidden');
        }, 3200);
    };
    const hideFeedbackNote = () => {
        if (state.feedbackTimer) {
            clearTimeout(state.feedbackTimer);
            state.feedbackTimer = null;
        }
        const noteEl = els.feedbackRight?.querySelector('.ceflow-feedback-note');
        if (noteEl) {
            noteEl.classList.add('hidden');
            noteEl.textContent = '';
        }
    };
    const showFeedbackNote = (text) => {
        const noteEl = els.feedbackRight?.querySelector('.ceflow-feedback-note');
        if (!noteEl) return;
        hideFeedbackNote();
        const msg = compactText(text, 210);
        if (!msg) return;
        noteEl.textContent = msg;
        noteEl.classList.remove('hidden');
        state.feedbackTimer = window.setTimeout(() => hideFeedbackNote(), 6400);
    };

    const persistMode = () => {
        localStorage.setItem(COMIC_ENGINE_PREFS_KEY, JSON.stringify({ mode: state.mode, updatedAt: new Date().toISOString() }));
    };
    const persistIndex = () => {
        localStorage.setItem(COMIC_ENGINE_STORAGE_KEY, JSON.stringify({ index: state.index, updatedAt: new Date().toISOString() }));
    };

    const roundDurationSeconds = () => ceflowClampInt(
        currentScenario()?.shotClockSeconds || currentScenario()?.context?.shotClockSeconds,
        CEFLOW_DEFAULT_SHOT_CLOCK_SECONDS,
        CEFLOW_MIN_SHOT_CLOCK_SECONDS,
        CEFLOW_MAX_SHOT_CLOCK_SECONDS
    );

    const currentShotClockState = () => {
        const baseMs = Math.max(1000, roundDurationSeconds() * 1000);
        const totalMs = state.shotClockTotalMs > 0 ? state.shotClockTotalMs : baseMs;
        let remainingMs = state.shotClockDeadlineMs > 0
            ? Math.max(0, state.shotClockDeadlineMs - Date.now())
            : totalMs;
        if (state.flowState === CEFLOW_STATES.TIMEOUT) {
            remainingMs = 0;
        } else if (state.flowState !== CEFLOW_STATES.SCENE_READY) {
            remainingMs = 0;
        }
        const pct = totalMs > 0 ? Math.max(0, Math.min(1, remainingMs / totalMs)) : 0;
        const secondsLeft = Math.max(0, Math.ceil(remainingMs / 1000));
        const pressureState = state.flowState === CEFLOW_STATES.TIMEOUT
            ? 'timeout'
            : state.flowState !== CEFLOW_STATES.SCENE_READY
                ? 'locked'
                : remainingMs <= 3500
                    ? 'critical'
                    : remainingMs <= 9000
                        ? 'alert'
                        : 'steady';
        const pressureScore = state.flowState === CEFLOW_STATES.TIMEOUT
            ? 100
            : state.flowState !== CEFLOW_STATES.SCENE_READY
                ? 34
                : Math.round((1 - pct) * 100);
        return {
            baseMs,
            totalMs,
            remainingMs,
            pct,
            secondsLeft,
            pressureState,
            pressureScore
        };
    };

    const choiceUiMeta = (choice) => {
        const id = String(choice?.id || '').toLowerCase();
        if (id === 'angry') {
            return {
                toneLabel: 'התפרצות חמה',
                preview: 'הלחץ קופץ, והצד השני נכנס להגנה.',
                icon: '🔥'
            };
        }
        if (id === 'mock') {
            return {
                toneLabel: 'עקיצה ביקורתית',
                preview: 'הבושה עולה, והאמון נחתך מהר.',
                icon: '🗡️'
            };
        }
        if (id === 'rescue') {
            return {
                toneLabel: 'הרגעה שטחית',
                preview: 'יש הקלה רגעית, אבל האחריות נחלשת.',
                icon: '🛟'
            };
        }
        if (id === 'avoid') {
            return {
                toneLabel: 'דחייה נסוגה',
                preview: 'קונים שקט קטן ומאבדים בהירות.',
                icon: '🌫️'
            };
        }
        return {
            toneLabel: 'מהלך מטה-מודל',
            preview: 'נפתח מידע חדש והסוכנות חוזרת לשיחה.',
            icon: '🧭'
        };
    };

    const collectLanguageDrivers = (text) => {
        const source = String(text || '').trim();
        if (!source) return [];
        const found = [];
        CEFLOW_HL_RULES.forEach((rule) => {
            rule.tokens.forEach((token) => {
                if (!token || !source.includes(token)) return;
                if (found.some((item) => item.token === token)) return;
                found.push({ token, type: rule.type, label: rule.label });
            });
        });
        return found.slice(0, 4);
    };

    const quoteFocusPhrase = (text, fallback = 'הניסוח שבחרת') => {
        const normalized = String(text || '').trim().replace(/\s+/g, ' ').replace(/["'`]/g, '');
        if (!normalized) return fallback;
        const short = normalized.split(' ').slice(0, 5).join(' ');
        if (!short) return fallback;
        return `"${short}"`;
    };

    const deriveLanguageLearningArc = (hud) => {
        const onboarding = 'בקומיקס הזה בוחרים תגובה ורואים איך המילים משנות זרימה, סוכנות, בושה ותגובתיות בשיחה.';
        const noChoiceMetricWhy = Object.freeze({
            flow: 'עדיין לא נבחר ניסוח, ולכן זה מדד פתיחה של הסצנה.',
            agency: 'כרגע זה מצב בסיס לפני החלטה לשונית.',
            shame: 'זה עומס התחלתי של הרגע, לפני תגובה שלך.',
            reactivity: 'זה משקף בעיקר לחץ זמן והקשר התחלתי.'
        });

        if (!state.selectedChoice) {
            return {
                onboarding,
                panelWhy: 'הפאנל למטה מציג את מצב הפתיחה של הסצנה, לפני בחירת תגובה.',
                workedLine: '',
                burdenLine: '',
                takeaway: 'בחר/י כרטיס אחד כדי לראות מה בדיוק במילים יצר את השינוי במדדים.',
                metricWhy: noChoiceMetricWhy
            };
        }

        const choice = state.selectedChoice;
        const choiceText = String(choice.say || '').trim();
        const replyText = String(state.userReply || '').trim();
        const choiceDrivers = collectLanguageDrivers(choiceText);
        const replyDrivers = collectLanguageDrivers(replyText);
        const allDrivers = [...choiceDrivers, ...replyDrivers];
        const primaryDriver = replyDrivers[0] || choiceDrivers[0] || null;
        const phraseRef = primaryDriver ? `"${primaryDriver.token}"` : quoteFocusPhrase(replyText || choiceText);
        const joinedText = `${choiceText} ${replyText}`.trim();
        const hasCollaborativeCue = CEFLOW_COLLABORATIVE_CUES.some((cue) => joinedText.includes(cue));
        const hasRiskCue = allDrivers.some((driver) => driver.type === 'generalization' || driver.type === 'modal');
        const hasVagueCue = allDrivers.some((driver) => driver.type === 'vague');

        let workedLine = '';
        let burdenLine = '';
        let takeaway = '';

        if (choice.id === 'meta') {
            workedLine = `מה עבד כאן: מעבר לשאלה מדויקת כמו ${phraseRef} פותח מידע במקום מאבק.`;
            burdenLine = hasVagueCue
                ? `מה הכביד כאן: ניסוח כללי כמו ${phraseRef} יכול להשאיר את הצד השני בלי צעד ברור.`
                : 'מה הכביד כאן: אם ממשיכים מהר להסבר ארוך מדי, הפתיחה יכולה להיסגר שוב.';
            takeaway = 'משפט קצר שמבקש פירוט מחזיר סוכנות ומוריד עומס רגשי.';
        } else if (choice.id === 'rescue') {
            workedLine = hasCollaborativeCue
                ? `מה עבד כאן: הניסוח ${phraseRef} שומר שותפות במקום לקחת הכול לבד.`
                : 'מה עבד כאן: כשמוסיפים שאלה קטנה לצד השני, האחריות מתחילה להתחלק.';
            burdenLine = `מה הכביד כאן: ההצלה הראשונית "${compactText(choiceText, 44)}" הורידה סוכנות גם אם הכוונה טובה.`;
            takeaway = 'עזרה יעילה היא עזרה שמחזירה לצד השני יכולת פעולה, לא מחליפה אותו.';
        } else if (choice.id === 'avoid') {
            workedLine = hasCollaborativeCue
                ? `מה עבד כאן: המשפט ${phraseRef} החזיר תנועה במקום דחייה.`
                : 'מה עבד כאן: עצם המעבר מהתחמקות לניסוח מפורש מתחיל להוריד ערפל.';
            burdenLine = `מה הכביד כאן: דחייה כמו "${compactText(choiceText, 44)}" קונה שקט רגעי אבל מעלה עומס בהמשך.`;
            takeaway = 'כדאי משפט שמגדיר צעד מיידי קטן במקום לדחות את כל השיחה.';
        } else if (choice.id === 'mock') {
            workedLine = hasCollaborativeCue
                ? `מה עבד כאן: הניסוח ${phraseRef} מפחית עקיצה ומחזיר קשר.`
                : 'מה עבד כאן: כשעוברים משיפוט לשפה עניינית, יש יותר סיכוי לשיתוף.';
            burdenLine = `מה הכביד כאן: עקיצה כמו "${compactText(choiceText, 44)}" מעלה בושה ומורידה זרימה.`;
            takeaway = 'פחות השוואה ויותר דיוק עובד טוב יותר מקצרנות צינית.';
        } else {
            workedLine = hasCollaborativeCue
                ? `מה עבד כאן: במשפט ${phraseRef} יש יותר אחריות משותפת ולכן מתחיל תיקון.`
                : 'מה עבד כאן: משפט המשך רגוע יותר יכול לעצור הסלמה גם אחרי פתיחה קשה.';
            burdenLine = `מה הכביד כאן: טון חד כמו "${compactText(choiceText, 44)}" דוחף את הצד השני למגננה.`;
            takeaway = 'אפשר להחזיק גבול בלי התקפה: טון מדויק מוריד לחץ ושומר חיבור.';
        }

        if (hasRiskCue && replyText) {
            burdenLine = `מה הכביד כאן: ניסוח מוחלט כמו ${phraseRef} נשמע סגור ולכן מעלה לחץ ובושה.`;
        }
        if (!workedLine && replyText) {
            workedLine = hasCollaborativeCue
                ? `מה עבד כאן: הניסוח ${phraseRef} משדר יותר שותפות ובחירה.`
                : 'מה עבד כאן: עצם המעבר מתגובה אוטומטית למשפט מודע כבר משנה את הכיוון.';
        }

        const metricWhy = {
            flow: hud.flow >= 65
                ? `עלה כי ${phraseRef} מקדם תנועה בשיחה.`
                : hud.flow >= 45
                    ? `באמצע: יש תנועה, אבל ${phraseRef} עדיין יוצר חיכוך.`
                    : `ירד כי ${phraseRef} נשמע סוגר או מאשים.`,
            agency: hud.agency >= 65
                ? `עלתה כי בניסוח יש יותר בחירה ואחריות.`
                : hud.agency >= 45
                    ? `חלקית: יש גבול, אבל לא מספיק ברור עדיין.`
                    : `ירדה כי הניסוח נשמע פסיבי, תוקף או מבטל.`,
            shame: hud.shame >= 65
                ? `עלתה כי ${phraseRef} מצמצם ביטחון ושיתוף.`
                : hud.shame >= 45
                    ? `נשארה ברקע: יש עדיין התכווצות זהירה.`
                    : `ירדה כי הניסוח נותן מקום לצד השני.`,
            reactivity: hud.reactivity >= 65
                ? `עלתה כי הטון נשאר דרוך ומהיר מדי.`
                : hud.reactivity >= 45
                    ? `ביניים: יש מתח, אבל אפשר עדיין לווסת.`
                    : `ירדה כי התגובה נעשתה מדויקת ופחות אוטומטית.`
        };

        const panelWhy = !state.userReply
            ? 'הפאנל למטה מגיב כרגע לטון של הכרטיס שבחרת, עוד לפני משפט ההמשך.'
            : `הפאנל משווה בין הכרטיס הראשון לבין משפט ההמשך שלך (${phraseRef}), ולכן המדדים ממשיכים לזוז.`;

        return {
            onboarding,
            panelWhy: compactText(panelWhy, 190),
            workedLine: compactText(workedLine, 180),
            burdenLine: compactText(burdenLine, 180),
            takeaway: compactText(takeaway, 180),
            metricWhy
        };
    };

    const describeMetric = (metric, value) => {
        if (metric === 'flow') {
            if (value >= 75) return 'הדיאלוג זורם ונשאר פתוח.';
            if (value >= 50) return 'יש תנועה, אבל עדיין יש חיכוך.';
            return 'הזרימה נקטעת והשיחה נאספת בכוח.';
        }
        if (metric === 'agency') {
            if (value >= 75) return 'יש גבול ברור בלי לאבד קשר.';
            if (value >= 50) return 'יש קצת יציבות, אבל עדיין לא מסגרת מלאה.';
            return 'הסוכנות נשמטת והתגובה נהיית ריאקטיבית.';
        }
        if (metric === 'shame') {
            if (value >= 75) return 'הבושה מורגשת ומצמצמת שיתוף.';
            if (value >= 50) return 'יש התכווצות זהירה ברקע.';
            return 'יש פחות אשמה ויותר מקום לדבר.';
        }
        if (value >= 75) return 'המערכת דרוכה ומגיבה מהר מדי.';
        if (value >= 50) return 'המתח מורגש אבל עדיין נשלט.';
        return 'הטון רגוע יותר והמערכת פחות קופצת.';
    };

    const deriveEmotionalState = () => {
        const scenario = currentScenario();
        const context = scenario?.context || {};
        const clock = currentShotClockState();
        const dominantEmotion = String(context.dominantEmotion || '');
        const emotionText = `${dominantEmotion} ${context.trigger || ''}`;
        let flow = 54;
        let agency = 48;
        let shame = 42;
        if (emotionText.includes('כעס')) flow -= 10;
        if (emotionText.includes('לחץ')) {
            flow -= 8;
            agency -= 6;
        }
        if (emotionText.includes('עלבון')) shame += 10;
        if (emotionText.includes('דאגה')) shame += 6;
        if (emotionText.includes('תשישות')) agency -= 8;
        if (state.activeDistractor) {
            flow -= 10;
            agency -= 8;
            shame += 6;
        }
        const streak = negativeStreak(true);
        if (streak >= 2) {
            flow -= 8;
            agency -= 6;
            shame += 8;
        }
        if (state.selectedChoice?.impact?.stats) {
            flow = ceflowClamp(state.selectedChoice.impact.stats.flow, flow);
            agency = ceflowClamp(state.selectedChoice.impact.stats.agency, agency);
            shame = ceflowClamp(state.selectedChoice.impact.stats.shame, shame);
            if (state.userReply && state.selectedChoice.id === 'meta') {
                flow = ceflowClamp(flow + 4, flow);
                agency = ceflowClamp(agency + 6, agency);
                shame = ceflowClamp(shame - 6, shame);
            } else if (state.userReply && state.selectedRepair) {
                flow = ceflowClamp(flow + 8, flow);
                agency = ceflowClamp(agency + 8, agency);
                shame = ceflowClamp(shame - 10, shame);
            } else if (state.userReply && state.selectedChoice.id !== 'meta') {
                flow = ceflowClamp(flow + 4, flow);
                agency = ceflowClamp(agency + 4, agency);
                shame = ceflowClamp(shame - 4, shame);
            }
        }
        if (state.flowState === CEFLOW_STATES.TIMEOUT) {
            flow = 12;
            agency = 18;
            shame = 78;
        }
        const reactivity = Math.max(0, Math.min(100, Math.round((100 - flow + shame + clock.pressureScore) / 3)));
        const baseTags = Array.isArray(state.selectedChoice?.impact?.xrayTags) && state.selectedChoice.impact.xrayTags.length
            ? state.selectedChoice.impact.xrayTags.slice(0, 3)
            : [
                `🎭 ${dominantEmotion || 'מתח'}`,
                state.activeDistractor ? '⚠️ גירוי נוסף' : '🎯 רגע חי',
                streak >= 2 ? '🌡️ הסלמה ברקע' : (clock.pressureState === 'critical' ? '⏱️ חלון נסגר' : '🫁 עוד יש מרחב בחירה')
            ];
        let atmosphere = 'neutral';
        if (state.flowState === CEFLOW_STATES.TIMEOUT) atmosphere = 'timeout';
        else if (state.selectedChoice?.id === 'meta' && state.userReply) atmosphere = 'repair';
        else if (state.selectedChoice?.id === 'meta') atmosphere = 'opening';
        else if (state.selectedChoice?.id === 'rescue') atmosphere = 'fragile';
        else if (state.userReply && state.selectedChoice) atmosphere = 'repair';
        else if (state.selectedChoice) atmosphere = state.userReply ? 'aftershock' : 'fracture';
        else if (clock.pressureState === 'critical' || state.activeDistractor) atmosphere = 'pressure';
        if (streak >= 2 && atmosphere !== 'repair' && atmosphere !== 'opening') atmosphere = 'aftershock';

        return {
            flow,
            agency,
            shame,
            reactivity,
            pressureState: clock.pressureState,
            pressureScore: clock.pressureScore,
            atmosphere,
            xrayTags: baseTags,
            negativeStreak: streak
        };
    };

    const deriveSceneVisualState = () => {
        const clock = currentShotClockState();
        const choice = state.selectedChoice;
        const streak = negativeStreak(true);
        const repairLevel = state.selectedRepair ? 'committed' : (state.userReply ? 'tentative' : 'none');
        const impact = state.flowState === CEFLOW_STATES.TIMEOUT
            ? 'timeout'
            : !choice
                ? 'none'
                : choice.id !== 'meta' && state.userReply
                    ? 'repair'
                : choice.id === 'meta'
                    ? 'good'
                    : 'bad';
        let sceneState = 'idle';
        if (impact === 'timeout' || (impact === 'bad' && streak >= 2)) sceneState = 'escalation';
        else if (impact === 'repair') sceneState = 'repair';
        else if (impact !== 'none') sceneState = 'impact';
        else if (clock.pressureState === 'alert' || clock.pressureState === 'critical' || !!state.activeDistractor) sceneState = 'pressure';
        else if ((Date.now() - state.roundStartedAt) < 2200) sceneState = 'incoming';
        const activeSpeaker = state.flowState === CEFLOW_STATES.TIMEOUT
            ? 'left'
            : state.userReply
                ? 'right'
                : 'left';
        if (impact === 'timeout') {
            return {
                sceneState,
                impact,
                activeSpeaker,
                escalationLevel: streak >= 2 ? 'high' : 'base',
                repairLevel,
                kicker: 'החלון נסגר',
                headline: streak >= 2 ? 'עוד חלון הלך לאיבוד, והסצנה כבר נסגרת מהר יותר.' : 'הרגע ננעל לפני שיצאה תגובה.',
                copy: 'אין כאן פספוס טכני בלבד. חוסר תגובה עצמו כבר מורגש על הבמה.',
                turnChip: streak >= 2 ? 'סכנת קריסה' : 'פספוס חלון תגובה'
            };
        }
        if (impact === 'good') {
            return {
                sceneState,
                impact,
                activeSpeaker,
                escalationLevel: streak >= 2 ? 'high' : 'base',
                repairLevel,
                kicker: 'הטון נפתח',
                headline: 'הבחירה שלך יצרה יותר מרחב נשימה.',
                copy: streak >= 2
                    ? 'יש כאן תיקון משמעותי, אבל הרקע עדיין זוכר את המתח שנצבר.'
                    : 'ההבעה נרגעת, הבועה מתרככת, ויש יותר סיכוי לדיוק במקום הסלמה.',
                turnChip: 'פתיחה מחודשת'
            };
        }
        if (impact === 'repair') {
            return {
                sceneState,
                impact,
                activeSpeaker,
                escalationLevel: streak >= 2 ? 'high' : 'base',
                repairLevel,
                kicker: 'תיקון אחרי פגיעה',
                headline: repairLevel === 'committed'
                    ? 'התגובה החדשה מתחילה לשקם את המגע.'
                    : 'יש ניסיון תיקון, אבל האמון עדיין זהיר.',
                copy: repairLevel === 'committed'
                    ? 'הסצנה לא חוזרת למושלם, אבל הכיוון כבר פחות סגור ופחות חד.'
                    : 'הגוף מנסה לחזור לקשר, אך עדיין מרגישים את המכה הקודמת.',
                turnChip: repairLevel === 'committed' ? 'תיקון אחרי פגיעה' : 'ניסיון תיקון'
            };
        }
        if (impact === 'bad') {
            return {
                sceneState,
                impact,
                activeSpeaker,
                escalationLevel: streak >= 2 ? 'high' : 'base',
                repairLevel,
                kicker: 'כך זה פגע',
                headline: streak >= 2 ? 'עוד בחירה סוגרת את הסצנה מהר יותר.' : 'הבחירה שלך הקשיחה את הסצנה.',
                copy: streak >= 2
                    ? 'זו כבר לא רק מכה אחת. נבנית כאן תחושת הידרדרות ברורה.'
                    : 'הצד השני מצטמצם, והאווירה נהיית חדה יותר כמעט מיד.',
                turnChip: streak >= 2 ? 'מסלול הידרדרות' : 'התגוננות עולה'
            };
        }
        if (sceneState === 'pressure') {
            return {
                sceneState,
                impact,
                activeSpeaker,
                escalationLevel: streak >= 2 ? 'high' : 'base',
                repairLevel,
                kicker: 'המתח עולה',
                headline: clock.pressureState === 'critical' ? 'עוד רגע והחלון נסגר.' : 'השעון כבר מורגש בגוף.',
                copy: state.activeDistractor
                    ? `גם "${compactText(state.activeDistractor, 72)}" נכנס לרקע ומעלה עומס.`
                    : 'הזמן דוחף לתגובה מהירה, אבל עדיין אפשר לבחור דיוק במקום snap.',
                turnChip: 'המתח עולה'
            };
        }
        if (sceneState === 'incoming') {
            return {
                sceneState,
                impact,
                activeSpeaker,
                escalationLevel: streak >= 2 ? 'high' : 'base',
                repairLevel,
                kicker: 'הקו נכנס',
                headline: 'כך זה נשמע עכשיו מהצד השני.',
                copy: 'המשפט החי כבר על הבמה. קודם מקשיבים לטון, אחר כך בוחרים תגובה.',
                turnChip: 'דיאלוג נכנס'
            };
        }
        return {
            sceneState,
            impact,
            activeSpeaker,
            escalationLevel: streak >= 2 ? 'high' : 'base',
            repairLevel,
            kicker: 'סצנה חיה',
            headline: 'הבמה פתוחה ומחכה לבחירה שלך.',
            copy: 'עוד יש מרחב. אפשר לראות את הרגע, לווסת, ורק אז להגיב.',
            turnChip: 'מוכן/ה לסצנה'
        };
    };

    const deriveSceneNarrative = () => {
        const scenario = currentScenario();
        const context = scenario?.context || {};
        const choice = state.selectedChoice;
        const toneMeta = choiceUiMeta(choice);
        const emotion = context.dominantEmotion || 'לחץ';
        const hud = deriveEmotionalState();
        const visual = deriveSceneVisualState();
        const outcomes = Array.isArray(choice?.impact?.microOutcome) ? choice.impact.microOutcome.slice(0, 3) : [];
        if (state.flowState === CEFLOW_STATES.TIMEOUT) {
            return {
                atmosphere: 'timeout',
                subtitle: 'השעון נסגר והמערכת הקפיאה את הסבב כדי לדמות לחץ אמת.',
                choiceTitle: 'הסבב ננעל',
                choiceCopy: 'נסה/י שוב או עבור/י לסצנה הבאה. כשהזמן נגמר, התגובה האימפולסיבית בוחרת במקומך.',
                consequenceClass: 'is-negative',
                consequenceKicker: 'החלון נסגר',
                consequenceTitle: visual.escalationLevel === 'high' ? 'עוד פספוס דוחף את הסצנה לסגירה מהירה.' : 'הזמן בחר במקומך.',
                consequenceCopy: 'כשאין תגובה, הלחץ עולה והמשפט האוטומטי מתחזק.',
                replyTitle: 'הסצנה נעצרה. צריך לפתוח אותה מחדש.',
                hudHeadline: 'התגובתיות תפסה פיקוד',
                hudCaption: 'המערכת בעומס, והיכולת לשמור על דיוק נשחקת.'
            };
        }
        if (!choice) {
            return {
                atmosphere: hud.atmosphere,
                subtitle: `ה${emotion} כבר באוויר, אבל עדיין יש לך חלון קטן לבחור טון אחר.`,
                choiceTitle: 'בחר/י תגובה עם משקל רגשי',
                choiceCopy: 'כל כרטיס הוא טון אחר. הבחירה שלך משנה מיד את ההבעה, ובפאנל למטה תרא/י איך זה מזיז זרימה, סוכנות ובושה.',
                consequenceClass: 'is-neutral',
                consequenceKicker: hud.pressureState === 'critical' ? 'הזמן סוגר עליך' : 'השיחה מחכה לבחירה שלך',
                consequenceTitle: hud.pressureState === 'critical' ? 'עוד רגע והחלון נסגר.' : 'הבמה פתוחה, אבל לא רגועה.',
                consequenceCopy: state.activeDistractor
                    ? `גם "${state.activeDistractor}" נכנס לרקע ומוסיף עומס.`
                    : 'בחר/י תגובה אחת כדי לראות איך הצד השני שומע אותה באמת.',
                replyTitle: 'כך זה נחת בצד השני. מה את/ה אומר/ת עכשיו?',
                hudHeadline: 'מדד רגשי חי',
                hudCaption: 'המדדים כבר נעים לפי הלחץ, עוד לפני שבחרת תגובה.'
            };
        }
        if (choice.id !== 'meta' && state.userReply) {
            return {
                atmosphere: 'repair',
                subtitle: visual.repairLevel === 'committed'
                    ? 'אחרי פגיעה, התיקון כבר נראה על הבמה אבל עדיין לא מחזיר הכול למצב רגוע.'
                    : 'יש ניסיון לחזור לקשר, אבל המתח עדיין זוכר את המכה הקודמת.',
                choiceTitle: 'תיקון חלקי בתנועה',
                choiceCopy: 'התגובה השנייה כבר משנה משהו, אבל היא לא מוחקת את מה שקרה קודם.',
                consequenceClass: 'is-positive',
                consequenceKicker: 'השיחה זזה מכאן',
                consequenceTitle: visual.repairLevel === 'committed'
                    ? 'יש פתיחה מחודשת, זהירה אבל אמיתית.'
                    : 'נוצר ניסיון תיקון, עדיין בלי ריסט מלא.',
                consequenceCopy: outcomes.join(' · ') || 'המתח יורד קצת, והדיאלוג מקבל עוד הזדמנות אחת מדויקת.',
                replyTitle: 'התחלת לתקן. מה עוד יכול לייצב את המגע?',
                hudHeadline: 'תיקון, לא איפוס',
                hudCaption: 'יש ירידה מסוימת בתגובתיות, אבל האמון עדיין נבנה מחדש.'
            };
        }
        if (choice.id === 'meta' && state.userReply) {
            return {
                atmosphere: 'repair',
                subtitle: 'יש יותר אוויר בשיחה. עכשיו אפשר לעבור מדיוק רגשי לצעד ראשון.',
                choiceTitle: 'המהלך נפתח',
                choiceCopy: 'בחרת שאלה מדויקת. עכשיו רואים ירידת לחץ ועלייה בסוכנות.',
                consequenceClass: 'is-positive',
                consequenceKicker: 'נפתח חלון חדש',
                consequenceTitle: 'הטון נרגע והצד השני נשאר בשיחה.',
                consequenceCopy: outcomes.join(' · ') || 'המידע מתחיל לזרום במקום להיתקע בהתגוננות.',
                replyTitle: choice.replyPrompt || 'הדיוק עבד. מה המשפט הבא שלך כדי להמשיך את הפתיחה?',
                hudHeadline: 'המערכת מתייצבת',
                hudCaption: 'הזרימה והסוכנות עולות, והתגובתיות יורדת.'
            };
        }
        if (choice.id === 'meta') {
            return {
                atmosphere: 'opening',
                subtitle: 'השאלה זזה מהאשמה לחקירה. זה עדיין עדין, אבל השיחה נפתחת.',
                choiceTitle: 'הבחירה ננעלה',
                choiceCopy: 'זה מהלך מדויק. עכשיו השאלה היא איך להמשיך בלי לאבד את הפתיחה.',
                consequenceClass: 'is-positive',
                consequenceKicker: 'כך זה נוחת',
                consequenceTitle: 'הצד השני מרגיש שיש פה ניסיון להבין, לא רק להגיב.',
                consequenceCopy: outcomes.join(' · ') || toneMeta.preview,
                replyTitle: choice.replyPrompt || 'עכשיו כשהצד השני נפתח קצת, מה את/ה אומר/ת?',
                hudHeadline: 'הטון זז לכיוון בירור',
                hudCaption: 'המדדים מראים יותר מרחב נשימה ופחות תגובתיות.'
            };
        }
        return {
            atmosphere: choice.id === 'rescue' ? 'fragile' : (state.userReply ? 'aftershock' : 'fracture'),
            subtitle: visual.escalationLevel === 'high'
                ? `זו כבר הידרדרות מורגשת, לא רק בחירה אחת לא מדויקת. המחיר של ${toneMeta.toneLabel} נערם על הרגע הקודם.`
                : `הבחירה שלך כבר צבעה את הסצנה. עכשיו רואים את המחיר של ${toneMeta.toneLabel}.`,
            choiceTitle: 'הבחירה ננעלה',
            choiceCopy: 'התגובה כבר יצאה. עכשיו צריך להתמודד עם מה שהיא יצרה בשיחה.',
            consequenceClass: 'is-negative',
            consequenceKicker: 'כך זה פגע בשיחה',
            consequenceTitle: visual.escalationLevel === 'high' ? 'הסצנה כבר מחליקה למסלול הידרדרות.' : toneMeta.preview,
            consequenceCopy: outcomes.join(' · ') || (visual.escalationLevel === 'high'
                ? 'המתח נערם, ההבעה נסגרת מהר יותר, והאמון נשבר בקלות רבה יותר.'
                : 'המתח עולה, והצד השני מתכווץ או מתרחק.'),
            replyTitle: choice.replyPrompt || 'כך זה נחת בצד השני. מה את/ה אומר/ת עכשיו?',
            hudHeadline: 'הטון התקשה',
            hudCaption: 'המדדים מראים סגירה, עליית בושה או ירידת סוכנות.'
        };
    };

    const renderSceneState = () => {
        const visual = deriveSceneVisualState();
        if (els.root) {
            els.root.dataset.ceflowSceneState = visual.sceneState;
            els.root.dataset.ceflowImpact = visual.impact;
            els.root.dataset.ceflowSpeaker = visual.activeSpeaker;
            els.root.dataset.ceflowEscalation = visual.escalationLevel;
            els.root.dataset.ceflowRepair = visual.repairLevel;
        }
        if (els.stageStatus) {
            els.stageStatus.innerHTML = `
                <div class="ceflow-stage-status-copy">
                    <p class="ceflow-dialog-kicker">${escapeHtml(visual.kicker)}</p>
                    <strong>${escapeHtml(visual.headline)}</strong>
                    <p>${escapeHtml(visual.copy)}</p>
                </div>
                <span class="ceflow-scene-speaker">${visual.activeSpeaker === 'left' ? 'הצד השני בפוקוס' : 'עכשיו התור שלך'}</span>
            `;
        }
        if (els.turnLayer) {
            els.turnLayer.innerHTML = `<span class="ceflow-turn-pill">${escapeHtml(visual.turnChip)}</span>`;
        }
    };

    const renderShotClock = () => {
        const clock = currentShotClockState();
        const remainingMs = clock.remainingMs;
        const secondsLeft = clock.secondsLeft;
        const pct = clock.pct;
        const previousPressureState = state.lastPressureState;
        if (els.shotClockRing) els.shotClockRing.style.setProperty('--clock-pct', String(pct.toFixed(4)));
        if (els.shotClockSeconds) els.shotClockSeconds.textContent = String(secondsLeft);
        if (els.shotClockLabel) {
            if (state.flowState === CEFLOW_STATES.TIMEOUT) els.shotClockLabel.textContent = 'נגמר הזמן';
            else if (state.flowState !== CEFLOW_STATES.SCENE_READY) els.shotClockLabel.textContent = 'הבחירה ננעלה';
            else if (clock.pressureState === 'critical') els.shotClockLabel.textContent = 'שניות אחרונות';
            else if (clock.pressureState === 'alert') els.shotClockLabel.textContent = 'הלחץ עולה';
            else els.shotClockLabel.textContent = 'עוד יש מרחב בחירה';
        }
        if (els.shotClock) {
            const closing = state.flowState === CEFLOW_STATES.SCENE_READY && remainingMs <= 5000 && remainingMs > 0;
            const warning = state.flowState === CEFLOW_STATES.SCENE_READY && remainingMs <= 9000 && remainingMs > 5000;
            const urgent = state.flowState === CEFLOW_STATES.SCENE_READY && remainingMs <= 3000 && remainingMs > 0;
            const finalHit = state.flowState === CEFLOW_STATES.SCENE_READY && remainingMs <= 1000 && remainingMs > 0;
            els.shotClock.classList.toggle('is-closing', closing);
            els.shotClock.classList.toggle('is-warning', warning);
            els.shotClock.classList.toggle('is-urgent', urgent);
            els.shotClock.classList.toggle('is-final-hit', finalHit);
            els.shotClock.classList.toggle('is-locked', state.flowState !== CEFLOW_STATES.SCENE_READY && state.flowState !== CEFLOW_STATES.TIMEOUT);
            els.shotClock.classList.toggle('is-timeout', state.flowState === CEFLOW_STATES.TIMEOUT);
            els.shotClock.dataset.pressure = clock.pressureState;
        }
        if (els.root) els.root.dataset.ceflowPressure = clock.pressureState;
        state.lastPressureState = clock.pressureState;
        renderSceneState();
        if (previousPressureState && previousPressureState !== clock.pressureState && state.flowState === CEFLOW_STATES.SCENE_READY && !state.selectedChoice) {
            renderHeader();
            renderConsequenceBanner();
            renderCharacters();
            renderDialog();
            renderOverlay();
        }
    };

    const stopShotClock = () => {
        if (state.shotClockTimer) {
            clearInterval(state.shotClockTimer);
            state.shotClockTimer = 0;
        }
        state.shotClockTotalMs = 0;
        state.shotClockDeadlineMs = 0;
        state.shotClockNextTickMs = 0;
        state.shotClockDistractorFired = false;
        state.shotClockPenaltyNextMs = 0;
        state.shotClockFiveFired = false;
        state.shotClockThreeFired = false;
    };

    const timeoutRound = () => {
        pushHistorySnapshot('timeout');
        stopShotClock();
        hideDistractor();
        state.flowState = CEFLOW_STATES.TIMEOUT;
        state.selectedChoice = null;
        state.selectedQuestion = '';
        state.generatedInfo = '';
        state.userReply = '';
        state.replyDraft = '';
        state.selectedRepair = '';
        pressureAudio.buzzer();
        emitCeflowSoundHook('timeout');
        playUISound('error');
        render();
    };

    const tickShotClockLoop = () => {
        if (!isEngineVisible() || state.flowState !== CEFLOW_STATES.SCENE_READY) {
            stopShotClock();
            renderShotClock();
            return;
        }
        const now = Date.now();
        const remainingMs = Math.max(0, state.shotClockDeadlineMs - now);
        if (remainingMs <= 0) {
            renderShotClock();
            timeoutRound();
            return;
        }

        const remainingSeconds = Math.max(0, Math.ceil(remainingMs / 1000));
        const tickInterval = remainingMs <= 5000 ? 500 : 1000;
        if (now >= state.shotClockNextTickMs) {
            pressureAudio.tick(remainingMs <= 5000);
            state.shotClockNextTickMs = now + tickInterval;
        }
        if (!state.shotClockFiveFired && remainingSeconds <= 5) {
            state.shotClockFiveFired = true;
            emitCeflowSoundHook('warning-5sec', { secondsLeft: remainingSeconds });
        }
        if (!state.shotClockThreeFired && remainingSeconds <= 3) {
            state.shotClockThreeFired = true;
            emitCeflowSoundHook('warning-3sec', { secondsLeft: remainingSeconds });
        }

        const elapsedRatio = 1 - (remainingMs / Math.max(1, state.shotClockTotalMs));
        if (!state.shotClockDistractorFired && elapsedRatio >= 0.4) {
            state.shotClockDistractorFired = true;
            const distractors = currentScenario()?.context?.distractors || [];
            const randomText = distractors.length
                ? distractors[Math.floor(Math.random() * distractors.length)]
                : 'עוד גירוי נכנס ברקע ומעלה עומס.';
            showDistractor(randomText);
            pressureAudio.distractor();
            renderHeader();
            renderConsequenceBanner();
            renderSceneState();
            renderCharacters();
            renderDialog();
            renderOverlay();
        }

        if (now >= state.shotClockPenaltyNextMs) {
            state.shotClockPenaltyNextMs = now + 3000;
            pressureAudio.tick(true);
            els.root.classList.add('ceflow-pressure-pulse');
            setTimeout(() => els.root.classList.remove('ceflow-pressure-pulse'), 210);
            if (!prefersReducedMotion() && typeof navigator !== 'undefined' && typeof navigator.vibrate === 'function') {
                try { navigator.vibrate(20); } catch (_error) {}
            }
        }

        if (remainingSeconds <= 5 && !prefersReducedMotion()) {
            els.root.classList.add('ceflow-pressure-pulse');
            setTimeout(() => els.root.classList.remove('ceflow-pressure-pulse'), 220);
        }

        renderShotClock();
    };

    const startShotClock = () => {
        if (!isEngineVisible()) return;
        if (state.flowState !== CEFLOW_STATES.SCENE_READY) return;
        if (state.shotClockTimer) return;
        const seconds = roundDurationSeconds();
        state.shotClockTotalMs = Math.max(1000, seconds * 1000);
        state.shotClockDeadlineMs = Date.now() + state.shotClockTotalMs;
        state.shotClockNextTickMs = Date.now() + 220;
        state.shotClockDistractorFired = false;
        state.shotClockPenaltyNextMs = Date.now() + 3000;
        state.shotClockFiveFired = false;
        state.shotClockThreeFired = false;
        state.shotClockTimer = window.setInterval(tickShotClockLoop, 120);
        renderShotClock();
    };

    const syncShotClockLifecycle = () => {
        if (state.flowState === CEFLOW_STATES.SCENE_READY) startShotClock();
        else stopShotClock();
        renderShotClock();
    };

    const speakerName = (line) => line.speaker === 'right' ? currentScenario()?.characters?.right?.name : currentScenario()?.characters?.left?.name;

    const setMode = (mode, persist) => {
        state.mode = mode === 'play' ? 'play' : 'learn';
        els.root.classList.toggle('is-play-mode', state.mode === 'play');
        if (els.toggleMode) {
            els.toggleMode.textContent = state.mode === 'learn' ? '🎮 מצב משחק' : '📚 מצב לימוד';
        }
        if (persist) persistMode();
    };

    const resetRound = () => {
        stopShotClock();
        state.flowState = CEFLOW_STATES.SCENE_READY;
        state.selectedChoice = null;
        state.selectedRepair = '';
        state.replyDraft = '';
        state.userReply = '';
        state.selectedQuestion = '';
        state.generatedInfo = '';
        hideFeedbackNote();
        hideFloatingNote();
        hideDistractor();
        state.roundStartedAt = Date.now();
        state.lastPressureState = '';
        state.lastBubbleKey = '';
        state.shotClockFiveFired = false;
        state.shotClockThreeFired = false;
        emitCeflowSoundHook('turn-start', { mode: state.mode });
    };

    const deriveCharacterView = (side) => {
        const scenario = currentScenario();
        const context = scenario?.context || {};
        const dominantEmotion = context.dominantEmotion || 'לחץ';
        const emotionText = `${dominantEmotion} ${context.trigger || ''}`;
        const choice = state.selectedChoice;
        const isLeft = side === 'left';
        const roleLabel = isLeft ? 'הצד השני' : 'התגובה שלך';
        const clock = currentShotClockState();
        const visual = deriveSceneVisualState();
        const spotlight = visual.activeSpeaker === side;
        const incomingExpression = /עלבון|כאב|בושה/.test(emotionText)
            ? 'hurt'
            : /פחד|לחץ|כעס/.test(emotionText)
                ? 'tense'
                : 'open';
        if (state.flowState === CEFLOW_STATES.TIMEOUT) {
            return {
                roleLabel,
                spotlight,
                expression: isLeft ? 'closed' : 'tense',
                stateLabel: isLeft ? 'החלון נסגר והצד השני מתכווץ.' : 'הגוף קפא והתגובה לא יצאה.'
            };
        }
        if (!choice) {
            if (visual.sceneState === 'incoming') {
                return {
                    roleLabel,
                    spotlight,
                    expression: isLeft ? incomingExpression : 'neutral',
                    stateLabel: isLeft ? 'זה המשפט שנוחת עכשיו בתוך הסצנה.' : 'עוד רגע צריך לבחור טון, לא רק טקסט.'
                };
            }
            if (visual.sceneState === 'pressure') {
                return {
                    roleLabel,
                    spotlight,
                    expression: isLeft ? (state.activeDistractor ? 'hurt' : 'tense') : 'tense',
                    stateLabel: isLeft
                        ? 'ההמתנה מתוחה יותר, והטון עלול להיסגר.'
                        : clock.pressureState === 'critical'
                            ? 'הזמן סוגר. צריך תגובה ברורה עכשיו.'
                            : 'הלחץ כבר עולה, אבל עדיין אפשר לבחור דיוק.'
                };
            }
            return {
                roleLabel,
                spotlight,
                expression: isLeft ? 'neutral' : 'steady',
                stateLabel: isLeft ? `נכנס/ת עם ${dominantEmotion}, אבל עדיין לא נסגר/ת.` : 'יש מרחב לווסת ולבחור קו תגובה.'
            };
        }
        if (choice.id === 'meta') {
            if (state.userReply) {
                return {
                    roleLabel,
                    spotlight,
                    expression: isLeft ? 'open' : 'relieved',
                    stateLabel: isLeft ? 'נשאר/ת בשיחה ומוכן/ה לפרט יותר.' : 'התגובה נשמעת מווסתת, ברורה ומדויקת.'
                };
            }
            return {
                roleLabel,
                spotlight,
                expression: isLeft ? 'relieved' : 'open',
                stateLabel: isLeft ? 'מרגיש/ה שמישהו מנסה להבין, לא רק לעצור.' : 'שומר/ת על סקרנות במקום snap.'
            };
        }
        if (choice.id === 'angry') {
            return {
                roleLabel,
                spotlight,
                expression: isLeft ? 'defensive' : 'angry',
                stateLabel: isLeft ? 'נסגר/ת מול מתקפה ישירה.' : 'הטון שלך מתחמם ומאבד דיוק.'
            };
        }
        if (choice.id === 'mock') {
            return {
                roleLabel,
                spotlight,
                expression: isLeft ? 'hurt' : 'defensive',
                stateLabel: isLeft ? 'נפגע/ת ומתרחק/ת מהשיחה.' : 'התגובה נעשית חדה ועוקצנית.'
            };
        }
        if (choice.id === 'rescue') {
            return {
                roleLabel,
                spotlight,
                expression: isLeft ? 'withdrawn' : 'tense',
                stateLabel: isLeft ? 'משחרר/ת אחריות ומתרגל/ת תלות.' : 'לוקח/ת הכול עליך כדי להרגיע מהר.'
            };
        }
        return {
            roleLabel,
            spotlight,
            expression: isLeft ? 'closed' : 'withdrawn',
            stateLabel: isLeft ? 'לא מרגיש/ה שמבינים אותי באמת.' : 'נסוג/ה וקונה שקט קטן במחיר עתידי.'
        };
    };

    const renderCharacters = () => {
        const scenario = currentScenario();
        const draw = (slot, ch, side) => {
            if (!slot) return;
            const safeName = escapeHtml(ch?.name || 'דמות');
            const view = deriveCharacterView(side);
            const spriteOverride = !side || side !== 'right' ? '' : String(state.selectedChoice?.rightSpriteOverride || '').trim();
            const safeSprite = escapeHtml(spriteOverride || String(ch?.sprite || '').trim());
            const fallbackFace = renderAvatarFaceSvg(view.expression, side, ch?.name || 'דמות');
            slot.classList.toggle('is-spotlight', !!view.spotlight);
            slot.dataset.expression = view.expression;
            slot.dataset.avatarExpression = resolveAvatarExpressionKey(view.expression);
            slot.innerHTML = `
                <div class="ceflow-character-inner">
                    <div class="ceflow-character-art">
                        ${safeSprite ? `<img data-ceflow-avatar-img="1" src="${safeSprite}" alt="${safeName}" loading="lazy">` : ''}
                        <div class="ceflow-avatar-fallback${safeSprite ? ' hidden' : ''}" data-avatar-expression="${escapeHtml(resolveAvatarExpressionKey(view.expression))}">${fallbackFace}</div>
                    </div>
                    <div class="ceflow-character-copy">
                        <p class="ceflow-character-role">${escapeHtml(view.roleLabel)}</p>
                        <p class="ceflow-character-name">${safeName}</p>
                        <p class="ceflow-character-state">${escapeHtml(view.stateLabel)}</p>
                    </div>
                </div>
            `;
            const image = slot.querySelector('img[data-ceflow-avatar-img="1"]');
            const fallback = slot.querySelector('.ceflow-avatar-fallback');
            if (image && fallback) {
                image.addEventListener('error', () => {
                    image.remove();
                    fallback.classList.remove('hidden');
                }, { once: true });
            }
        };
        draw(els.left, scenario?.characters?.left, 'left');
        draw(els.right, scenario?.characters?.right, 'right');
    };

    const bubbleToneForLine = (line) => {
        const role = String(line?.role || '').trim();
        const streak = negativeStreak(true);
        if (role === 'reply') return state.selectedChoice?.id === 'meta' ? 'open' : 'repair';
        if (role === 'counter') {
            if (state.flowState === CEFLOW_STATES.TIMEOUT) return 'escalated';
            if (state.selectedChoice?.id === 'meta') return state.userReply ? 'open' : 'soft';
            if (streak >= 2) return 'escalated';
            if (state.selectedChoice?.id === 'mock') return 'hurt';
            if (state.selectedChoice?.id === 'angry') return 'sharp';
            return 'defensive';
        }
        if (role === 'selected') return state.selectedChoice?.id === 'meta' ? 'open' : (streak >= 2 ? 'escalated' : 'sharp');
        if (role === 'new-info') return state.activeDistractor ? 'escalated' : 'soft';
        const emotionText = `${currentScenario()?.context?.dominantEmotion || ''} ${currentScenario()?.context?.trigger || ''}`;
        if (line?.speaker === 'left') {
            if (/עלבון|כאב|בושה/.test(emotionText)) return 'hurt';
            if (/כעס|לחץ|פחד/.test(emotionText)) return 'defensive';
            return 'soft';
        }
        return 'open';
    };

    const renderDialog = () => {
        const scenario = currentScenario();
        const lines = [...(scenario?.dialog || [])];
        if (state.selectedChoice) {
            lines.push({ speaker: 'right', text: state.selectedChoice.say, role: 'selected' });
            lines.push({ speaker: 'left', text: state.selectedChoice.counterReply || CEFLOW_FALLBACKS[state.selectedChoice.id]?.counterReply || '', role: 'counter' });
        }
        if (state.activeDistractor && state.flowState === CEFLOW_STATES.SCENE_READY) {
            lines.push({ speaker: 'left', text: `אירוע נוסף: ${state.activeDistractor}`, role: 'new-info' });
        }
        if (state.userReply) lines.push({ speaker: 'right', text: state.userReply, role: 'reply' });
        if (state.generatedInfo) lines.push({ speaker: 'left', text: state.generatedInfo, role: 'new-info' });
        if (state.flowState === CEFLOW_STATES.TIMEOUT) {
            lines.push({ speaker: 'left', text: deriveTimeoutCounterReply(), role: 'counter' });
        }
        if (!lines.length) {
            lines.push({
                speaker: 'left',
                text: 'לא נטענו שורות דיאלוג לסצנה זו. אפשר ללחוץ "נסה שוב" או "טען מחדש".',
                role: 'counter'
            });
        }
        const visual = deriveSceneVisualState();
        let activeIndex = lines.length - 1;
        for (let i = lines.length - 1; i >= 0; i -= 1) {
            if ((lines[i]?.speaker === 'right' ? 'right' : 'left') === visual.activeSpeaker) {
                activeIndex = i;
                break;
            }
        }
        const activeLine = lines[activeIndex] || lines[lines.length - 1] || {};
        const activeBubbleKey = [
            currentScenario()?.id || '',
            state.flowState,
            activeIndex,
            activeLine.role || '',
            activeLine.text || ''
        ].join('::');
        if (activeBubbleKey && activeBubbleKey !== state.lastBubbleKey) {
            state.lastBubbleKey = activeBubbleKey;
            emitCeflowSoundHook('bubble-appear', {
                speaker: activeLine.speaker === 'right' ? 'right' : 'left',
                role: activeLine.role || ''
            });
        }
        els.dialog.innerHTML = lines.map((line, index) => {
            const side = line.speaker === 'right' ? 'right' : 'left';
            const tone = bubbleToneForLine(line);
            const active = index === activeIndex;
            return `
            <article class="ceflow-bubble is-${side} ${line.role ? `is-${escapeHtml(line.role)}` : ''} is-tone-${tone}${active ? ' is-active' : ' is-history'}">
                <p class="ceflow-bubble-speaker">${escapeHtml(speakerName(line) || 'דמות')}</p>
                <p class="ceflow-bubble-text">${ceflowHighlight(line.text, line.highlights, state.mode)}</p>
            </article>
        `;
        }).join('');
        els.dialog.scrollTop = els.dialog.scrollHeight;
    };

    const renderOverlay = () => {
        if (!els.overlay) return;
        const hud = deriveEmotionalState();
        const narrative = deriveSceneNarrative();
        const learningArc = deriveLanguageLearningArc(hud);
        const metricLinkCopy = !state.selectedChoice
            ? 'בחר/י כרטיס כדי לראות איך המדדים זזים בזמן אמת.'
            : (state.userReply
                ? 'המדדים מחושבים לפי הכרטיס שבחרת וגם לפי משפט ההמשך שלך.'
                : 'המדדים כבר זזים לפי הכרטיס שנבחר, עוד לפני משפט ההמשך.');
        const metricsLegendLine = 'מדדים: זרימה = קצב התקדמות השיחה, סוכנות = בחירה וגבול, בושה = עומס רגשי, תגובתיות = אוטומט תחת לחץ.';
        const renderStat = (metric, value, cssName) => {
            const meta = ceflowMetricMeta(metric);
            const meaning = compactText(meta.meaning || describeMetric(metric, value), 88);
            const reason = compactText(learningArc.metricWhy?.[metric] || describeMetric(metric, value), 110);
            return `
            <article class="ceflow-stat ${cssName}">
                <div class="ceflow-stat-head">
                    <span>${escapeHtml(meta.label)}</span>
                    <small class="ceflow-stat-meaning">${escapeHtml(meaning)}</small>
                </div>
                <div class="ceflow-bar"><span style="width:${ceflowClamp(value, 50)}%"></span></div>
                <small class="ceflow-stat-reason">למה זה זז: ${escapeHtml(reason)}</small>
            </article>
        `;
        };
        const onboardingLine = !state.selectedChoice
            ? `<p class="ceflow-hud-onboarding">${escapeHtml(learningArc.onboarding)}</p>`
            : '';
        els.overlay.innerHTML = `
            <div class="ceflow-hud-head">
                <div class="ceflow-hud-copy">
                    <p class="ceflow-hud-kicker">${escapeHtml(CEFLOW_UI.hudKicker)}</p>
                    <strong>${escapeHtml(narrative.hudHeadline)}</strong>
                </div>
                <p class="ceflow-hud-caption">${escapeHtml(narrative.hudCaption)}</p>
            </div>
            ${onboardingLine}
            <p class="ceflow-hud-link">${escapeHtml(metricLinkCopy)}</p>
            <p class="ceflow-hud-link">${escapeHtml(metricsLegendLine)}</p>
            <p class="ceflow-hud-why">${escapeHtml(learningArc.panelWhy)}</p>
            <div class="ceflow-xray-tags">${hud.xrayTags.map(tag => `<span>${escapeHtml(tag)}</span>`).join('')}</div>
            <div class="ceflow-stats">
                ${renderStat('flow', hud.flow, 'is-flow')}
                ${renderStat('agency', hud.agency, 'is-agency')}
                ${renderStat('shame', hud.shame, 'is-shame')}
                ${renderStat('reactivity', hud.reactivity, 'is-reactivity')}
            </div>
        `;
        els.overlay.classList.remove('hidden');
    };

    const renderContext = () => {
        const context = currentScenario()?.context || {};
        const role = context.role || 'אדם תחת לחץ';
        const stakes = context.stakes || 'יש מחיר מיידי לדרך שבה תגיב/י עכשיו.';
        const trigger = context.trigger || 'משהו קטן מפעיל תגובה אוטומטית.';
        const emotion = context.dominantEmotion || 'לחץ';
        const snap = context.snapLine || CEFLOW_NATURAL_CHOICE_COPY.angry.say;
        const intro = context.contextIntro || `את/ה בתפקיד ${role}, ובדקה הזו הכול צפוף ומהיר.`;
        if (els.contextMain) {
            els.contextMain.textContent = intro;
        }
        if (els.contextStakes) {
            els.contextStakes.textContent = `מה מונח על השולחן עכשיו: ${stakes}`;
        }
        if (els.contextTrigger) {
            els.contextTrigger.textContent = `מה הדליק את הרגע: ${trigger} כרגע זה מרגיש כמו ${emotion}.`;
        }
        if (els.contextSnap) {
            els.contextSnap.textContent = `המשפט שעלול לברוח אוטומטית: "${snap}"`;
        }
    };

    const renderConsequenceBanner = () => {
        if (!els.consequence) return;
        const narrative = deriveSceneNarrative();
        els.root.dataset.ceflowAtmosphere = narrative.atmosphere;
        els.consequence.className = `ceflow-consequence-banner ${narrative.consequenceClass}`.trim();
        els.consequence.innerHTML = `
            <p class="ceflow-consequence-kicker">${escapeHtml(narrative.consequenceKicker)}</p>
            <strong>${escapeHtml(narrative.consequenceTitle)}</strong>
            <p>${escapeHtml(narrative.consequenceCopy)}</p>
        `;
    };

    const renderTimeout = () => {
        const open = state.flowState === CEFLOW_STATES.TIMEOUT;
        els.timeout?.classList.toggle('hidden', !open);
        if (!open || !els.timeout) return;
        const context = currentScenario()?.context || {};
        const snap = context.snapLine || CEFLOW_NATURAL_CHOICE_COPY.angry.say;
        const timeoutReply = deriveTimeoutCounterReply();
        els.timeout.innerHTML = `
            <strong>⏱️ החלון נסגר על הסצנה הזו.</strong>
            <div><strong>מה שנשמע בצד השני:</strong> ${escapeHtml(timeoutReply)}</div>
            <div>לא נבחרה תגובה בזמן, ולכן המערכת הקפיאה את הרגע כדי להמחיש איך לחץ זמן דוחף לתגובה אימפולסיבית.</div>
            <div><strong>זה המשפט האוטומטי שכנראה היה בורח:</strong> ${escapeHtml(snap)}</div>
        `;
    };

    const renderDeck = () => {
        const scenario = currentScenario();
        const choices = Array.isArray(scenario?.choices) ? scenario.choices : [];
        if (!choices.length) {
            els.deck.innerHTML = `
                <button type="button" class="ceflow-choice ceflow-tone-good" data-ceflow-reload="1" aria-label="טען מחדש את הסצנה">
                    <span class="ceflow-choice-top"><strong>🔄 טען מחדש</strong></span>
                    <span class="ceflow-choice-line">לא נמצאו אפשרויות תגובה כרגע.</span>
                </button>
            `;
            return;
        }
        const locked = state.flowState !== CEFLOW_STATES.SCENE_READY;
        els.deck.innerHTML = choices.map(choice => {
            const selected = state.selectedChoice?.id === choice.id;
            const icon = choice.badge ? `<img src="${escapeHtml(choice.badge)}" alt="${escapeHtml(choice.label)}" loading="lazy">` : '';
            const ui = choiceUiMeta(choice);
            const stats = choice.impact?.stats || {};
            const selectedImpact = choice.id === 'meta'
                ? 'good'
                : state.userReply
                    ? 'repair'
                    : 'bad';
            const impactClass = selected ? ` is-impact-${selectedImpact}` : '';
            const dimmedClass = locked && state.selectedChoice && !selected ? ' is-dimmed' : '';
            return `
                <button type="button" class="ceflow-choice ${ceflowToneClass(choice.tone)}${selected ? ' is-selected' : ''}${impactClass}${dimmedClass}" data-choice-id="${escapeHtml(choice.id)}" data-choice-impact="${escapeHtml(selectedImpact)}" ${locked ? 'disabled' : ''} aria-label="${escapeHtml(choice.label)}" aria-pressed="${selected ? 'true' : 'false'}">
                    <span class="ceflow-choice-tone">${escapeHtml(ui.icon)} ${escapeHtml(ui.toneLabel)}</span>
                    <span class="ceflow-choice-top"><strong>${escapeHtml(choice.emoji)} ${escapeHtml(choice.label)}</strong>${icon}</span>
                    <span class="ceflow-choice-line">${escapeHtml(choice.say)}</span>
                    <span class="ceflow-choice-preview">
                        <span class="ceflow-choice-preview-label">כך זה כנראה יזוז</span>
                        <strong>${escapeHtml(ui.preview)}</strong>
                    </span>
                    <span class="ceflow-choice-stats">
                        <span>${escapeHtml(ceflowMetricMeta('flow').short)} ${escapeHtml(String(ceflowClamp(stats.flow, 50)))}</span>
                        <span>${escapeHtml(ceflowMetricMeta('agency').short)} ${escapeHtml(String(ceflowClamp(stats.agency, 50)))}</span>
                        <span>${escapeHtml(ceflowMetricMeta('shame').short)} ${escapeHtml(String(ceflowClamp(stats.shame, 50)))}</span>
                    </span>
                </button>
            `;
        }).join('');
    };

    const renderReply = () => {
        const open = !!state.selectedChoice && !state.userReply;
        els.replyBox?.classList.toggle('hidden', !open);
        if (!open) return;
        if (els.replyTitle) {
            els.replyTitle.textContent = state.selectedChoice?.replyPrompt || 'כך זה נחת בצד השני. מה את/ה אומר/ת עכשיו?';
        }
        if (els.replyQuick) {
            els.replyQuick.innerHTML = (state.selectedChoice.replyOptions || []).map(opt => `<button type="button" class="ceflow-reply-option" data-reply-option="${escapeHtml(opt)}">${escapeHtml(opt)}</button>`).join('');
        }
        if (els.replyInput) els.replyInput.value = state.replyDraft || '';
        if (els.replyInput) {
            els.replyInput.placeholder = state.selectedChoice?.id === 'meta'
                ? 'כתבו משפט שממשיך את הדיוק ופותח עוד צעד קטן...'
                : 'כתבו משפט שמנסה לייצב את השיחה מחדש...';
        }
        if (els.replyStatus) els.replyStatus.textContent = '';
    };

    const renderFeedback = () => {
        const open = !!state.selectedChoice && !!state.userReply;
        els.feedback?.classList.toggle('hidden', !open);
        if (!open) {
            hideFeedbackNote();
            return;
        }
        const choice = state.selectedChoice;
        const leftBadge = choice.badge ? `<img src="${escapeHtml(choice.badge)}" alt="badge" loading="lazy">` : '';
        const leftSfx = choice.sfx ? `<img src="${escapeHtml(choice.sfx)}" alt="sfx" loading="lazy">` : '';
        if (els.feedbackLeft) els.feedbackLeft.innerHTML = `${leftBadge}${leftSfx}`;
        if (els.feedbackRight) {
            const interpretation = compactText(choice.interpretation, 210);
            const regulation = compactText(currentScenario().regulationNote, 220);
            const narrative = deriveSceneNarrative();
            const hud = deriveEmotionalState();
            const learningArc = deriveLanguageLearningArc(hud);
            const counterReply = compactText(choice.counterReply || CEFLOW_FALLBACKS[choice.id]?.counterReply || '', 180);
            const highlightedChoiceSay = ceflowHighlight(choice.say, [], state.mode);
            const highlightedUserReply = ceflowHighlight(state.userReply, [], state.mode);
            const learningWorked = learningArc.workedLine
                ? `<p class="ceflow-language-effect-line is-worked">✅ ${escapeHtml(learningArc.workedLine)}</p>`
                : '';
            const learningBurden = learningArc.burdenLine
                ? `<p class="ceflow-language-effect-line is-burden">⚠️ ${escapeHtml(learningArc.burdenLine)}</p>`
                : '';
            const learningTakeaway = learningArc.takeaway
                ? `<p class="ceflow-language-effect-takeaway">🧠 לקחת הלאה: ${escapeHtml(learningArc.takeaway)}</p>`
                : '';
            const repairOptions = Array.isArray(choice.repairOptions) ? choice.repairOptions.slice(0, 4) : [];
            const repairBlock = (choice.id !== 'meta' && repairOptions.length)
                ? `
                    <div class="ceflow-repair-box">
                        <p>מה יכול להתחיל לתקן את הרגע הזה?</p>
                        <div class="ceflow-repair-options">
                            ${repairOptions.map(item => `
                                <button type="button" class="ceflow-repair-option${state.selectedRepair === item ? ' is-selected' : ''}" data-repair-option="${escapeHtml(item)}">
                                    ${escapeHtml(item)}
                                </button>
                            `).join('')}
                        </div>
                    </div>
                `
                : '';
            els.feedbackRight.innerHTML = `
                <div class="ceflow-section-head">
                    <p class="ceflow-section-kicker">${escapeHtml(narrative.consequenceKicker)}</p>
                    <h4 class="ceflow-block-title">${escapeHtml(narrative.consequenceTitle)}</h4>
                </div>
                <div class="ceflow-feedback-quote">
                    <strong>המשפט שיצא ממך</strong>
                    <p class="ceflow-feedback-phrase">${highlightedChoiceSay}</p>
                </div>
                <div class="ceflow-feedback-quote">
                    <strong>כך זה נשמע בצד השני</strong>
                    <p>${escapeHtml(counterReply || 'הטון התקשה, והצד השני לא נשאר פתוח לגמרי.')}</p>
                </div>
                <div class="ceflow-feedback-quote">
                    <strong>המשפט שבחרת עכשיו</strong>
                    <p class="ceflow-feedback-phrase">${highlightedUserReply}</p>
                </div>
                <div class="ceflow-outcomes">${(choice.impact?.microOutcome || []).map(item => `<span>${escapeHtml(item)}</span>`).join('')}</div>
                <div class="ceflow-language-effect">
                    <strong>מה במילים הזיז את התוצאה?</strong>
                    ${learningWorked}
                    ${learningBurden}
                    ${learningTakeaway}
                </div>
                <p class="ceflow-interpretation">${escapeHtml(interpretation)}</p>
                <div class="ceflow-feedback-actions">
                    <button type="button" class="ceflow-mini-btn" data-feedback-note="${escapeHtml(interpretation)}">🔍 פרשנות</button>
                    <button type="button" class="ceflow-mini-btn" data-feedback-note="${escapeHtml(regulation)}">🧠 ויסות סטייט</button>
                    <button type="button" class="ceflow-mini-btn ceflow-back-mini-btn" data-feedback-step-back="1">↩ חזרה צעד</button>
                </div>
                ${repairBlock}
                <div class="ceflow-feedback-note hidden" aria-live="polite"></div>
            `;
            updateStepBackControl();
        }
    };

    const renderTurnSnapshot = () => {
        if (!els.turnSnapshot) return;
        const open = !!state.userReply || state.flowState === CEFLOW_STATES.TIMEOUT;
        els.turnSnapshot.classList.toggle('hidden', !open);
        if (!open) return;
        const narrative = deriveSceneNarrative();
        const visual = deriveSceneVisualState();
        const learningArc = deriveLanguageLearningArc(deriveEmotionalState());
        const choice = state.selectedChoice;
        const pickedLabel = state.flowState === CEFLOW_STATES.TIMEOUT
            ? 'לא נבחרה תגובה בזמן'
            : `${choice?.label || 'תגובה'}: ${choice?.say || ''}`;
        const landedCopy = state.flowState === CEFLOW_STATES.TIMEOUT
            ? deriveTimeoutCounterReply()
            : (choice?.counterReply || CEFLOW_FALLBACKS[choice?.id]?.counterReply || 'הטון התקשה והצד השני לא נשאר פתוח לגמרי.');
        const defaultNextTry = state.flowState === CEFLOW_STATES.TIMEOUT
            ? 'בפעם הבאה: משפט ראשון קצר עדיף על קיפאון מלא.'
            : choice?.id === 'meta'
                ? 'בפעם הבאה: המשך/י עם שאלה קטנה אחת נוספת, בלי לעבור מהר מדי להסבר.'
                : visual.impact === 'repair'
                    ? 'בפעם הבאה: החזק/י אחריות קצרה וברורה לפני עוד הסבר או הגנה.'
                    : 'בפעם הבאה: חפש/י ניסוח שגם מחזיק גבול וגם משאיר פתח לבירור.';
        const nextTry = learningArc.takeaway
            ? `לקחת הלאה: ${learningArc.takeaway}`
            : defaultNextTry;
        const shiftCopy = Array.isArray(choice?.impact?.microOutcome) && choice.impact.microOutcome.length
            ? choice.impact.microOutcome.slice(0, 3).join(' · ')
            : narrative.consequenceCopy;
        els.turnSnapshot.innerHTML = `
            <div class="ceflow-section-head">
                <p class="ceflow-section-kicker">מה קרה בשיחה</p>
                <h4 class="ceflow-block-title">${escapeHtml(narrative.consequenceTitle)}</h4>
            </div>
            <div class="ceflow-turn-snapshot-grid">
                <article class="ceflow-turn-snapshot-card">
                    <strong>מה בחרת</strong>
                    <p>${escapeHtml(pickedLabel)}</p>
                </article>
                <article class="ceflow-turn-snapshot-card">
                    <strong>איך זה נחת</strong>
                    <p>${escapeHtml(landedCopy)}</p>
                </article>
                <article class="ceflow-turn-snapshot-card">
                    <strong>מה זז</strong>
                    <p>${escapeHtml(shiftCopy)}</p>
                </article>
            </div>
            <p class="ceflow-turn-snapshot-note">${escapeHtml(nextTry)}</p>
        `;
    };

    const renderPower = () => {
        const open = state.selectedChoice?.id === 'meta' && !!state.userReply && (state.flowState === CEFLOW_STATES.POWER_CARD || state.flowState === CEFLOW_STATES.BLUEPRINT_OPEN);
        els.power?.classList.toggle('hidden', !open);
        if (!open) return;
        if (els.powerQuestions) {
            els.powerQuestions.innerHTML = (state.selectedChoice.powerQuestions || []).map(q => `<button type="button" class="ceflow-power-question${state.selectedQuestion === q ? ' is-active' : ''}" data-power-question="${escapeHtml(q)}">${escapeHtml(q)}</button>`).join('');
        }
        if (els.newInfo) {
            const hasInfo = !!state.generatedInfo;
            els.newInfo.classList.toggle('hidden', !hasInfo);
            els.newInfo.innerHTML = hasInfo
                ? `<p><strong>שאלה:</strong> ${escapeHtml(state.selectedQuestion)}</p><p><strong>מידע חדש:</strong> ${escapeHtml(state.generatedInfo)}</p>`
                : '';
        }
    };

    const renderBlueprint = () => {
        const bp = activeBlueprint();
        const open = state.flowState === CEFLOW_STATES.BLUEPRINT_OPEN && !!bp;
        els.blueprint?.classList.toggle('hidden', !open);
        if (!open || !els.blueprint) return;
        const middle = bp.middle || [];
        const alternatives = bp.alternatives || [];
        const preconditions = bp.preconditions || [];
        els.blueprint.innerHTML = `
            <h4>${escapeHtml(CEFLOW_UI.blueprintTitle)}</h4>
            <div class="ceflow-blueprint-grid">
                <article class="ceflow-blueprint-step"><h5>🎯 מטרה</h5><p>${escapeHtml(bp.goal || 'לא הוגדר')}</p></article>
                <article class="ceflow-blueprint-step"><h5>🟢 צעד ראשון</h5><p>${escapeHtml(bp.first || 'לא הוגדר')}</p></article>
                <article class="ceflow-blueprint-step"><h5>🔁 שלבי ביניים</h5><p>${escapeHtml(middle.join(' | ') || 'עד 3 שלבים ברורים')}</p></article>
                <article class="ceflow-blueprint-step"><h5>✅ צעד אחרון</h5><p>${escapeHtml(bp.last || 'לא הוגדר')}</p></article>
                <article class="ceflow-blueprint-step"><h5>🧰 חלופות</h5><p>${escapeHtml(alternatives.join(' | ') || 'אין חלופות')}</p></article>
            </div>
            <p class="ceflow-blueprint-footnote"><strong>${escapeHtml(CEFLOW_UI.blueprintPreconditions)}:</strong> ${escapeHtml(preconditions.join(' | ') || 'אין תנאים מיוחדים')}</p>
        `;
    };

    const renderControls = () => {
        const hasRoundOutcome = !!state.selectedChoice || !!state.userReply || state.flowState === CEFLOW_STATES.TIMEOUT;
        if (els.retry) els.retry.disabled = !hasRoundOutcome;
        if (els.next) els.next.disabled = !(state.userReply || state.flowState === CEFLOW_STATES.TIMEOUT);
        const showBlueprint = !!activeBlueprint() && !!state.userReply;
        els.openBlueprint?.classList.toggle('hidden', !showBlueprint);
        updateStepBackControl();
    };

    const renderChoiceAffordance = () => {
        if (!els.choiceAffordance || !els.deck) return;
        let stateKey = 'ready';
        let message = 'לחצו על אחד הכרטיסים הצבעוניים כדי לבחור תגובה.';

        if (state.flowState === CEFLOW_STATES.TIMEOUT) {
            stateKey = 'locked';
            message = 'הסבב נעצר בגלל זמן. אפשר חזרה צעד או "נסה שוב".';
        } else if (state.flowState === CEFLOW_STATES.SCENE_READY && !state.selectedChoice) {
            stateKey = 'ready';
            message = 'לבחירה עכשיו: לחצו על אחד הכרטיסים כדי לנעול תגובה.';
        } else if (state.selectedChoice && !state.userReply) {
            stateKey = 'locked';
            message = 'הבחירה נעולה. כתבו משפט המשך, או חזרו צעד לבחירה אחרת.';
        } else if (state.userReply && state.selectedChoice) {
            stateKey = 'locked';
            message = 'התגובה נשמרה. אפשר חזרה צעד לעריכה, או לעבור לסצנה הבאה.';
        }

        els.choiceAffordance.dataset.state = stateKey;
        els.choiceAffordance.textContent = message;
        els.deck.classList.toggle('is-interactive', stateKey === 'ready');
        els.deck.classList.toggle('is-locked', stateKey !== 'ready');
    };

    const renderHeader = () => {
        const scenario = currentScenario();
        const narrative = deriveSceneNarrative();
        if (els.domain) els.domain.textContent = `תחום: ${scenario.domain}`;
        if (els.progress) els.progress.textContent = `סצנה ${state.index + 1}/${scenarios.length}`;
        if (els.level) els.level.textContent = `רמה: ${ceflowFormatLevelLabel(scenario.level)}`;
        if (els.title) els.title.textContent = scenario.title;
        if (els.sceneSubtitle) els.sceneSubtitle.textContent = narrative.subtitle;
        if (els.choiceTitle) els.choiceTitle.textContent = narrative.choiceTitle;
        if (els.choiceCopy) els.choiceCopy.textContent = narrative.choiceCopy;
        if (els.expandStage) {
            els.expandStage.textContent = state.stageExpanded ? '🗕 כווץ קומיקס' : '🖼️ הגדל רגע';
            els.expandStage.setAttribute('aria-pressed', state.stageExpanded ? 'true' : 'false');
        }
        renderContext();
        renderChoiceAffordance();
        try {
            renderGlobalComicStrip('comic-engine', scenario);
        } catch (error) {
            console.warn('Comic strip render failed in Comic Engine Flow:', error);
        }
    };

    const render = () => {
        els.root.classList.toggle('is-stage-expanded', !!state.stageExpanded);
        renderHeader();
        renderSceneState();
        renderConsequenceBanner();
        renderCharacters();
        renderDialog();
        renderOverlay();
        renderDeck();
        renderTimeout();
        renderReply();
        renderFeedback();
        renderTurnSnapshot();
        renderPower();
        renderBlueprint();
        renderControls();
        setMode(state.mode, false);
        syncShotClockLifecycle();
    };

    const choose = (choiceId) => {
        if (state.flowState !== CEFLOW_STATES.SCENE_READY) return;
        const choice = (currentScenario()?.choices || []).find(item => item.id === choiceId);
        if (!choice) return;
        pushHistorySnapshot('choose');
        stopShotClock();
        hideDistractor();
        state.selectedChoice = choice;
        state.selectedRepair = '';
        state.replyDraft = choice.replyOptions?.[0] || '';
        state.flowState = CEFLOW_STATES.CHOICE_REVEALED;
        state.userReply = '';
        state.selectedQuestion = '';
        state.generatedInfo = '';
        playUISound(choice.id === 'meta' ? 'correct' : 'next');
        emitCeflowSoundHook('select-response', { choiceId: choice.id });
        emitCeflowSoundHook(choice.id === 'meta' ? 'good-consequence' : 'bad-consequence', { choiceId: choice.id });
        render();
        els.replyInput?.focus();
    };

    const confirmReply = () => {
        const text = String(els.replyInput?.value || '').trim();
        if (!text) {
            if (els.replyStatus) els.replyStatus.textContent = 'כתבו תגובה קצרה לפני פרשנות.';
            return;
        }
        pushHistorySnapshot('confirm-reply');
        state.userReply = text;
        state.replyDraft = text;
        state.selectedRepair = '';
        if (state.selectedChoice?.id === 'meta') {
            state.selectedQuestion = state.selectedChoice.powerQuestions?.[0] || '';
            state.generatedInfo = state.selectedChoice.newInfoBubble || 'השאלה פתחה מידע חדש, ואפשר להתקדם לצעד ראשון.';
            state.flowState = CEFLOW_STATES.POWER_CARD;
        }
        playUISound('finish');
        emitCeflowSoundHook(state.selectedChoice?.id === 'meta' ? 'reply-confirmed-good' : 'reply-confirmed-repair', {
            choiceId: state.selectedChoice?.id || ''
        });
        render();
    };

    const openBlueprint = () => {
        if (!activeBlueprint()) return;
        pushHistorySnapshot('open-blueprint');
        state.flowState = CEFLOW_STATES.BLUEPRINT_OPEN;
        render();
    };

    const retry = () => {
        pushHistorySnapshot('retry');
        resetRound();
        render();
    };

    const nextScene = () => {
        if (!state.userReply && state.flowState !== CEFLOW_STATES.TIMEOUT) return;
        pushHistorySnapshot('next-scene');
        hideFloatingNote();
        hideFeedbackNote();
        hideDistractor();
        stopShotClock();
        pushRoundOutcomeToTrail();
        state.flowState = CEFLOW_STATES.NEXT_SCENE;
        els.root.classList.add('ceflow-scene-leave');
        setTimeout(() => {
            state.index = (state.index + 1) % scenarios.length;
            persistIndex();
            resetRound();
            render();
            els.root.classList.remove('ceflow-scene-leave');
            els.root.classList.add('ceflow-scene-enter');
            setTimeout(() => els.root.classList.remove('ceflow-scene-enter'), prefersReducedMotion() ? 1 : 190);
        }, prefersReducedMotion() ? 1 : 130);
    };

    document.addEventListener('pointerdown', () => pressureAudio.arm(), { once: true, capture: true });
    document.addEventListener('keydown', () => pressureAudio.arm(), { once: true, capture: true });
    document.addEventListener('touchstart', () => pressureAudio.arm(), { once: true, capture: true, passive: true });

    els.deck?.addEventListener('click', (event) => {
        const reloadBtn = event.target.closest('button[data-ceflow-reload]');
        if (reloadBtn) {
            ensureComicEngineFlowReady({ force: true });
            return;
        }
        const button = event.target.closest('button[data-choice-id]');
        if (!button) return;
        choose(button.getAttribute('data-choice-id'));
    });
    els.infoBtn?.addEventListener('click', () => {
        if (!els.floatingNote) return;
        if (!els.floatingNote.classList.contains('hidden')) {
            hideFloatingNote();
            return;
        }
        const learningArc = deriveLanguageLearningArc(deriveEmotionalState());
        const contextualNote = !state.selectedChoice
            ? `${learningArc.onboarding} ${learningArc.panelWhy}`
            : (learningArc.takeaway || learningArc.panelWhy);
        showFloatingNote(contextualNote || currentScenario()?.regulationNote || 'לכולנו יש תגובה אימפולסיבית ראשונה. כאן עוצרים רגע, מווסתים סטייט, ועוברים לשאלה מדויקת.');
    });
    els.expandStage?.addEventListener('click', () => {
        state.stageExpanded = !state.stageExpanded;
        els.root.classList.toggle('is-stage-expanded', state.stageExpanded);
        render();
    });
    els.replyQuick?.addEventListener('click', (event) => {
        const button = event.target.closest('button[data-reply-option]');
        if (!button || !els.replyInput) return;
        const value = button.getAttribute('data-reply-option') || '';
        state.replyDraft = value;
        els.replyInput.value = value;
        els.replyInput.focus();
    });
    els.replyInput?.addEventListener('input', () => {
        state.replyDraft = String(els.replyInput.value || '');
    });
    els.replyInput?.addEventListener('keydown', (event) => {
        if (event.key !== 'Enter') return;
        if (event.shiftKey) return;
        if (!event.ctrlKey && !event.metaKey) return;
        event.preventDefault();
        confirmReply();
    });
    els.replyStepBack?.addEventListener('click', stepBackOneAction);
    els.replyConfirm?.addEventListener('click', confirmReply);
    els.powerQuestions?.addEventListener('click', (event) => {
        const button = event.target.closest('button[data-power-question]');
        if (!button || !state.selectedChoice) return;
        const nextQuestion = button.getAttribute('data-power-question') || '';
        if (nextQuestion && nextQuestion !== state.selectedQuestion) {
            pushHistorySnapshot('power-question');
        }
        state.selectedQuestion = nextQuestion;
        state.generatedInfo = state.selectedChoice.newInfoBubble || 'נפתח מידע חדש שאפשר לעבוד איתו.';
        state.flowState = CEFLOW_STATES.POWER_CARD;
        render();
    });
    els.feedbackRight?.addEventListener('click', (event) => {
        const backBtn = event.target.closest('button[data-feedback-step-back]');
        if (backBtn) {
            stepBackOneAction();
            return;
        }
        const repairBtn = event.target.closest('button[data-repair-option]');
        if (repairBtn) {
            const nextRepair = repairBtn.getAttribute('data-repair-option') || '';
            if (nextRepair && nextRepair !== state.selectedRepair) {
                pushHistorySnapshot('repair-option');
            }
            state.selectedRepair = nextRepair;
            renderFeedback();
            renderTurnSnapshot();
            showFeedbackNote(nextRepair);
            return;
        }
        const button = event.target.closest('button[data-feedback-note]');
        if (!button) return;
        showFeedbackNote(button.getAttribute('data-feedback-note') || '');
    });
    els.stepBack?.addEventListener('click', stepBackOneAction);
    els.retry?.addEventListener('click', retry);
    els.next?.addEventListener('click', nextScene);
    els.openBlueprint?.addEventListener('click', openBlueprint);
    els.openBlueprintInner?.addEventListener('click', openBlueprint);
    els.toggleMode?.addEventListener('click', () => {
        state.mode = state.mode === 'learn' ? 'play' : 'learn';
        setMode(state.mode, true);
        render();
    });
    document.addEventListener('visibilitychange', () => {
        if (document.hidden) {
            stopShotClock();
            renderShotClock();
            return;
        }
        syncShotClockLifecycle();
    });

    const motionMql = window.matchMedia ? window.matchMedia('(prefers-reduced-motion: reduce)') : null;
    if (motionMql) {
        const onMotionChange = () => {
            syncMotionPreference();
            renderShotClock();
        };
        if (typeof motionMql.addEventListener === 'function') motionMql.addEventListener('change', onMotionChange);
        else if (typeof motionMql.addListener === 'function') motionMql.addListener(onMotionChange);
    }

    try {
        syncMotionPreference();
        resetRound();
        setMode(state.mode, false);
        render();
        root.dataset.ceflowBootState = 'ready';
    } catch (error) {
        root.dataset.ceflowBootState = 'error';
        console.error('Comic Engine Flow render failure:', error);
        renderComicEngineLoadError(els, 'במת הקומיקס הרגשי נתקעה בזמן ציור המסך. לחצו "טען מחדש".');
    }
}

// ==================== WRINKLE REVEAL FLOW (OVERRIDE) ===================

const WR2_STORAGE_KEY = 'wrinkle_reveal_v2';

const WR2_SEED_SCENES = Object.freeze([
    Object.freeze({
        id: 'wr2_seed_1',
        anchor: 'אני לא יכול',
        visibleSentence: 'אני לא יכול להסביר לה מה אני רוצה',
        template: 'אני לא יכול {Q} להסביר לה מה אני רוצה',
        quantifiers: Object.freeze(['אף פעם', 'בשום מצב רגשי', 'בשום סיטואציה', 'בשום צורה']),
        transformedSentence: 'לפעמים קשה לי להסביר לה מה אני רוצה.'
    }),
    Object.freeze({
        id: 'wr2_seed_2',
        anchor: 'אני חייב',
        visibleSentence: 'אני חייב להספיק הכל היום',
        template: 'אני חייב {Q} להספיק הכל היום',
        quantifiers: Object.freeze(['בכל תנאי', 'בלי לנשום', 'גם כשאני מותש', 'לא משנה מה המחיר']),
        transformedSentence: 'אני בוחר להתמקד במה שחשוב היום, צעד אחד בכל ׳₪עם.'
    }),
    Object.freeze({
        id: 'wr2_seed_3',
        anchor: 'אי אפשר',
        visibleSentence: 'אי אפשר לדבר איתו',
        template: 'אי אפשר {Q} לדבר איתו',
        quantifiers: Object.freeze(['בשום מצב', 'עם אף אחד', 'בשום צורה', 'בכל סיטואציה']),
        transformedSentence: 'כרגע קשה לדבר איתו, ואפשר לחפש דרך מדויקת לשיחה.'
    }),
    Object.freeze({
        id: 'wr2_seed_4',
        anchor: 'תמיד',
        visibleSentence: 'תמיד אני נתקע כשצריך לדבר מול אנשים',
        template: 'תמיד {Q} אני נתקע כשצריך לדבר מול אנשים',
        quantifiers: Object.freeze(['ללא יוצא דופן', 'בכל מקום', 'עם כולם', 'בכל רמת לחץ']),
        transformedSentence: 'לפעמים אני נתקע מול אנשים, ואפשר להתאמן כדי להשתפר.'
    })
]);

function wr2TrimText(value, maxLen = 180) {
    const clean = String(value || '').replace(/\s+/g, ' ').trim();
    if (!clean) return '';
    return clean.length > maxLen ? `${clean.slice(0, maxLen - 1)}...` : clean;
}

function wr2DetectAnchor(sentence) {
    const s = String(sentence || '');
    const anchors = ['לא יכול', 'אי אפשר', 'חייב', 'צריך', 'מוכרח', 'תמיד', 'כולם', 'אף פעם', 'אין ברירה'];
    for (let i = 0; i < anchors.length; i += 1) {
        const token = anchors[i];
        if (s.includes(token)) return token;
    }
    return 'המשפט';
}

function wr2BuildTemplate(sentence) {
    const raw = String(sentence || '').trim();
    if (!raw) return '{Q}';
    const anchor = wr2DetectAnchor(raw);
    if (!anchor || anchor === 'המשפט') return `${raw} {Q}`;
    const idx = raw.indexOf(anchor);
    if (idx < 0) return `${raw} {Q}`;
    const left = raw.slice(0, idx + anchor.length).trimEnd();
    const right = raw.slice(idx + anchor.length).trimStart();
    return `${left} {Q}${right ? ` ${right}` : ''}`;
}

function wr2InferQuantifiers(sentence) {
    const normalized = normalizeText(sentence || '');
    if (/(לא יכול|אי אפשר|בלתי אפשרי|אין סיכוי)/.test(normalized)) {
        return ['אף פעם', 'בשום מצב רגשי', 'בשום סיטואציה', 'בשום צורה'];
    }
    if (/(תמיד|כל הזמן|אף פעם|כולם|אף אחד)/.test(normalized)) {
        return ['בכל מצב', 'ללא יוצא דופן', 'עם כולם', 'בכל ׳–מן'];
    }
    if (/(חייב|צריך|אין ברירה|מוכרח)/.test(normalized)) {
        return ['בכל תנאי', 'ללא בחירה', 'גם כשאני עייף', 'לא משנה מה'];
    }
    return ['בשום מצב', 'בכל תנאי', 'בשום צורה'];
}

function wr2SoftenSentence(sentence) {
    let text = String(sentence || '').trim();
    if (!text) return '';
    text = text.replace(/אני לא יכול/g, 'לפעמים קשה לי');
    text = text.replace(/אי אפשר/g, 'כרגע זה מאתגר');
    text = text.replace(/תמיד/g, 'לפעמים');
    text = text.replace(/אף פעם/g, 'לפעמים');
    text = text.replace(/כולם/g, 'חלק מהאנשים');
    text = text.replace(/אין ברירה/g, 'יש לי כמה אפשרויות');
    text = text.replace(/חייב/g, 'מעדיף');
    if (!/[.!?]$/.test(text)) text += '.';
    return text;
}

function wr2NormalizeScene(raw, idxPrefix = 'wr2_custom') {
    if (!raw || typeof raw !== 'object') return null;
    const visibleSentence = wr2TrimText(raw.visibleSentence || raw.statement, 160);
    if (!visibleSentence) return null;
    const quantifiers = (Array.isArray(raw.quantifiers) ? raw.quantifiers : [])
        .map(value => wr2TrimText(value, 34))
        .filter(Boolean)
        .slice(0, 4);
    const inferred = quantifiers.length ? quantifiers : wr2InferQuantifiers(visibleSentence);
    return {
        id: String(raw.id || `${idxPrefix}_${Date.now()}_${Math.random().toString(16).slice(2, 6)}`),
        source: raw.source === 'self' ? 'self' : 'seed',
        anchor: wr2TrimText(raw.anchor || wr2DetectAnchor(visibleSentence), 30),
        visibleSentence,
        template: wr2TrimText(raw.template || wr2BuildTemplate(visibleSentence), 220),
        quantifiers: [...new Set(inferred)].slice(0, 4),
        transformedSentence: wr2TrimText(raw.transformedSentence || wr2SoftenSentence(visibleSentence), 190),
        createdAt: Number(raw.createdAt) || Date.now()
    };
}

function wr2OverlayHtml(template, activeQuantifier) {
    const parts = String(template || '').split('{Q}');
    const q = activeQuantifier ? `[${activeQuantifier}]` : '[בחר/י כמת]';
    const qHtml = `<span class="wr2-q-inline">${escapeHtml(q)}</span>`;
    if (parts.length < 2) return `${escapeHtml(template || '')} ${qHtml}`.trim();
    return `${escapeHtml(parts[0])}${qHtml}${escapeHtml(parts.slice(1).join('{Q}'))}`;
}

function wr2TriggerFx(layer, strong = false) {
    if (!layer) return;
    layer.innerHTML = '';
    const glyphs = strong ? ['✨', '🎉', '💥', '🌟'] : ['✨', '🔍', '🧩'];
    const count = strong ? 14 : 7;
    for (let i = 0; i < count; i += 1) {
        const star = document.createElement('span');
        star.className = 'wr2-fx-star';
        star.textContent = glyphs[i % glyphs.length];
        star.style.left = `${12 + Math.random() * 76}%`;
        star.style.top = `${30 + Math.random() * 42}%`;
        star.style.setProperty('--x', `${Math.round((Math.random() - 0.5) * 120)}px`);
        layer.appendChild(star);
    }
    setTimeout(() => {
        if (!layer) return;
        layer.innerHTML = '';
    }, strong ? 820 : 620);
}

function setupWrinkleGame() {
    const root = document.getElementById('wrinkle-game');
    if (!root) return;

    if (!document.getElementById('wr2-quantifiers')) {
        root.className = 'card wrinkle-reveal-card';
        root.innerHTML = `
            <div class="wr2-topbar">
                <span class="wr2-top-icon">🕵️‍♂️</span>
                <h3>חשוף את הכמת!</h3>
                <div class="wr2-score">
                    <span>🔥 <strong id="wr2-streak">0</strong></span>
                    <span>⭐ <strong id="wr2-points">0</strong></span>
                </div>
            </div>
            <div class="wr2-headline">
                <h4>המשפט נשמע תמים...</h4>
                <p>אבל הבעיה האמיתית מסתתרת כאן 👇</p>
            </div>
            <section class="wr2-plain-box">
                <p id="wr2-visible-sentence" class="wr2-visible-sentence"></p>
                <small>כך זה נשמע</small>
            </section>
            <section class="wr2-detect-zone">
                <p class="wr2-zone-title">כמתים סמויים</p>
                <div id="wr2-quantifiers" class="wr2-quantifiers" role="group" aria-label="כמתים סמויים"></div>
                <div class="wr2-overlay-box">
                    <p id="wr2-overlay-sentence" class="wr2-overlay-sentence"></p>
                    <p id="wr2-explain-line" class="wr2-explain-line">לחץ/י על כמת אדום כדי לחשוף טוטאליות סמויה.</p>
                </div>
                <p id="wr2-progress" class="wr2-progress">0 מתוך 0 כמתים חשופים</p>
            </section>
            <section id="wr2-release" class="wr2-release hidden">
                <p>הבעיה אינה במילים "אני לא יכול". הבעיה היא בהכללות נסתרות שיוצרות תחושת "אין מוצא".</p>
                <button id="wr2-unlock-btn" class="btn btn-primary wr2-unlock-btn" type="button">חשפתי את כל הכמתים! 🎉</button>
            </section>
            <section id="wr2-transform-zone" class="wr2-transform-zone hidden">
                <button id="wr2-transform-btn" class="btn btn-primary wr2-transform-btn" type="button">הסר הכללה טוטאלית</button>
                <div id="wr2-transformed" class="wr2-transformed hidden" aria-live="polite">
                    <p class="wr2-transformed-label">ניסוח משוחרר:</p>
                    <p id="wr2-transformed-text" class="wr2-transformed-text"></p>
                </div>
            </section>
            <div class="wr2-actions">
                <button id="wr2-next-btn" class="btn btn-secondary" type="button">משפט הבא</button>
                <button id="wr2-self-toggle" class="btn btn-secondary" type="button">+ משפט אישי</button>
            </div>
            <section id="wr2-self-panel" class="wr2-self-panel hidden">
                <label for="wr2-self-input">Self-Reference (אופציונלי)</label>
                <textarea id="wr2-self-input" rows="2" placeholder="לדוגמה: אני לא יכול להסביר לה מה אני רוצה."></textarea>
                <button id="wr2-self-add" class="btn btn-secondary" type="button">הוסף לתרגול</button>
                <ul id="wr2-self-list" class="wr2-self-list"></ul>
            </section>
            <div id="wr2-fx-layer" class="wr2-fx-layer" aria-hidden="true"></div>
        `;
    }

    const els = {
        streak: document.getElementById('wr2-streak'),
        points: document.getElementById('wr2-points'),
        visibleSentence: document.getElementById('wr2-visible-sentence'),
        quantifiers: document.getElementById('wr2-quantifiers'),
        overlaySentence: document.getElementById('wr2-overlay-sentence'),
        explainLine: document.getElementById('wr2-explain-line'),
        progress: document.getElementById('wr2-progress'),
        release: document.getElementById('wr2-release'),
        unlockBtn: document.getElementById('wr2-unlock-btn'),
        transformZone: document.getElementById('wr2-transform-zone'),
        transformBtn: document.getElementById('wr2-transform-btn'),
        transformed: document.getElementById('wr2-transformed'),
        transformedText: document.getElementById('wr2-transformed-text'),
        nextBtn: document.getElementById('wr2-next-btn'),
        selfToggle: document.getElementById('wr2-self-toggle'),
        selfPanel: document.getElementById('wr2-self-panel'),
        selfInput: document.getElementById('wr2-self-input'),
        selfAdd: document.getElementById('wr2-self-add'),
        selfList: document.getElementById('wr2-self-list'),
        fxLayer: document.getElementById('wr2-fx-layer')
    };

    if (!els.quantifiers || !els.visibleSentence || !els.overlaySentence) return;

    let saved = {};
    try {
        saved = JSON.parse(localStorage.getItem(WR2_STORAGE_KEY) || '{}') || {};
    } catch (error) {
        saved = {};
    }

    const customScenes = (Array.isArray(saved.customScenes) ? saved.customScenes : [])
        .map((item, i) => wr2NormalizeScene(item, `wr2_saved_${i}`))
        .filter(Boolean)
        .slice(0, 12);

    const state = {
        seedScenes: WR2_SEED_SCENES.map((item, i) => wr2NormalizeScene(item, `wr2_seed_${i}`)).filter(Boolean),
        customScenes,
        index: Math.max(0, Math.floor(Number(saved.index) || 0)),
        streak: Math.max(0, Math.floor(Number(saved.streak) || 0)),
        points: Math.max(0, Math.floor(Number(saved.points) || 0)),
        revealed: [],
        activeQuantifier: '',
        unlocked: false,
        transformed: false
    };

    const allScenes = () => [...state.seedScenes, ...state.customScenes];
    const currentScene = () => {
        const scenes = allScenes();
        if (!scenes.length) return null;
        if (state.index >= scenes.length) state.index = 0;
        return scenes[state.index];
    };
    const allRevealed = () => {
        const scene = currentScene();
        if (!scene) return false;
        return state.revealed.length >= scene.quantifiers.length;
    };
    const persist = () => {
        localStorage.setItem(WR2_STORAGE_KEY, JSON.stringify({
            index: state.index,
            streak: state.streak,
            points: state.points,
            customScenes: state.customScenes
        }));
    };
    const resetRound = () => {
        state.revealed = [];
        state.activeQuantifier = '';
        state.unlocked = false;
        state.transformed = false;
    };
    const renderSelfList = () => {
        if (!els.selfList) return;
        els.selfList.innerHTML = '';
        const rows = [...state.customScenes]
            .sort((a, b) => (Number(b.createdAt) || 0) - (Number(a.createdAt) || 0))
            .slice(0, 5);
        if (!rows.length) return;
        rows.forEach((scene) => {
            const item = document.createElement('li');
            item.textContent = `“${scene.visibleSentence}”`;
            els.selfList.appendChild(item);
        });
    };
    const render = () => {
        const scene = currentScene();
        if (!scene) {
            root.innerHTML = '<p>אין כרגע משפטים לתרגול.</p>';
            return;
        }

        if (els.streak) els.streak.textContent = String(state.streak);
        if (els.points) els.points.textContent = String(state.points);
        if (els.visibleSentence) els.visibleSentence.textContent = scene.visibleSentence;
        if (els.overlaySentence) {
            els.overlaySentence.innerHTML = wr2OverlayHtml(scene.template, state.activeQuantifier);
            els.overlaySentence.classList.toggle('is-active', Boolean(state.activeQuantifier));
        }
        if (els.explainLine) {
            els.explainLine.textContent = state.activeQuantifier
                ? `זה לא בהכרח "${scene.anchor}". זה "${state.activeQuantifier}".`
                : 'לחץ/י על כמת אדום כדי לחשוף טוטאליות סמויה.';
        }

        const qSet = new Set(state.revealed);
        if (els.quantifiers) {
            els.quantifiers.innerHTML = scene.quantifiers.map((q) => {
                const active = state.activeQuantifier === q;
                const seen = qSet.has(q);
                return `<button type="button" class="wr2-quantifier${active ? ' is-active' : ''}${seen ? ' is-revealed' : ''}" data-q="${escapeHtml(q)}" aria-label="חשוף ${escapeHtml(q)}">[${escapeHtml(q)}]</button>`;
            }).join('');
        }

        if (els.progress) {
            els.progress.textContent = `${state.revealed.length} מתוך ${scene.quantifiers.length} כמתים חשופים`;
        }

        const revealedAll = allRevealed();
        els.release?.classList.toggle('hidden', !revealedAll);
        if (els.unlockBtn) {
            els.unlockBtn.disabled = !revealedAll || state.unlocked;
            els.unlockBtn.textContent = state.unlocked
                ? 'מעולה, נעבור לטרנספורמציה ✅'
                : 'חשפתי את כל הכמתים! 🎉';
        }

        const showTransform = state.unlocked || state.transformed;
        els.transformZone?.classList.toggle('hidden', !showTransform);
        els.transformed?.classList.toggle('hidden', !state.transformed);
        if (els.transformedText) {
            els.transformedText.textContent = state.transformed ? scene.transformedSentence : '';
        }
    };
    const revealQuantifier = (value) => {
        const scene = currentScene();
        if (!scene || !scene.quantifiers.includes(value)) return;
        state.activeQuantifier = value;
        if (!state.revealed.includes(value)) {
            state.revealed.push(value);
            state.points += 2;
            playUISound('next');
            wr2TriggerFx(els.fxLayer, false);
            persist();
        }
        if (allRevealed()) playUISound('correct');
        render();
    };
    const unlock = () => {
        if (!allRevealed()) return;
        if (!state.unlocked) {
            state.unlocked = true;
            playUISound('finish');
            wr2TriggerFx(els.fxLayer, true);
            persist();
        }
        render();
    };
    const transform = () => {
        const scene = currentScene();
        if (!scene || !state.unlocked || state.transformed) return;
        state.transformed = true;
        state.streak += 1;
        state.points += scene.source === 'self' ? 14 : 10;
        addXP(scene.source === 'self' ? 12 : 10);
        if (state.streak > 0 && state.streak % 3 === 0) addStars(1);
        playUISound('correct');
        wr2TriggerFx(els.fxLayer, true);
        persist();
        render();
    };
    const nextScene = () => {
        const scenes = allScenes();
        if (!scenes.length) return;
        state.index = (state.index + 1) % scenes.length;
        resetRound();
        persist();
        render();
    };
    const addSelfSentence = () => {
        const input = String(els.selfInput?.value || '').trim();
        if (input.length < 8) {
            if (els.explainLine) els.explainLine.textContent = 'כתבו משפט אישי קצר (לפחות 8 תווים).';
            return;
        }
        const normalized = normalizeText(input).replace(/\s+/g, ' ').trim();
        const exists = state.customScenes.some(scene => normalizeText(scene.visibleSentence).replace(/\s+/g, ' ').trim() === normalized);
        if (exists) {
            if (els.explainLine) els.explainLine.textContent = 'המשפט הזה כבר קיים בתרגול.';
            return;
        }
        const scene = wr2NormalizeScene({
            id: `wr2_self_${Date.now()}`,
            source: 'self',
            visibleSentence: input,
            anchor: wr2DetectAnchor(input),
            template: wr2BuildTemplate(input),
            quantifiers: wr2InferQuantifiers(input),
            transformedSentence: wr2SoftenSentence(input),
            createdAt: Date.now()
        });
        if (!scene) return;
        state.customScenes.unshift(scene);
        if (state.customScenes.length > 12) state.customScenes = state.customScenes.slice(0, 12);
        state.index = allScenes().findIndex(item => item.id === scene.id);
        if (state.index < 0) state.index = 0;
        if (els.selfInput) els.selfInput.value = '';
        resetRound();
        persist();
        renderSelfList();
        render();
        playUISound('start');
    };

    els.quantifiers.addEventListener('click', (event) => {
        const button = event.target.closest('button[data-q]');
        if (!button) return;
        revealQuantifier(button.getAttribute('data-q') || '');
    });
    els.unlockBtn?.addEventListener('click', unlock);
    els.transformBtn?.addEventListener('click', transform);
    els.nextBtn?.addEventListener('click', nextScene);
    els.selfToggle?.addEventListener('click', () => {
        els.selfPanel?.classList.toggle('hidden');
    });
    els.selfAdd?.addEventListener('click', addSelfSentence);

    renderSelfList();
    resetRound();
    render();
}

